def _gs():
    """Obtener instancia de Google Sync (o None si no está disponible)"""
    if not GOOGLE_SYNC_DISPONIBLE:
        return None
    try:
        gs = get_google_sync()
        return gs if gs.conectado else None
    except Exception:
        return None

