def _gestion_usuarios_admin():
    """Admin puede editar/eliminar usuarios. Crear cuentas = Registrar Docente en Matrícula."""
    usuarios = cargar_usuarios()
    
    # NUEVO: Detectar y borrar cuentas obsoletas
    cuentas_viejas = [u for u in usuarios.keys() 
                      if (u.startswith('profe') or u.startswith('prof.')) 
                      and u not in ['profesional', 'profesor']]
    
    if cuentas_viejas:
        st.warning(f"⚠️ Se detectaron {len(cuentas_viejas)} cuentas obsoletas")
        
        # Mostrar lista sin expander (para evitar anidamiento)
        st.markdown("**👀 Cuentas obsoletas detectadas:**")
        for cv in cuentas_viejas:
            st.caption(f"🗑️ {cv} → {usuarios[cv].get('label', 'Sin nombre')}")
        
        if st.button("🗑️ ELIMINAR TODAS LAS CUENTAS OBSOLETAS", 
                   type="primary", key="btn_del_obsoletas"):
            for cv in cuentas_viejas:
                del usuarios[cv]
            guardar_usuarios(usuarios)
            st.success(f"✅ {len(cuentas_viejas)} cuentas obsoletas eliminadas")
            st.balloons()
            time.sleep(1)
            st.rerun()
        st.markdown("---")
    
    st.caption(f"**{len(usuarios)} cuentas de acceso:**")
    for usr, datos in usuarios.items():
        rol_emoji = {"admin": "⚙️", "directivo": "📋", "auxiliar": "👤", "docente": "DOCENTE"}.get(datos.get('rol', ''), '•')
        grado_txt = ""
        if datos.get('docente_info') and datos['docente_info'].get('grado'):
            grado_txt = f" — {datos['docente_info']['grado']}"
        st.caption(f"{rol_emoji} **{usr}** → {datos.get('label', datos['rol'])}{grado_txt}")

    st.info("💡 Para crear nuevas cuentas: vaya a **Matrícula > Registrar Docente**")

    st.markdown("---")
    st.markdown("**✏️ Editar cuenta:**")
    editable = [u for u in usuarios.keys() if u != "administrador"]
    if not editable:
        st.caption("No hay cuentas editables.")
        return
    edit_usr = st.selectbox("Seleccionar usuario:", editable, key="edit_usr")
    if edit_usr:
        datos_edit = usuarios[edit_usr]
        ne_label = st.text_input("Nombre completo:", value=datos_edit.get('label', ''), key="ne_label")
        ne_pass = st.text_input("Contraseña:", value=datos_edit.get('password', ''), key="ne_pass")
        ne_rol = st.selectbox("Rol:", ["docente", "directivo", "auxiliar"],
                               index=["docente", "directivo", "auxiliar"].index(datos_edit.get('rol', 'docente')),
                               key="ne_rol")
        
        # Solo docentes necesitan grado y nivel
        ne_nivel = "PRIMARIA"
        ne_grado = "N/A"
        if ne_rol == "docente":
            niveles_opciones = ["INICIAL", "PRIMARIA", "SECUNDARIA", "PREUNIVERSITARIO", "TODOS"]
            nivel_actual = datos_edit.get('docente_info', {}).get('nivel', 'PRIMARIA') if datos_edit.get('docente_info') else 'PRIMARIA'
            if nivel_actual not in niveles_opciones:
                nivel_actual = "PRIMARIA"
            ne_nivel = st.selectbox("Nivel:", niveles_opciones,
                                     index=niveles_opciones.index(nivel_actual),
                                     key="ne_nivel")
            if ne_nivel == "TODOS":
                grados_opts = ["ALL_NIVELES"]
                st.success("🔓 Acceso a TODOS los grados (Inicial, Primaria, Secundaria, Pre-U)")
            else:
                grados_opts = ["N/A"] + NIVELES_GRADOS.get(ne_nivel, []) + ["ALL_SECUNDARIA"]
            ne_grado = st.selectbox("Grado asignado:", grados_opts, key="ne_grado")
        else:
            st.caption(f"🔓 **{ne_rol.title()}** tiene acceso completo (sin grado específico)")
        
        c1, c2 = st.columns(2)
        with c1:
            if st.button("💾 GUARDAR", type="primary", key="btn_edit_usr"):
                usuarios[edit_usr]['label'] = ne_label
                usuarios[edit_usr]['password'] = ne_pass
                usuarios[edit_usr]['rol'] = ne_rol
                if ne_rol == "docente":
                    # Preservar DNI existente o intentar resolverlo
                    old_di = datos_edit.get('docente_info') or {}
                    dni_doc = old_di.get('dni', '')
                    di = {"label": ne_label, "grado": ne_grado, "nivel": ne_nivel, "dni": dni_doc}
                    usuarios[edit_usr]['docente_info'] = di
                else:
                    usuarios[edit_usr]['docente_info'] = None
                guardar_usuarios(usuarios)
                st.success(f"✅ {edit_usr} actualizado")
                st.rerun()
        with c2:
            if st.button("🗑️ Eliminar", key="btn_del_usr", type="primary"):
                if edit_usr != "administrador":
                    del usuarios[edit_usr]
                    guardar_usuarios(usuarios)
                    st.success(f"✅ {edit_usr} eliminado")
                    st.rerun()


# ================================================================
# TAB: MATRÍCULA (Alumnos + Docentes)
# ================================================================

def tab_matricula(config):
    st.header("📝 Matrícula")
    tab_est, tab_doc, tab_lista, tab_pdf = st.tabs([
        "➕ Registrar Alumno", "DOCENTE Registrar Docente",
        "📋 Listas", "⬇️ Registros PDF"
    ])

    with tab_est:
        st.subheader("📝 Matrícula de Estudiante")

        # --- MODO DE REGISTRO ---
        modo_reg = st.radio(
            "Tipo de registro:",
            ["✅ Completo (con DNI)", "⏳ Provisional (solo nombre)"],
            horizontal=True, key="modo_matricula"
        )
        es_provisional = "Provisional" in modo_reg

        if es_provisional:
            st.info("💡 **Modo provisional**: solo ingrese apellidos y nombres. Puede completar DNI, apoderado y celular después en **Base de Datos → Completar Datos**.")

        c1, c2 = st.columns(2)
        with c1:
            mn = st.text_input("Apellidos y Nombres: *", key="mn",
                               placeholder="APELLIDO APELLIDO, Nombre")
            if not es_provisional:
                md = st.text_input("DNI: *", key="md", max_chars=8,
                                   placeholder="12345678")
            else:
                md = ""
            mnv = st.selectbox("Nivel:", list(NIVELES_GRADOS.keys()), key="mnv")
            mg = st.selectbox("Grado:", NIVELES_GRADOS[mnv], key="mg")
            # Secundaria/Preuniversitario → sección A por defecto
            if mnv in ("SECUNDARIA", "PREUNIVERSITARIO"):
                ms = st.selectbox("Sección:", SECCIONES, index=SECCIONES.index("A"), key="ms")
            else:
                ms = st.selectbox("Sección:", SECCIONES, key="ms")
        with c2:
            msexo = st.selectbox("Sexo:", ["Masculino", "Femenino"], key="msexo")
            if not es_provisional:
                ma = st.text_input("Apoderado (Padre/Madre):", key="ma")
                mda = st.text_input("DNI Apoderado:", key="mda", max_chars=8)
                mc = st.text_input("Celular Apoderado:", key="mc", max_chars=9,
                                   placeholder="987654321")
            else:
                ma = ""
                mda = ""
                mc = ""
                st.caption("👆 DNI, apoderado y celular se completan luego en Base de Datos")

        if st.button("✅ MATRICULAR", type="primary", use_container_width=True,
                     key="bm"):
            if mn:
                if es_provisional:
                    # Registro provisional — sin DNI
                    with st.spinner("💾 Guardando matrícula provisional..."):
                        BaseDatos.registrar_estudiante({
                            'Nombre': mn.strip().upper(), 'DNI': '',
                            'Nivel': mnv, 'Grado': mg, 'Seccion': ms,
                            'Sexo': msexo, 'Apoderado': '', 'DNI_Apoderado': '',
                            'Celular_Apoderado': '', '_provisional': 'SI'
                        })
                        time.sleep(1)
                    avatar = "👦" if msexo == "Masculino" else "👧"
                    st.success(f"⏳ **MATRÍCULA PROVISIONAL REGISTRADA**")
                    st.markdown(f"""
                    <div class="asist-ok">
                        <strong>📋 Matrícula Provisional</strong><br>
                        {avatar} {mn.strip().upper()}<br>
                        🎓 {mg} — Sección {ms}<br>
                        📅 {fecha_peru_str()}<br>
                        <span style="color:orange;font-weight:bold;">⚠️ PENDIENTE: completar DNI y celular en Base de Datos</span>
                    </div>
                    """, unsafe_allow_html=True)
                    reproducir_beep_exitoso()
                else:
                    # Registro completo — requiere DNI
                    if not md:
                        st.error("⚠️ En modo Completo el DNI es obligatorio")
                    else:
                        md_clean = ''.join(c for c in md.strip() if c.isdigit())
                        if len(md_clean) != 8:
                            st.error(f"⚠️ El DNI debe tener 8 dígitos ({len(md_clean)} encontrados)")
                        else:
                            with st.spinner("💾 Guardando matrícula..."):
                                BaseDatos.registrar_estudiante({
                                    'Nombre': mn.strip().upper(), 'DNI': md_clean,
                                    'Nivel': mnv, 'Grado': mg, 'Seccion': ms,
                                    'Sexo': msexo, 'Apoderado': ma.strip(),
                                    'DNI_Apoderado': mda.strip(),
                                    'Celular_Apoderado': mc.strip(),
                                    '_provisional': 'NO'
                                })
                                time.sleep(2)
                            verificar = BaseDatos.buscar_por_dni(md_clean)
                            if verificar:
                                avatar = "👦" if msexo == "Masculino" else "👧"
                                st.success(f"✅ **MATRICULADO CORRECTAMENTE** ☁️ Guardado en la nube")
                                st.markdown(f"""
                                <div class="asist-ok">
                                    <strong>📋 Confirmación de Matrícula</strong><br>
                                    {avatar} {mn.strip().upper()}<br>
                                    🆔 DNI: {md_clean}<br>
                                    🎓 {mg} — Sección {ms}<br>
                                    📅 {fecha_peru_str()}<br>
                                    <span style="color:green;font-weight:bold;">☑️ VERIFICADO EN BASE DE DATOS</span>
                                </div>
                                """, unsafe_allow_html=True)
                                reproducir_beep_exitoso()
                                st.balloons()
                            else:
                                st.warning("⚠️ Se intentó guardar pero no se pudo verificar. Revise en la lista.")
            else:
                st.error("⚠️ El nombre es obligatorio")

    with tab_doc:
        st.subheader("DOCENTE Registro de Docente / Personal")
        c1, c2 = st.columns(2)
        with c1:
            dn_n = st.text_input("👤 Apellidos y Nombres:", key="dn_nom")
            dn_d = st.text_input("🆔 DNI:", key="dn_dni", max_chars=8)
            dn_c = st.selectbox("💼 Cargo:", [
                "Docente", "Directora", "Auxiliar", "Coordinador",
                "Secretaria", "Personal de Limpieza", "Otro"
            ], key="dn_cargo")
            dn_e = st.text_input("📚 Especialidad:", key="dn_esp",
                                  placeholder="Ej: Educación Primaria")
        with c2:
            dn_t = st.text_input("📱 Celular:", key="dn_cel", max_chars=9,
                                  placeholder="987654321")
            
            # Solo Docente/Coordinador necesitan nivel y grado
            dn_areas_sel = ""
            if dn_c in ["Docente", "Coordinador"]:
                dn_nivel = st.selectbox("🏫 Nivel:", 
                                         ["INICIAL", "PRIMARIA", "SECUNDARIA", "PREUNIVERSITARIO",
                                          "TODOS LOS NIVELES"],
                                         key="dn_nivel_reg")
                if dn_nivel == "TODOS LOS NIVELES":
                    # Ed. Física, Inglés, etc. — acceso a TODOS los grados
                    dn_g = "ALL_NIVELES"
                    dn_nivel = "TODOS"
                    st.success(f"✅ Acceso a TODOS los grados: Inicial ({len(NIVELES_GRADOS['INICIAL'])}), "
                               f"Primaria ({len(NIVELES_GRADOS['PRIMARIA'])}), "
                               f"Secundaria ({len(NIVELES_GRADOS['SECUNDARIA'])}), "
                               f"Pre-U ({len(NIVELES_GRADOS['PREUNIVERSITARIO'])})")
                    st.caption("Grados: " + ", ".join(TODOS_LOS_GRADOS))
                    dn_areas_sel = ""
                elif dn_nivel in ["INICIAL", "PRIMARIA"]:
                    _grados_niv = ["N/A"] + NIVELES_GRADOS.get(dn_nivel, [])
                    dn_g_base = st.selectbox("🎓 Grado Asignado:",
                                         _grados_niv, key="dn_grado")
                    if dn_g_base and dn_g_base != "N/A":
                        dn_sec = st.selectbox("🔤 Sección:",
                                         ["Única", "A", "B", "C", "D"],
                                         key="dn_seccion_reg")
                        dn_g = f"{dn_g_base} — Sección {dn_sec}" if dn_sec != "Única" else dn_g_base
                        st.caption(f"✅ Asignado a: **{dn_g}**")
                    else:
                        dn_g = dn_g_base
                else:
                    # SECUNDARIA y PREUNIVERSITARIO: acceso a TODOS los grados de ambos niveles
                    dn_g = "ALL_SEC_PREU"
                    grados_sec = NIVELES_GRADOS.get('SECUNDARIA', [])
                    grados_preu = NIVELES_GRADOS.get('PREUNIVERSITARIO', [])
                    st.success(f"✅ Acceso automático a TODOS los grados de Secundaria ({len(grados_sec)}) y Pre-U ({len(grados_preu)})")
                    st.caption("Grados: " + ", ".join(grados_sec + grados_preu))
                    # Todas las áreas SEC + PREU combinadas
                    todas_areas = list(AREAS_MINEDU.get('SECUNDARIA', []))
                    for a in AREAS_CEPRE_UNSAAC.get('GRUPO AB', []):
                        if a not in todas_areas:
                            todas_areas.append(a)
                    for a in AREAS_CEPRE_UNSAAC.get('GRUPO CD', []):
                        if a not in todas_areas:
                            todas_areas.append(a)
                    st.info(f"📚 {len(todas_areas)} áreas disponibles (Secundaria + CEPRE UNSAAC)")
                    dn_areas_sel = todas_areas  # Todas seleccionadas por defecto
            else:
                # Directora, Auxiliar, etc. — acceso completo sin grado
                dn_nivel = "PRIMARIA"
                dn_g = "N/A"
                st.caption(f"🔓 {dn_c}: acceso completo (sin grado específico)")
            dn_email = st.text_input("📧 Email:", key="dn_email",
                                      placeholder="nombre@ieyachay.org")
            dn_foto = st.file_uploader("📸 Foto:", type=['jpg', 'png', 'jpeg'],
                                        key="dn_foto")
            if dn_foto:
                st.image(dn_foto, width=120)
            # Opción para crear cuenta de acceso
            crear_cuenta = st.checkbox("🔐 Crear cuenta de acceso al sistema", value=True, key="crear_cuenta_doc")
            if crear_cuenta:
                cc1, cc2 = st.columns(2)
                with cc1:
                    dn_usuario = st.text_input("👤 Usuario:", 
                                                value=dn_n.strip().lower().replace(' ', '.').split('.')[0] if dn_n else '',
                                                key="dn_usuario_auto",
                                                placeholder="ej: prof.matematica")
                with cc2:
                    dn_password = st.text_input("🔑 Contraseña:", 
                                                 value=dn_d.strip() if dn_d else '',
                                                 key="dn_pass_auto",
                                                 placeholder="DNI por defecto")

        if st.button("✅ REGISTRAR DOCENTE", type="primary",
                     use_container_width=True, key="bd"):
            if dn_n and dn_d:
                if dn_foto:
                    foto_path = f"foto_doc_{dn_d.strip()}.png"
                    with open(foto_path, "wb") as fout:
                        fout.write(dn_foto.getbuffer())
                areas_txt = ', '.join(dn_areas_sel) if dn_areas_sel else dn_e.strip()
                BaseDatos.registrar_docente({
                    'Nombre': dn_n.strip().upper(), 'DNI': dn_d.strip(),
                    'Cargo': dn_c, 'Especialidad': areas_txt,
                    'Celular': dn_t.strip(), 'Grado_Asignado': dn_g,
                    'Email': dn_email.strip(), 'Nivel': dn_nivel,
                    'Areas': areas_txt
                })
                st.success(f"✅ {dn_n} registrado como {dn_c}")
                
                # Auto-crear cuenta de usuario
                if crear_cuenta and dn_usuario and dn_password:
                    usuarios = cargar_usuarios()
                    u_key = dn_usuario.strip().lower()
                    rol_auto = "docente" if dn_c == "Docente" else ("auxiliar" if dn_c == "Auxiliar" else "directivo")
                    
                    # Solo docentes tienen grado/nivel
                    if rol_auto == "docente":
                        di = {"label": dn_n.strip().upper(), "grado": dn_g, "nivel": dn_nivel, "dni": dn_d.strip()}
                    else:
                        di = None  # Directivos y auxiliares no necesitan grado
                    
                    usuarios[u_key] = {
                        "password": dn_password,
                        "rol": rol_auto,
                        "label": dn_n.strip().upper(),
                        "docente_info": di,
                    }
                    guardar_usuarios(usuarios)
                    st.success(f"🔐 Cuenta creada: **{u_key}** / contraseña: **{dn_password}** / rol: **{rol_auto}**")
                
                if dn_areas_sel:
                    st.info(f"📚 Áreas: {areas_txt}")
                reproducir_beep_exitoso()
                st.balloons()
            else:
                st.error("⚠️ Nombre y DNI requeridos")

    with tab_lista:
        st.subheader("📚 Alumnos Matriculados")
        df = BaseDatos.cargar_matricula()
        if not df.empty:
            c1, c2, c3 = st.columns(3)
            with c1:
                fn = st.selectbox("Nivel:", ["Todos"] + list(NIVELES_GRADOS.keys()),
                                  key="fn")
            with c2:
                go = ["Todos"] + (NIVELES_GRADOS[fn] if fn != "Todos"
                                  else TODOS_LOS_GRADOS)
                fg = st.selectbox("Grado:", go, key="fg")
            with c3:
                bq = st.text_input("🔍 Buscar:", key="bq")
            d = df.copy()
            if fn != "Todos" and 'Nivel' in d.columns:
                d = d[d['Nivel'] == fn]
            if fg != "Todos" and 'Grado' in d.columns:
                d = d[d['Grado'] == fg]
            if bq:
                d = d[d.apply(lambda r: bq.lower() in str(r).lower(), axis=1)]
            if 'Nombre' in d.columns:
                d = d.sort_values('Nombre')
            st.metric("Resultados", len(d))
            st.dataframe(d, use_container_width=True, hide_index=True, height=400)
            buf = io.BytesIO()
            d.to_excel(buf, index=False, engine='openpyxl')
            buf.seek(0)
            st.download_button("⬇️ Excel", buf,
                               f"Matricula_{config['anio']}.xlsx", key="dme")
            # Solo admin puede eliminar
            if puede_borrar():
                with st.expander("🗑️ Eliminar Alumno"):
                    deld = st.text_input("DNI a eliminar:", key="dd")
                    if st.button("🗑️ Eliminar", key="bdel", type="primary"):
                        if deld:
                            BaseDatos.eliminar_estudiante(deld)
                            st.rerun()
        else:
            st.info("📝 Sin alumnos matriculados.")

        st.markdown("---")
        st.subheader("DOCENTE Docentes Registrados")
        df_doc = BaseDatos.cargar_docentes()
        if not df_doc.empty:
            if 'Nombre' in df_doc.columns:
                df_doc = df_doc.sort_values('Nombre')
            st.dataframe(df_doc, use_container_width=True, hide_index=True)
            buf2 = io.BytesIO()
            df_doc.to_excel(buf2, index=False, engine='openpyxl')
            buf2.seek(0)
            st.download_button("⬇️ Excel Docentes", buf2,
                               "docentes.xlsx", key="dmedoc")
            if puede_borrar():
                with st.expander("🗑️ Eliminar Docente"):
                    deld2 = st.text_input("DNI:", key="dddoc")
                    if st.button("🗑️ Eliminar", key="bdeldoc", type="primary"):
                        if deld2:
                            BaseDatos.eliminar_docente(deld2)
                            st.rerun()
        else:
            st.info("📝 Sin docentes registrados.")

    with tab_pdf:
        _seccion_registros_pdf(config)




def _generar_pdf_acta_libros(config, grado, seccion, anio, tipo_texto, df_mat):
    """Acta de recepción de textos/libros con lista de alumnos y firmas."""
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, KeepTogether
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER, TA_JUSTIFY
    import io as _io
    buf = _io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            topMargin=1.8*cm, bottomMargin=1.8*cm,
                            leftMargin=2*cm, rightMargin=2*cm)
    styles = getSampleStyleSheet()
    st_t = ParagraphStyle('T', fontSize=11, alignment=TA_CENTER,
                           fontName='Helvetica-Bold', spaceAfter=4,
                           parent=styles['Normal'])
    st_b = ParagraphStyle('B', fontSize=9, alignment=TA_JUSTIFY,
                           leading=13, spaceAfter=6, parent=styles['Normal'])
    fecha_hoy = fecha_peru_str()
    # Obtener alumnos del grado
    alumnos = []
    if not df_mat.empty:
        fil = df_mat[df_mat.get('Grado', pd.Series(dtype=str)) == grado] if 'Grado' in df_mat.columns else df_mat
        if seccion != 'Todas' and 'Seccion' in fil.columns:
            fil = fil[fil['Seccion'] == seccion]
        for _, row in fil.iterrows():
            alumnos.append(str(row.get('Nombre', '')))
    story = [
        Paragraph("I.E.P. ALTERNATIVO YACHAY — CHINCHERO, CUSCO", st_t),
        Paragraph("ACTA DE RECEPCIÓN DE TEXTOS ESCOLARES", st_t),
        Paragraph(f"GRADO: {grado}  |  SECCIÓN: {seccion}  |  AÑO: {anio}",
                  ParagraphStyle('s', fontSize=9, alignment=TA_CENTER,
                                 parent=styles['Normal'], spaceAfter=6)),
        Spacer(1, 0.3*cm),
        Paragraph(
            f"Siendo las ____:____ del día ____ de ____________ de {anio}, el/la docente "
            f"del {grado} — Sección {seccion} hace entrega de <b>{tipo_texto}</b> "
            f"a los padres/madres de familia, quienes firman en señal de recepción conforme.", st_b),
        Spacer(1, 0.2*cm),
        Paragraph("<b>RELACIÓN DE ALUMNOS Y RECEPCIÓN:</b>",
                  ParagraphStyle('h', fontName='Helvetica-Bold', fontSize=9,
                                 parent=styles['Normal'], spaceAfter=4)),
    ]
    header = [["N°", "APELLIDOS Y NOMBRES DEL ALUMNO/A", "TEXTO RECIBIDO", "ESTADO", "FIRMA PADRE/MADRE"]]
    rows = []
    for i, alu in enumerate(alumnos[:30], 1):
        rows.append([str(i), alu[:45], "□ Completo  □ Incompleto", "□B □R □M", ""])
    if not rows:
        for i in range(1, 26):
            rows.append([str(i), "", "□ Completo  □ Incompleto", "□B □R □M", ""])
    t = Table(header + rows, colWidths=[0.7*cm, 5.8*cm, 4*cm, 2*cm, 4*cm])
    t.setStyle(TableStyle([
        ('FONTNAME', (0,0), (-1,0), 'Helvetica-Bold'),
        ('FONTSIZE', (0,0), (-1,-1), 7.5),
        ('GRID', (0,0), (-1,-1), 0.4, colors.black),
        ('BACKGROUND', (0,0), (-1,0), colors.Color(0.1,0.1,0.4)),
        ('TEXTCOLOR', (0,0), (-1,0), colors.white),
        ('ALIGN', (0,0), (-1,-1), 'CENTER'),
        ('ALIGN', (1,1), (1,-1), 'LEFT'),
        ('ROWBACKGROUNDS', (0,1), (-1,-1), [colors.white, colors.Color(0.97,0.97,1)]),
        ('MINROWHEIGHT', (0,1), (-1,-1), 0.65*cm),
    ]))
    story += [t, Spacer(1, 0.3*cm)]
    story.append(KeepTogether([
        Paragraph("Se firma la presente acta en señal de conformidad con la entrega.", st_b),
        Spacer(1, 0.6*cm),
        Table([
            ["_______________________________", "  ", "_______________________________"],
            ["Docente de Aula", "  ", "Directora"],
            [f"{grado} — Sección {seccion}", "  ", "I.E.P. ALTERNATIVO YACHAY"],
        ], colWidths=[7*cm, 0.5*cm, 7*cm],
        style=TableStyle([
            ('FONTSIZE',(0,0),(-1,-1),9),('ALIGN',(0,0),(-1,-1),'CENTER'),
        ])),
        Spacer(1, 0.3*cm),
        Paragraph(f"<i>YACHAY PRO — {fecha_hoy}</i>",
                  ParagraphStyle('fi', fontSize=7, alignment=TA_CENTER,
                                 textColor=colors.grey, parent=styles['Normal'])),
    ]))
    doc.build(story)
    buf.seek(0)
    return buf


def _generar_pdf_carta_compromiso_padre(config, alumno, padre, grado, motivo, anio):
    """Carta de compromiso del padre/madre de familia."""
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER, TA_JUSTIFY, TA_LEFT
    import io as _io
    buf = _io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            topMargin=2.5*cm, bottomMargin=2.5*cm,
                            leftMargin=3*cm, rightMargin=3*cm)
    styles = getSampleStyleSheet()
    st_t = ParagraphStyle('T', fontSize=13, alignment=TA_CENTER,
                           fontName='Helvetica-Bold', spaceAfter=8,
                           parent=styles['Normal'])
    st_b = ParagraphStyle('B', fontSize=10.5, alignment=TA_JUSTIFY,
                           leading=18, spaceAfter=12, parent=styles['Normal'])
    st_l = ParagraphStyle('L', fontSize=10.5, alignment=TA_LEFT,
                           leading=16, spaceAfter=8, parent=styles['Normal'])
    fecha_hoy = fecha_peru_str()
    compromisos = {
        "Bajo rendimiento académico": [
            "Revisar diariamente el cuaderno de tareas y firma de control.",
            "Asegurar un espacio y tiempo adecuado para el estudio en casa.",
            "Asistir a las reuniones de padres convocadas por el docente.",
            "Buscar apoyo académico adicional si fuera necesario.",
            "Mantener comunicación permanente con el/la docente del aula.",
        ],
        "Inasistencias reiteradas": [
            "Garantizar la asistencia puntual y regular de mi hijo/a a clases.",
            "Comunicar oportunamente las ausencias justificadas a la institución.",
            "Asegurar que mi hijo/a recupere los contenidos de las clases perdidas.",
            "Presentar justificaciones médicas u otras en los plazos establecidos.",
        ],
        "Problemas de conducta": [
            "Establecer normas claras de comportamiento en el hogar.",
            "Coordinar permanentemente con el/la docente y auxiliar.",
            "Asistir a las citaciones de tutoría sin excepción.",
            "Apoyar las acciones correctivas establecidas por la institución.",
            "No justificar conductas inapropiadas de mi hijo/a.",
        ],
        "Compromiso general de apoyo": [
            "Apoyar activamente el proceso educativo de mi hijo/a.",
            "Participar en las actividades escolares convocadas.",
            "Mantener comunicación fluida con el equipo docente.",
            "Velar por el bienestar integral de mi hijo/a.",
        ],
        "Deudas pendientes": [
            "Regularizar los pagos pendientes en el plazo acordado.",
            "Cumplir con el cronograma de pagos establecido.",
            "Comunicar oportunamente cualquier dificultad económica.",
        ],
    }
    lista = compromisos.get(motivo, compromisos["Compromiso general de apoyo"])
    story = [
        Paragraph("I.E.P. ALTERNATIVO YACHAY", st_t),
        Paragraph("CARTA DE COMPROMISO DEL PADRE / MADRE DE FAMILIA", st_t),
        Spacer(1, 0.5*cm),
        Paragraph(f"Chinchero, {fecha_hoy}", ParagraphStyle('d', fontSize=10,
                   alignment=TA_LEFT, parent=styles['Normal'], spaceAfter=16)),
        Paragraph(
            f"Yo, <b>{padre or '___________________________________'}</b>, "
            f"identificado/a con DNI N° _________________________, padre/madre del/la "
            f"estudiante <b>{alumno or '___________________________________'}</b>, "
            f"del grado <b>{grado}</b>, año {anio}, me comprometo ante la I.E.P. ALTERNATIVO YACHAY "
            f"a cumplir los siguientes acuerdos en relación a: <b>{motivo}</b>:", st_b),
        Spacer(1, 0.2*cm),
    ]
    for i, comp in enumerate(lista, 1):
        story.append(Paragraph(f"<b>{i}.</b> {comp}", st_l))
    story += [
        Spacer(1, 0.4*cm),
        Paragraph(
            "Declaro haber recibido orientación sobre la situación de mi hijo/a y me comprometo "
            "a cumplir lo acordado, entendiendo que el incumplimiento reiterado podrá derivar "
            "en las acciones que la institución considere pertinentes.", st_b),
        Spacer(1, 1.2*cm),
        Table([
            ["_______________________________", "  ", "_______________________________"],
            [padre or "________________________", "  ", "Tutor/a del Aula"],
            ["Padre / Madre de Familia", "  ", f"{grado}"],
            ["DNI: ____________________", "  ", "I.E.P. ALTERNATIVO YACHAY"],
        ], colWidths=[7*cm, 0.5*cm, 7*cm],
        style=TableStyle([
            ('FONTSIZE',(0,0),(-1,-1),9), ('ALIGN',(0,0),(-1,-1),'CENTER'),
        ])),
        Spacer(1, 0.5*cm),
        Paragraph(f"<i>YACHAY PRO — {fecha_hoy}</i>",
                  ParagraphStyle('fi', fontSize=7, alignment=TA_CENTER,
                                 textColor=colors.grey, parent=styles['Normal'])),
    ]
    doc.build(story)
    buf.seek(0)
    return buf


def _generar_pdf_acta_entrega_salon(config, docente_nombre, grado, seccion, anio):
    """Acta de entrega de salón — firmada por directora y docente."""
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_JUSTIFY
    import io as _io
    buf = _io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            topMargin=2*cm, bottomMargin=2*cm,
                            leftMargin=2.5*cm, rightMargin=2.5*cm)
    styles = getSampleStyleSheet()
    st_title = ParagraphStyle('T', parent=styles['Heading1'],
                               fontSize=13, alignment=TA_CENTER, spaceAfter=4)
    st_sub   = ParagraphStyle('S', parent=styles['Normal'],
                               fontSize=10, alignment=TA_CENTER, spaceAfter=8)
    st_body  = ParagraphStyle('B', parent=styles['Normal'],
                               fontSize=10, alignment=TA_JUSTIFY,
                               leading=16, spaceAfter=8)
    st_bold  = ParagraphStyle('BB', parent=st_body, fontName='Helvetica-Bold')
    fecha_hoy = fecha_peru_str()
    story = [
        Paragraph("I.E.P. ALTERNATIVO YACHAY", st_title),
        Paragraph("Chinchero, Cusco — Pioneros en la Educación de Calidad", st_sub),
        Spacer(1, 0.3*cm),
        Paragraph("ACTA DE ENTREGA DE SALÓN DE CLASES", st_title),
        Spacer(1, 0.5*cm),
        Paragraph(f"En la ciudad de Chinchero, a los ____ días del mes de ____________ del año {anio}, "
                  f"siendo las ____:____ horas, en las instalaciones de la I.E.P. ALTERNATIVO YACHAY, "
                  f"la Directora de la institución hace entrega formal del salón de clases al/la docente "
                  f"responsable del presente año escolar.", st_body),
        Spacer(1, 0.3*cm),
        Paragraph("<b>DATOS DEL SALÓN:</b>", st_bold),
    ]
    data_salon = [
        ["Grado y Sección:", f"{grado} — Sección {seccion}"],
        ["Docente responsable:", docente_nombre or "___________________________________"],
        ["Año escolar:", str(anio)],
        ["Aula N°:", "___________"],
        ["Número de carpetas:", "___________"],
        ["Número de sillas:", "___________"],
        ["Pizarrón:", "□ Bueno  □ Regular  □ Malo"],
        ["Estado general del aula:", "□ Bueno  □ Regular  □ Necesita mantenimiento"],
    ]
    t_salon = Table(data_salon, colWidths=[6*cm, 10*cm])
    t_salon.setStyle(TableStyle([
        ('FONTSIZE', (0,0), (-1,-1), 9),
        ('FONTNAME', (0,0), (0,-1), 'Helvetica-Bold'),
        ('GRID', (0,0), (-1,-1), 0.5, colors.grey),
        ('BACKGROUND', (0,0), (0,-1), colors.Color(0.9,0.9,1)),
        ('VALIGN', (0,0), (-1,-1), 'MIDDLE'),
        ('ROWBACKGROUNDS', (0,0), (-1,-1), [colors.white, colors.Color(0.97,0.97,1)]),
    ]))
    story += [t_salon, Spacer(1, 0.4*cm)]
    story.append(Paragraph("<b>INVENTARIO BÁSICO DEL AULA:</b>", st_bold))
    inv_data = [
        ["Ítem", "Descripción", "Cantidad", "Estado"],
        ["01", "Pizarrón / pizarra", "_____", "□B □R □M"],
        ["02", "Carpetas / mesas unipersonales", "_____", "□B □R □M"],
        ["03", "Sillas del docente", "_____", "□B □R □M"],
        ["04", "Escritorio del docente", "_____", "□B □R □M"],
        ["05", "Armario / estante", "_____", "□B □R □M"],
        ["06", "Televisor / Smart TV", "_____", "□B □R □M  □No hay"],
        ["07", "Proyector / cañón", "_____", "□B □R □M  □No hay"],
        ["08", "Equipo de sonido / parlante", "_____", "□B □R □M  □No hay"],
        ["09", "Computadora / laptop", "_____", "□B □R □M  □No hay"],
        ["10", "Extintor", "_____", "□Sí □No"],
        ["11", "Botiquín básico", "_____", "□Sí □No"],
        ["12", "Ventanas operativas", "_____", "□B □R □M"],
        ["13", "Puerta con llave", "_____", "□Sí □No"],
        ["14", "Tomacorrientes operativos", "_____", "□B □R □M"],
        ["15", "Otros:", "_______________", "___________"],
    ]
    t_inv = Table(inv_data, colWidths=[1.2*cm, 7*cm, 3*cm, 4.3*cm])
    t_inv.setStyle(TableStyle([
        ('FONTNAME', (0,0), (-1,0), 'Helvetica-Bold'),
        ('FONTSIZE', (0,0), (-1,-1), 8.5),
        ('GRID', (0,0), (-1,-1), 0.5, colors.black),
        ('BACKGROUND', (0,0), (-1,0), colors.Color(0.1,0.1,0.4)),
        ('TEXTCOLOR', (0,0), (-1,0), colors.white),
        ('ALIGN', (0,0), (-1,-1), 'CENTER'),
        ('ALIGN', (1,1), (1,-1), 'LEFT'),
        ('ROWBACKGROUNDS', (0,1), (-1,-1), [colors.white, colors.Color(0.95,0.95,1)]),
    ]))
    story += [t_inv, Spacer(1, 0.3*cm)]

    # Firmas en el mismo bloque (KeepTogether evita que salten de página)
    from reportlab.platypus import KeepTogether
    firma_data = [
        ["_______________________________", "    ", "_______________________________"],
        ["DIRECTORA", "    ", "DOCENTE RESPONSABLE"],
        [config.get('directora','Lic. ___________________'), "    ", docente_nombre or "___________________"],
        ["Directora I.E.P. ALTERNATIVO YACHAY", "    ", f"{grado} — Sección {seccion}"],
        ["Sello y firma", "    ", "Firma"],
    ]
    t_firma = Table(firma_data, colWidths=[7*cm, 1.5*cm, 7*cm])
    t_firma.setStyle(TableStyle([
        ('FONTSIZE', (0,0), (-1,-1), 9),
        ('ALIGN', (0,0), (-1,-1), 'CENTER'),
        ('FONTNAME', (0,1), (0,1), 'Helvetica-Bold'),
        ('FONTNAME', (2,1), (2,1), 'Helvetica-Bold'),
    ]))
    pie = Paragraph(
        f"<i>Documento generado por YACHAY PRO — {fecha_hoy}</i>",
        ParagraphStyle('F', parent=styles['Normal'], fontSize=7, alignment=TA_CENTER,
                       textColor=colors.grey))
    story.append(KeepTogether([
        Paragraph("Ambas partes declaran conformes con el inventario descrito. "
                  "El/la docente se compromete a devolver el salón en el mismo estado "
                  "o mejor al finalizar el año escolar.", st_body),
        Spacer(1, 1.0*cm),
        t_firma,
        Spacer(1, 0.4*cm),
        pie,
    ]))
    doc.build(story)
    buf.seek(0)
    return buf


def _generar_pdf_constancia_reglamento(config, solicitante, cargo, grado=""):
    """Constancia de solicitud / entrega del Reglamento Interno y Normas de Convivencia."""
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_JUSTIFY
    import io as _io
    buf = _io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            topMargin=2*cm, bottomMargin=2*cm,
                            leftMargin=2.5*cm, rightMargin=2.5*cm)
    styles = getSampleStyleSheet()
    st_c = ParagraphStyle('C', parent=styles['Normal'], fontSize=12, alignment=TA_CENTER,
                           fontName='Helvetica-Bold', spaceAfter=6)
    st_b = ParagraphStyle('B', parent=styles['Normal'], fontSize=10,
                           alignment=TA_JUSTIFY, leading=16, spaceAfter=10)
    anio = config.get('anio', 2026)
    fecha_hoy = fecha_peru_str()
    story = [
        Paragraph("I.E.P. ALTERNATIVO YACHAY", st_c),
        Paragraph("Chinchero — Cusco", ParagraphStyle('s',parent=styles['Normal'],
                                                       fontSize=10,alignment=TA_CENTER,spaceAfter=4)),
        Spacer(1, 0.4*cm),
        Paragraph("CONSTANCIA DE RECEPCIÓN DEL REGLAMENTO INTERNO", st_c),
        Paragraph("Y NORMAS DE CONVIVENCIA ESCOLAR", st_c),
        Spacer(1, 0.6*cm),
        Paragraph(
            f"La Dirección de la I.E.P. ALTERNATIVO YACHAY de Chinchero, Cusco, "
            f"hace constar que el/la señor(a) <b>{solicitante or '___________________________________'}</b>, "
            f"con cargo de <b>{cargo or '___________________'}</b>"
            + (f" del grado <b>{grado}</b>" if grado else "") +
            f", ha recibido copia del <b>Reglamento Interno</b> y las "
            f"<b>Normas de Convivencia Escolar</b> vigentes para el año lectivo <b>{anio}</b>, "
            f"comprometiéndose a su cumplimiento y difusión en el ámbito correspondiente.", st_b),
        Spacer(1, 0.3*cm),
        Paragraph("<b>DOCUMENTOS ENTREGADOS:</b>",
                  ParagraphStyle('h', parent=styles['Normal'], fontSize=10,
                                 fontName='Helvetica-Bold')),
        Spacer(1, 0.2*cm),
    ]
    docs_data = [
        ["✓", "Reglamento Interno I.E.P. ALTERNATIVO YACHAY — Año " + str(anio)],
        ["✓", "Normas de Convivencia Escolar — Aprobadas en Asamblea General"],
        ["✓", "Protocolo de Atención a Estudiantes y Familias"],
        ["✓", "Calendario de Actividades y Compromisos del Año Escolar"],
        ["□", "Otro: _______________________________________________"],
    ]
    t_docs = Table(docs_data, colWidths=[0.8*cm, 14*cm])
    t_docs.setStyle(TableStyle([
        ('FONTSIZE', (0,0), (-1,-1), 9.5),
        ('VALIGN', (0,0), (-1,-1), 'MIDDLE'),
        ('ROWBACKGROUNDS', (0,0), (-1,-1), [colors.white, colors.Color(0.96,0.96,1)]),
    ]))
    story += [t_docs, Spacer(1, 0.8*cm)]
    story.append(Paragraph(
        f"Se expide la presente constancia a solicitud del interesado(a), "
        f"en Chinchero a los ____ días del mes de ____________ del {anio}.", st_b))
    story.append(Spacer(1, 1.5*cm))
    firma2 = [
        ["_______________________________", "    ", "_______________________________"],
        ["FIRMA DEL RECEPTOR/A", "    ", "Vo.Bo. DIRECTORA"],
        [solicitante or "___________________", "    ", config.get('directora','Directora')],
        [cargo or "___________________", "    ", "I.E.P. ALTERNATIVO YACHAY"],
    ]
    t_f2 = Table(firma2, colWidths=[7*cm, 1.5*cm, 7*cm])
    t_f2.setStyle(TableStyle([
        ('FONTSIZE', (0,0), (-1,-1), 9), ('ALIGN', (0,0), (-1,-1), 'CENTER'),
        ('FONTNAME', (0,1), (0,1), 'Helvetica-Bold'),
        ('FONTNAME', (2,1), (2,1), 'Helvetica-Bold'),
    ]))
    story += [t_f2, Spacer(1, 0.5*cm)]
    story.append(Paragraph(
        f"<i>YACHAY PRO — {fecha_hoy}</i>",
        ParagraphStyle('fi', parent=styles['Normal'], fontSize=7,
                       alignment=TA_CENTER, textColor=colors.grey)))
    doc.build(story)
    buf.seek(0)
    return buf


def _generar_pdf_junta_directiva_aula(config, grado, seccion, anio):
    """Acta de conformación de la Junta Directiva del Comité de Aula (MINEDU)."""
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER, TA_JUSTIFY
    import io as _io
    buf = _io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            topMargin=1.8*cm, bottomMargin=1.8*cm,
                            leftMargin=2*cm, rightMargin=2*cm)
    styles = getSampleStyleSheet()
    st_t = ParagraphStyle('T', parent=styles['Heading1'], fontSize=11,
                           alignment=TA_CENTER, spaceAfter=4)
    st_b = ParagraphStyle('B', parent=styles['Normal'], fontSize=9,
                           alignment=TA_JUSTIFY, leading=14, spaceAfter=6)
    fecha_hoy = fecha_peru_str()
    story = [
        Paragraph("I.E.P. ALTERNATIVO YACHAY — CHINCHERO, CUSCO", st_t),
        Paragraph("ACTA DE CONFORMACIÓN DE LA JUNTA DIRECTIVA DEL COMITÉ DE AULA", st_t),
        Paragraph(f"GRADO: {grado}  |  SECCIÓN: {seccion}  |  AÑO: {anio}",
                  ParagraphStyle('s', parent=styles['Normal'], fontSize=9,
                                 alignment=TA_CENTER, spaceAfter=6)),
        Spacer(1, 0.3*cm),
        Paragraph(
            f"Siendo las ____:____ horas del día ____ de ____________ del {anio}, "
            f"reunidos los padres de familia del {grado} — Sección {seccion} de la I.E.P. "
            f"ALTERNATIVO YACHAY, bajo la conducción del/la docente de aula, se procede "
            f"a la elección democrática de la Junta Directiva del Comité de Aula conforme "
            f"lo establece la R.M. N° 627-2016-MINEDU y normas vigentes.", st_b),
        Spacer(1, 0.2*cm),
        Paragraph("<b>JUNTA DIRECTIVA ELEGIDA:</b>",
                  ParagraphStyle('h', parent=styles['Normal'], fontName='Helvetica-Bold',
                                 fontSize=9, spaceAfter=4)),
    ]
    cargos_data = [
        ["CARGO", "APELLIDOS Y NOMBRES COMPLETOS", "DNI", "FIRMA"],
        ["Presidente/a", "", "", ""],
        ["Vicepresidente/a", "", "", ""],
        ["Secretario/a", "", "", ""],
        ["Tesorero/a", "", "", ""],
        ["Vocal 1", "", "", ""],
        ["Vocal 2", "", "", ""],
    ]
    # Paragraphs en cargo para wrap automático
    from reportlab.platypus import Paragraph as _P
    st_cell = ParagraphStyle('cell', parent=styles['Normal'], fontSize=7.5,
                              leading=9, alignment=TA_CENTER)
    st_hdr  = ParagraphStyle('hdr', parent=styles['Normal'], fontSize=8,
                              fontName='Helvetica-Bold', leading=10, alignment=TA_CENTER)
    cargos_wrapped = []
    for i, row in enumerate(cargos_data):
        style = st_hdr if i == 0 else st_cell
        cargos_wrapped.append([_P(str(row[0]), style), row[1], row[2], row[3]])
    t_c = Table(cargos_wrapped, colWidths=[4.2*cm, 6.6*cm, 2.2*cm, 3.5*cm])
    t_c.setStyle(TableStyle([
        ('FONTNAME', (1,0), (-1,0), 'Helvetica-Bold'),
        ('FONTSIZE', (1,0), (-1,-1), 8),
        ('GRID', (0,0), (-1,-1), 0.5, colors.black),
        ('BACKGROUND', (0,0), (-1,0), colors.Color(0.1,0.1,0.4)),
        ('TEXTCOLOR', (0,0), (-1,0), colors.white),
        ('ALIGN', (0,0), (-1,-1), 'CENTER'),
        ('VALIGN', (0,0), (-1,-1), 'MIDDLE'),
        ('ROWBACKGROUNDS', (0,1), (-1,-1), [colors.white, colors.Color(0.95,0.95,1)]),
        ('MINROWHEIGHT', (0,1), (-1,-1), 1.1*cm),
        ('TOPPADDING', (0,0), (-1,-1), 5),
        ('BOTTOMPADDING', (0,0), (-1,-1), 5),
        ('LEFTPADDING', (0,0), (0,-1), 4),
        ('RIGHTPADDING', (0,0), (0,-1), 4),
    ]))
    story += [t_c, Spacer(1, 0.3*cm)]

    # Lista de padres presentes con firma
    story.append(Paragraph("<b>PADRES/MADRES DE FAMILIA PRESENTES EN LA REUNIÓN:</b>",
                  ParagraphStyle('h2', parent=styles['Normal'], fontName='Helvetica-Bold',
                                 fontSize=9, spaceAfter=4)))
    asist_header = [["N°", "APELLIDOS Y NOMBRES DEL PADRE/MADRE", "DNI", "HIJO/A (ALUMNO/A)", "FIRMA"]]
    asist_rows = [[str(i), "", "", "", ""] for i in range(1, 21)]
    t_asist = Table(asist_header + asist_rows,
                    colWidths=[0.7*cm, 5.5*cm, 2.3*cm, 5*cm, 3*cm])
    t_asist.setStyle(TableStyle([
        ('FONTNAME', (0,0), (-1,0), 'Helvetica-Bold'),
        ('FONTSIZE', (0,0), (-1,-1), 7.5),
        ('GRID', (0,0), (-1,-1), 0.4, colors.black),
        ('BACKGROUND', (0,0), (-1,0), colors.Color(0.2,0.2,0.5)),
        ('TEXTCOLOR', (0,0), (-1,0), colors.white),
        ('ALIGN', (0,0), (-1,-1), 'CENTER'),
        ('ALIGN', (1,1), (1,-1), 'LEFT'),
        ('ALIGN', (3,1), (3,-1), 'LEFT'),
        ('ROWBACKGROUNDS', (0,1), (-1,-1), [colors.white, colors.Color(0.97,0.97,1)]),
        ('MINROWHEIGHT', (0,1), (-1,-1), 0.65*cm),
    ]))
    story += [t_asist, Spacer(1, 0.3*cm)]

    from reportlab.platypus import KeepTogether
    story.append(KeepTogether([
        Paragraph(
            "La Junta Directiva elegida se compromete a representar los intereses del aula, "
            "colaborar con la institución educativa y velar por la calidad educativa de los "
            "estudiantes. Se firma la presente acta en señal de conformidad.", st_b),
        Spacer(1, 0.6*cm),
        Table([
            ["_______________________________", "  ", "_______________________________"],
            ["Docente de Aula", "  ", "Directora I.E.P. ALTERNATIVO YACHAY"],
            [f"{grado} — Sección {seccion}", "  ", config.get('directora','')],
        ], colWidths=[7*cm, 0.5*cm, 7*cm],
        style=TableStyle([
            ('FONTSIZE',(0,0),(-1,-1),9),('ALIGN',(0,0),(-1,-1),'CENTER'),
            ('FONTNAME',(0,1),(-1,1),'Helvetica-Bold'),
        ])),
        Spacer(1, 0.3*cm),
        Paragraph(f"<i>Conforme R.M. N° 627-2016-MINEDU | YACHAY PRO — {fecha_hoy}</i>",
                  ParagraphStyle('fi', parent=styles['Normal'], fontSize=7,
                                 alignment=TA_CENTER, textColor=colors.grey)),
    ]))
    doc.build(story)
    buf.seek(0)
    return buf



def _seccion_documentos_auxiliar(config):
    """Módulo de documentos administrativos — navegación por botones, sin tabs."""
    st.subheader("📄 Documentos Administrativos")
    st.caption("Selecciona el documento que necesitas generar.")

    anio = config.get('anio', 2026)
    df_mat = BaseDatos.cargar_matricula()
    df_doc = BaseDatos.cargar_docentes() if hasattr(BaseDatos, 'cargar_docentes') else pd.DataFrame()
    grados_lista = []
    if not df_mat.empty and 'Grado' in df_mat.columns:
        grados_lista = sorted(df_mat['Grado'].dropna().unique().tolist())

    # Usar key con prefijo único para documentos — evita colisión con otros módulos
    _KEY = '_doc_inst_sel'
    if _KEY not in st.session_state:
        st.session_state[_KEY] = None

    # ── Grupos de documentos ─────────────────────────────────────────
    GRUPOS = {
        "Actas de Salon": {
            "color": "#1d4ed8",
            "docs": [
                ("Entrega de Salon",    "salon"),
                ("Junta Directiva",     "junta"),
                ("RI Alumnos",          "ri_alumnos"),
                ("RI Padres",           "ri_padres"),
                ("Acuerdos de Aula",    "acuerdos"),
                ("Seleccion de Textos", "seleccion_textos"),
                ("Material Propio",     "material_propio"),
                ("Conformidad Material","conformidad_material"),
            ]
        },
        "Relacion con Padres": {
            "color": "#7c3aed",
            "docs": [
                ("Constancia RI",       "constancia"),
                ("Compromiso Padres",   "compromiso"),
                ("Municipio Escolar",   "municipio"),
            ]
        },
        "Registros de Control": {
            "color": "#065f46",
            "docs": [
                ("Asistencia Manual",   "asist_manual"),
                ("Prestamo de Equipos", "prestamo"),
                ("Horas Colegiadas",    "horas_col"),
            ]
        },
        "Gestion Pedagogica": {
            "color": "#b91c1c",
            "docs": [
                ("Ficha de Monitoreo",  "monitoreo"),
                ("Programaciones Word", "programacion"),
            ]
        },
    }
    COLORES_BTN = {
        "salon": "#1d4ed8", "junta": "#2563eb", "ri_alumnos": "#3b82f6",
        "ri_padres": "#1e40af", "acuerdos": "#0f766e",
        "seleccion_textos": "#0c4a6e", "material_propio": "#155e75",
        "conformidad_material": "#164e63",
        "constancia": "#6d28d9", "compromiso": "#7c3aed", "municipio": "#8b5cf6",
        "asist_manual": "#065f46", "prestamo": "#059669", "horas_col": "#10b981",
        "monitoreo": "#b91c1c", "programacion": "#dc2626",
    }

    if st.session_state[_KEY] is None:
        import streamlit.components.v1 as _css_d

        # CSS forzado — primero para que aplique desde el inicio
        _css_d.html("""<script>
(function fixDocBtns() {
  var MAP = {
    'Entrega de Salon':    '#1d4ed8',
    'Junta Directiva':     '#2563eb',
    'RI Alumnos':          '#3b82f6',
    'RI Padres':           '#1e40af',
    'Acuerdos de Aula':    '#0f766e',
    'Seleccion de Textos': '#0c4a6e',
    'Material Propio':     '#155e75',
    'Conformidad Material':'#164e63',
    'Constancia RI':       '#6d28d9',
    'Compromiso Padres':   '#7c3aed',
    'Municipio Escolar':   '#8b5cf6',
    'Asistencia Manual':   '#065f46',
    'Prestamo de Equipos': '#059669',
    'Horas Colegiadas':    '#10b981',
    'Ficha de Monitoreo':  '#b91c1c',
    'Programaciones Word': '#dc2626',
  };
  function apply() {
    window.parent.document.querySelectorAll('button').forEach(function(b) {
      var txt = (b.innerText||'').trim();
      if(MAP[txt]) {
        var c = MAP[txt];
        b.style.setProperty('background', c, 'important');
        b.style.setProperty('background-color', c, 'important');
        b.style.setProperty('color', 'white', 'important');
        b.style.setProperty('-webkit-text-fill-color', 'white', 'important');
        b.style.setProperty('border', '2px solid rgba(255,255,255,0.3)', 'important');
        b.style.setProperty('font-weight', '700', 'important');
        b.style.setProperty('font-size', '0.85rem', 'important');
        b.style.setProperty('border-radius', '8px', 'important');
        b.style.setProperty('min-height', '42px', 'important');
        var p = b.querySelector('p');
        if(p) {
          p.style.setProperty('color','white','important');
          p.style.setProperty('-webkit-text-fill-color','white','important');
          p.style.setProperty('font-weight','700','important');
        }
      }
    });
  }
  apply();
  new MutationObserver(apply).observe(window.parent.document.body,
    {childList:true, subtree:true});
})();
</script>""", height=0)

        # Renderizar grupos — Actas de Salón tiene más docs, usar 2 filas
        for grupo, info in GRUPOS.items():
            color = info["color"]
            st.markdown(
                f"<div style='background:{color};color:white;padding:8px 14px;"
                f"border-radius:8px;font-weight:800;font-size:0.9rem;"
                f"margin:10px 0 6px 0;'>{grupo}</div>",
                unsafe_allow_html=True)
            docs = info["docs"]
            # Mostrar en filas de 3 botones
            for i in range(0, len(docs), 3):
                row_docs = docs[i:i+3]
                cols_btn = st.columns(len(row_docs))
                for ci, (label, key) in enumerate(row_docs):
                    with cols_btn[ci]:
                        if st.button(label, key=f"docbtn_{key}_inst",
                                      use_container_width=True, type="primary"):
                            st.session_state[_KEY] = key
                            st.rerun()
        return

    # ── Botón volver ─────────────────────────────────────────────────
