def _generar_registro_asistencia_manual(config, mes, n_dias, nombres_docentes):
    """Registro de asistencia con columnas ENTRADA/SALIDA por día para firma."""
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Table, TableStyle, Spacer
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER
    import io as _io
    buf  = _io.BytesIO()
    anio = config.get('anio', 2026)
    ie   = config.get('nombre_ie', 'I.E.P. ALTERNATIVO YACHAY')

    # Cada día tiene 2 columnas: E(ntrada) | S(alida)
    # Con 10 días por bloque caben bien en landscape A4
    DIAS_X_BLOQUE = 10

    def _bloque(dias_bloque, nombres):
        # Encabezado: N° | Apellidos y Nombres | D1-E | D1-S | D2-E | D2-S ...| Obs
        header_row1 = ['N°', 'APELLIDOS Y NOMBRES'] +                       [f'Día {d}' for d in dias_bloque for _ in range(2)] + ['Obs.']
        header_row2 = ['', ''] +                       ['E', 'S'] * len(dias_bloque) + ['']
        rows = [header_row1, header_row2]
        for i, nombre in enumerate(nombres):
            fila = [str(i+1), nombre] + [''] * (len(dias_bloque)*2) + ['']
            rows.append(fila)

        n_col = 2 + len(dias_bloque)*2 + 1
        ancho = 27*cm
        w_n = 0.55*cm; w_nom = 4.5*cm; w_obs = 1.2*cm
        w_dia = (ancho - w_n - w_nom - w_obs) / (len(dias_bloque)*2)
        col_ws = [w_n, w_nom] + [w_dia]*(len(dias_bloque)*2) + [w_obs]

        row_hs = [0.5*cm, 0.5*cm] + [0.65*cm]*len(nombres)

        t = Table(rows, colWidths=col_ws, rowHeights=row_hs)

        # Span días en fila 0
        style_cmds = [
            ('FONTNAME',(0,0),(-1,1),'Helvetica-Bold'),
            ('FONTSIZE',(0,0),(-1,1),6.5),
            ('FONTSIZE',(0,2),(-1,-1),7),
            ('BACKGROUND',(0,0),(-1,1),colors.Color(0.1,0.1,0.4)),
            ('TEXTCOLOR',(0,0),(-1,1),colors.white),
            ('ALIGN',(0,0),(-1,-1),'CENTER'),
            ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
            ('GRID',(0,0),(-1,-1),0.3,colors.black),
            ('ROWBACKGROUNDS',(0,2),(-1,-1),[colors.white, colors.Color(0.96,0.96,1)]),
            ('ALIGN',(1,2),(1,-1),'LEFT'),
            # Resaltar columnas E/S alternadas
        ]
        # Span cada "Día X" sobre sus 2 celdas E/S en fila 0
        for di, _ in enumerate(dias_bloque):
            c = 2 + di*2
            style_cmds.append(('SPAN',(c,0),(c+1,0)))
        # Color suave para E vs S
        for di in range(len(dias_bloque)):
            ce = 2 + di*2
            cs = 3 + di*2
            style_cmds.append(('BACKGROUND',(ce,1),(ce,1),colors.Color(0.7,0.85,1.0)))
            style_cmds.append(('BACKGROUND',(cs,1),(cs,1),colors.Color(1.0,0.75,0.75)))

        t.setStyle(TableStyle(style_cmds))
        return t

    doc = SimpleDocTemplate(buf, pagesize=landscape(A4),
                            topMargin=0.8*cm, bottomMargin=0.8*cm,
                            leftMargin=0.7*cm, rightMargin=0.7*cm)
    st_t = ParagraphStyle('T', fontSize=11, fontName='Helvetica-Bold',
                           alignment=TA_CENTER, parent=getSampleStyleSheet()['Normal'])
    st_s = ParagraphStyle('S', fontSize=7.5, alignment=TA_CENTER,
                           parent=getSampleStyleSheet()['Normal'])

    dias = list(range(1, n_dias+1))
    story = [
        Paragraph(f'REGISTRO DE ASISTENCIA DOCENTE — {mes.upper()} {anio}', st_t),
        Paragraph(f'{ie}  |  E = Entrada  |  S = Salida  |  '
                  f'Responsable: ___________________ | Firma: ___________', st_s),
        Spacer(1, 0.25*cm),
    ]

    # Dividir en bloques de DIAS_X_BLOQUE
    for i in range(0, len(dias), DIAS_X_BLOQUE):
        bloque_dias = dias[i:i+DIAS_X_BLOQUE]
        story.append(_bloque(bloque_dias, nombres_docentes))
        if i + DIAS_X_BLOQUE < len(dias):
            story.append(Spacer(1, 0.3*cm))

    story.append(Spacer(1, 0.4*cm))
    story.append(Paragraph(
        'FIRMA DEL DIRECTOR(A): ___________________________  '
        'FECHA: ___________  SELLO: ___________', st_s))
    doc.build(story)
    buf.seek(0)
    return buf


def _generar_control_prestamo_equipos(config):
    """Control de préstamo de equipos e implementos institucionales."""
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Table, TableStyle, Spacer, KeepTogether
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER
    import io as _io
    buf = _io.BytesIO()
    anio = config.get('anio', 2026)
    ie = config.get('nombre_ie', 'I.E.P. ALTERNATIVO YACHAY')
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            topMargin=1.5*cm, bottomMargin=1.5*cm,
                            leftMargin=1.8*cm, rightMargin=1.8*cm)
    styles = getSampleStyleSheet()
    st_t = ParagraphStyle('T', fontSize=12, fontName='Helvetica-Bold',
                           alignment=TA_CENTER, spaceAfter=4, parent=styles['Normal'])
    st_s = ParagraphStyle('S', fontSize=8, alignment=TA_CENTER, spaceAfter=6, parent=styles['Normal'])
    st_h = ParagraphStyle('H', fontSize=9, fontName='Helvetica-Bold',
                           spaceAfter=4, parent=styles['Normal'])

    EQUIPOS = [
        "Equipo de sonido / parlantes",
        "Micrófono inalámbrico",
        "Proyector / cañón",
        "Pantalla de proyección",
        "Laptop institucional",
        "Extensión eléctrica",
        "Cámara fotográfica",
        "Sillas plegables",
        "Mesas plegables",
        "Otros: _______________",
    ]
    story = [
        Paragraph(f"CONTROL DE PRÉSTAMO DE EQUIPOS E IMPLEMENTOS", st_t),
        Paragraph(f"{ie}  |  Año {anio}  |  Responsable Auxiliar: _________________________", st_s),
        Spacer(1, 0.3*cm),
    ]

    # Tabla de préstamos
    header = ["N\u00b0", "EQUIPO / MATERIAL", "FECHA SALIDA", "HORA SALIDA", "RESPONSABLE / DOCENTE", "DESTINO", "FECHA DEVOL.", "HORA DEVOL.", "ESTADO DEVOL.", "VB AUXILIAR"]
    rows = [header] + [[str(i+1), EQUIPOS[i % len(EQUIPOS)]] + [""]*8 for i in range(25)]
    col_ws = [0.7*cm, 3.5*cm, 1.5*cm, 1.2*cm, 3.8*cm, 2*cm, 1.5*cm, 1.2*cm, 1.5*cm, 1.5*cm]
    t = Table(rows, colWidths=col_ws,
              rowHeights=[1.1*cm] + [0.7*cm]*25)
    t.setStyle(TableStyle([
        ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
        ('FONTSIZE',(0,0),(-1,-1),7),
        ('BACKGROUND',(0,0),(-1,0),colors.Color(0.1,0.2,0.5)),
        ('TEXTCOLOR',(0,0),(-1,0),colors.white),
        ('ALIGN',(0,0),(-1,-1),'CENTER'),
        ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('GRID',(0,0),(-1,-1),0.4,colors.black),
        ('ROWBACKGROUNDS',(0,1),(-1,-1),[colors.white,colors.Color(0.95,0.95,1)]),
        ('ALIGN',(1,0),(1,-1),'LEFT'),
        ('ALIGN',(4,0),(4,-1),'LEFT'),
    ]))
    story.append(t)
    story.append(Spacer(1, 0.5*cm))

    # Inventario de equipos disponibles
    story.append(Paragraph("INVENTARIO DE EQUIPOS DISPONIBLES:", st_h))
    inv_data = [["N°","EQUIPO / IMPLEMENTO","CANTIDAD","ESTADO","OBSERVACIONES"]]
    for i, eq in enumerate(EQUIPOS[:-1]):
        inv_data.append([str(i+1), eq, "___", "Bueno / Regular / Malo", ""])
    t2 = Table(inv_data, colWidths=[0.7*cm, 5*cm, 1.5*cm, 3.5*cm, 4.3*cm],
               rowHeights=[0.7*cm]*len(inv_data))
    t2.setStyle(TableStyle([
        ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
        ('FONTSIZE',(0,0),(-1,-1),7.5),
        ('BACKGROUND',(0,0),(-1,0),colors.Color(0.2,0.2,0.5)),
        ('TEXTCOLOR',(0,0),(-1,0),colors.white),
        ('ALIGN',(0,0),(-1,-1),'CENTER'),
        ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('GRID',(0,0),(-1,-1),0.4,colors.black),
        ('ALIGN',(1,0),(1,-1),'LEFT'),
    ]))
    story.append(t2)
    doc.build(story)
    buf.seek(0)
    return buf


def _generar_control_horas_colegiadas(config, trimestre, n_sesiones, nombres_docentes):
    """
    Genera UN modelo de Acta de Trabajo Colegiado lista para imprimir y completar a mano.
    Formato oficial segun MINEDU: promotor + director + docentes firman al final.
    Se imprime tantas veces como sesiones haya (semanal o mensual).
    """
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import (SimpleDocTemplate, Paragraph, Table, TableStyle,
                                     Spacer, HRFlowable, KeepTogether)
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_JUSTIFY
    import io as _io

    buf  = _io.BytesIO()
    anio = config.get('anio', 2026)
    ie   = config.get('nombre_ie', 'I.E.P. ALTERNATIVO YACHAY')
    ugel = config.get('ugel', 'Urubamba')
    doc  = SimpleDocTemplate(buf, pagesize=A4,
                              topMargin=1.8*cm, bottomMargin=1.8*cm,
                              leftMargin=2.5*cm, rightMargin=2.5*cm)
    styles = getSampleStyleSheet()

    VERDE_OSC = colors.Color(0.05, 0.30, 0.05)
    VERDE_CLAR = colors.Color(0.88, 0.97, 0.88)
    AZUL_HEX  = colors.Color(0.10, 0.20, 0.50)
    GRIS = colors.Color(0.95, 0.95, 0.95)

    def P(txt, bold=False, size=10, align=TA_JUSTIFY, sb=3, sa=3, italic=False):
        fn = 'Helvetica-BoldOblique' if (bold and italic) else (
             'Helvetica-Bold' if bold else
             'Helvetica-Oblique' if italic else 'Helvetica')
        return Paragraph(
            txt,
            ParagraphStyle('pac', fontSize=size, leading=size+3.5,
                           alignment=align, spaceBefore=sb, spaceAfter=sa,
                           fontName=fn, parent=styles['Normal']))

    def linea_escrib(label, alto=0.8*cm, label_w=4*cm, total_w=15.5*cm):
        """Celda con etiqueta en negrita y espacio en blanco para escribir."""
        t = Table([[P(label, bold=True, size=9, align=TA_LEFT, sb=1, sa=1), ""]],
                  colWidths=[label_w, total_w - label_w],
                  rowHeights=[alto])
        t.setStyle(TableStyle([
            ('BOX',(0,0),(-1,-1),0.5,colors.black),
            ('LINEAFTER',(0,0),(0,0),0.5,colors.black),
            ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
            ('LEFTPADDING',(0,0),(-1,-1),4),
            ('BACKGROUND',(0,0),(0,0), VERDE_CLAR),
        ]))
        return t

    def bloque_lineas(label, n_lineas=4, alto_linea=0.8*cm):
        """Bloque con cabecera verde y n_lineas en blanco para escribir."""
        data = [[P(label, bold=True, size=9, align=TA_LEFT, sb=1, sa=1)]]
        for _ in range(n_lineas):
            data.append([""])
        row_hs = [0.55*cm] + [alto_linea]*n_lineas
        t = Table(data, colWidths=[15.5*cm], rowHeights=row_hs)
        t.setStyle(TableStyle([
            ('BOX',(0,0),(-1,-1),0.5,colors.black),
            ('LINEBELOW',(0,0),(0,0),0.5,colors.black),
            ('BACKGROUND',(0,0),(-1,0), VERDE_CLAR),
            ('GRID',(0,1),(-1,-1),0.3,colors.Color(0.8,0.8,0.8)),
            ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
            ('LEFTPADDING',(0,0),(-1,-1),4),
        ]))
        return t

    if not nombres_docentes:
        nombres_docentes = ["___________________________"] * 10

    story = []

    # ── ENCABEZADO ────────────────────────────────────────────────────
    story += [
        P(f"{ie.upper()}", bold=True, size=13, align=TA_CENTER, sb=0, sa=2),
        P(f"UGEL {ugel}  |  Año {anio}", size=9, align=TA_CENTER, sb=0, sa=2),
        HRFlowable(width="100%", thickness=2, color=VERDE_OSC, spaceAfter=6),
        P("ACTA DE REUNIÓN DE TRABAJO COLEGIADO",
          bold=True, size=14, align=TA_CENTER, sb=2, sa=2),
        P(f"{trimestre}  |  Año Escolar {anio}",
          size=10, align=TA_CENTER, sb=0, sa=4),
        HRFlowable(width="100%", thickness=1, color=VERDE_OSC, spaceAfter=8),
    ]

    # ── I. DATOS DE LA REUNION ─────────────────────────────────────────
    story.append(P("I. DATOS DE LA REUNIÓN", bold=True, size=10.5,
                   align=TA_LEFT, sb=4, sa=3))

    datos_cols = [2.8*cm, 4.9*cm, 2.8*cm, 5.0*cm]
    datos_data = [
        [P("Institución:", bold=True, size=8.5, sb=1,sa=1),
         P(ie, size=8.5, sb=1,sa=1),
         P("UGEL:", bold=True, size=8.5, sb=1,sa=1),
         P(ugel, size=8.5, sb=1,sa=1)],
        [P("Fecha:", bold=True, size=8.5, sb=1,sa=1),
         P("_____ / _____ / _______", size=8.5, sb=1,sa=1),
         P("N° Sesión:", bold=True, size=8.5, sb=1,sa=1),
         P("_____  de  _____  sesiones", size=8.5, sb=1,sa=1)],
        [P("Hora inicio:", bold=True, size=8.5, sb=1,sa=1),
         P("_______", size=8.5, sb=1,sa=1),
         P("Hora término:", bold=True, size=8.5, sb=1,sa=1),
         P("_______", size=8.5, sb=1,sa=1)],
        [P("Lugar:", bold=True, size=8.5, sb=1,sa=1),
         P("_______________________________", size=8.5, sb=1,sa=1),
         P("Modalidad:", bold=True, size=8.5, sb=1,sa=1),
         P("Presencial  /  Virtual  /  Mixto", size=8.5, sb=1,sa=1)],
    ]
    t_datos = Table(datos_data, colWidths=datos_cols,
                    rowHeights=[0.7*cm]*4)
    t_datos.setStyle(TableStyle([
        ('GRID',(0,0),(-1,-1),0.4,colors.black),
        ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('LEFTPADDING',(0,0),(-1,-1),5),
        ('BACKGROUND',(0,0),(0,-1), VERDE_CLAR),
        ('BACKGROUND',(2,0),(2,-1), VERDE_CLAR),
    ]))
    story.append(t_datos)
    story.append(Spacer(1, 0.25*cm))

    # ── II. AGENDA / TEMAS ───────────────────────────────────────────
    story.append(P("II. AGENDA DE LA REUNIÓN", bold=True, size=10.5,
                   align=TA_LEFT, sb=4, sa=3))
    agenda_data = [
        [P("N°", bold=True, size=8.5, align=TA_CENTER, sb=1,sa=1),
         P("PUNTO DE AGENDA / TEMA A TRATAR", bold=True, size=8.5, align=TA_CENTER, sb=1,sa=1),
         P("RESPONSABLE", bold=True, size=8.5, align=TA_CENTER, sb=1,sa=1),
         P("TIEMPO", bold=True, size=8.5, align=TA_CENTER, sb=1,sa=1)],
    ]
    for i in range(6):
        agenda_data.append([
            P(str(i+1), size=8.5, align=TA_CENTER, sb=1,sa=1),
            "", "", ""
        ])
    t_agenda = Table(agenda_data,
                     colWidths=[0.8*cm, 10.0*cm, 3.0*cm, 1.7*cm],
                     rowHeights=[0.65*cm] + [0.75*cm]*6)
    t_agenda.setStyle(TableStyle([
        ('GRID',(0,0),(-1,-1),0.4,colors.black),
        ('BACKGROUND',(0,0),(-1,0), VERDE_OSC),
        ('TEXTCOLOR',(0,0),(-1,0), colors.white),
        ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
        ('ALIGN',(0,0),(-1,0),'CENTER'),
        ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('LEFTPADDING',(0,0),(-1,-1),4),
    ]))
    story.append(t_agenda)
    story.append(Spacer(1, 0.3*cm))

    # ── IV. DESARROLLO / TEMAS TRATADOS ──────────────────────────────
    story.append(P("III. DESARROLLO DE LA REUNIÓN — RESUMEN DE TEMAS TRATADOS",
                   bold=True, size=10.5, align=TA_LEFT, sb=4, sa=3))
    desarr_data = [
        [P("TEMA TRATADO", bold=True, size=8.5, align=TA_CENTER, sb=1,sa=1),
         P("DESCRIPCION / CONTENIDO DESARROLLADO", bold=True, size=8.5, align=TA_CENTER, sb=1,sa=1)],
    ]
    for _ in range(5):
        desarr_data.append(["", ""])
    t_des = Table(desarr_data,
                  colWidths=[4.5*cm, 11.0*cm],
                  rowHeights=[0.65*cm] + [1.2*cm]*5)
    t_des.setStyle(TableStyle([
        ('GRID',(0,0),(-1,-1),0.4,colors.black),
        ('BACKGROUND',(0,0),(-1,0), VERDE_OSC),
        ('TEXTCOLOR',(0,0),(-1,0), colors.white),
        ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
        ('ALIGN',(0,0),(-1,0),'CENTER'),
        ('VALIGN',(0,0),(-1,-1),'TOP'),
        ('LEFTPADDING',(0,0),(-1,-1),4),
        ('TOPPADDING',(0,1),(-1,-1),5),
    ]))
    story.append(t_des)
    story.append(Spacer(1, 0.3*cm))

    # ── V. ACUERDOS Y COMPROMISOS ─────────────────────────────────────
    story.append(P("IV. ACUERDOS Y COMPROMISOS", bold=True, size=10.5,
                   align=TA_LEFT, sb=4, sa=3))
    acuerdos_data = [
        [P("N°", bold=True, size=8.5, align=TA_CENTER, sb=1,sa=1),
         P("ACUERDO / COMPROMISO", bold=True, size=8.5, align=TA_CENTER, sb=1,sa=1),
         P("RESPONSABLE", bold=True, size=8.5, align=TA_CENTER, sb=1,sa=1),
         P("PLAZO / FECHA", bold=True, size=8.5, align=TA_CENTER, sb=1,sa=1)],
    ]
    for i in range(6):
        acuerdos_data.append([
            P(str(i+1), size=8.5, align=TA_CENTER, sb=1,sa=1),
            "", "", ""
        ])
    t_ac = Table(acuerdos_data,
                 colWidths=[0.8*cm, 9.5*cm, 3.0*cm, 2.2*cm],
                 rowHeights=[0.65*cm] + [0.85*cm]*6)
    t_ac.setStyle(TableStyle([
        ('GRID',(0,0),(-1,-1),0.4,colors.black),
        ('BACKGROUND',(0,0),(-1,0), VERDE_OSC),
        ('TEXTCOLOR',(0,0),(-1,0), colors.white),
        ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
        ('ALIGN',(0,0),(-1,0),'CENTER'),
        ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('LEFTPADDING',(0,0),(-1,-1),4),
    ]))
    story.append(t_ac)
    story.append(Spacer(1, 0.3*cm))

    # ── VI. PROXIMA REUNION ───────────────────────────────────────────
    prox_data = [[
        P("PRÓXIMA REUNIÓN:", bold=True, size=8.5, sb=1,sa=1),
        P("Fecha: _______________", size=8.5, sb=1,sa=1),
        P("Hora: _________", size=8.5, sb=1,sa=1),
        P("Tema: _________________________________________", size=8.5, sb=1,sa=1),
    ]]
    t_prox = Table(prox_data, colWidths=[3.5*cm, 3.5*cm, 2.5*cm, 6.0*cm],
                   rowHeights=[0.7*cm])
    t_prox.setStyle(TableStyle([
        ('BOX',(0,0),(-1,-1),0.5,VERDE_OSC),
        ('GRID',(0,0),(-1,-1),0.3,colors.Color(0.7,0.9,0.7)),
        ('BACKGROUND',(0,0),(-1,-1), VERDE_CLAR),
        ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('LEFTPADDING',(0,0),(-1,-1),5),
    ]))
    story.append(t_prox)
    story.append(Spacer(1, 0.5*cm))

    # ── VII. FIRMAS ───────────────────────────────────────────────────
    story.append(HRFlowable(width="100%", thickness=1, color=VERDE_OSC, spaceAfter=6))
    story.append(P(
        f"Siendo las _____ horas se da por concluida la presente reunión en "
        f"Chinchero, a los _____ días del mes de _____________________ de {anio}.",
        size=9.5, align=TA_JUSTIFY, sb=2, sa=8))

    # Firmas principales: Promotor + Director + Secretario
    # Usar celdas con altura real para la firma — NO strings con \n
    espacio_firma = P("", size=9, sb=1, sa=1)  # celda vacía para firmar

    def celda_firma(titulo, nombre_label=""):
        """Celda de firma con cabecera verde oscura y espacio real en blanco."""
        inner = Table(
            [[P(titulo, bold=True, size=8.5, align=TA_CENTER, sb=1, sa=1)],
             [espacio_firma],
             [P(nombre_label or "Nombres y apellidos: _____________________",
                size=7.5, align=TA_CENTER, sb=1, sa=1)]],
            colWidths=[5.0*cm],
            rowHeights=[0.65*cm, 2.2*cm, 0.55*cm])
        inner.setStyle(TableStyle([
            ('BOX',   (0,0),(-1,-1), 0.8, VERDE_OSC),
            ('LINEBELOW',(0,0),(0,0), 0.5, VERDE_OSC),
            ('LINEABOVE',(0,2),(0,2), 0.5, colors.Color(0.7,0.7,0.7)),
            ('BACKGROUND',(0,0),(0,0), VERDE_OSC),
            ('TEXTCOLOR',(0,0),(0,0), colors.white),
            ('BACKGROUND',(0,1),(0,1), colors.white),
            ('BACKGROUND',(0,2),(0,2), VERDE_CLAR),
            ('ALIGN',  (0,0),(-1,-1), 'CENTER'),
            ('VALIGN', (0,0),(-1,-1), 'MIDDLE'),
        ]))
        return inner

    firmas_row = Table(
        [[celda_firma("FIRMA DEL PROMOTOR(A)"),
          celda_firma("FIRMA Y SELLO DEL DIRECTOR(A)"),
          celda_firma("SECRETARIO(A) DE ACTAS")]],
        colWidths=[5.1*cm, 5.2*cm, 5.2*cm],
        rowHeights=[3.6*cm])
    firmas_row.setStyle(TableStyle([
        ('VALIGN',(0,0),(-1,-1),'TOP'),
        ('LEFTPADDING',(0,0),(-1,-1),1),
        ('RIGHTPADDING',(0,0),(-1,-1),1),
    ]))
    story.append(firmas_row)
    story.append(Spacer(1, 0.3*cm))

    # Firmas de TODOS los docentes — 2 columnas (nombre + firma)
    story.append(P("FIRMAS DE TODOS LOS DOCENTES PARTICIPANTES:",
                   bold=True, size=9, align=TA_LEFT, sb=2, sa=3))

    # Tabla de 2 columnas: (N° | Nombre | Firma) repetido 2 veces en la misma fila
    # Cabecera
    doc_f_data = [[
        P("N°", bold=True, size=8, align=TA_CENTER, sb=1,sa=1),
        P("APELLIDOS Y NOMBRES", bold=True, size=8, align=TA_CENTER, sb=1,sa=1),
        P("FIRMA", bold=True, size=8, align=TA_CENTER, sb=1,sa=1),
        P("N°", bold=True, size=8, align=TA_CENTER, sb=1,sa=1),
        P("APELLIDOS Y NOMBRES", bold=True, size=8, align=TA_CENTER, sb=1,sa=1),
        P("FIRMA", bold=True, size=8, align=TA_CENTER, sb=1,sa=1),
    ]]

    # Dividir docentes en 2 columnas
    mitad = (len(nombres_docentes) + 1) // 2
    col_izq = nombres_docentes[:mitad]
    col_der = nombres_docentes[mitad:]

    n_filas_doc = max(len(col_izq), len(col_der))
    for i in range(n_filas_doc):
        nom_izq = col_izq[i] if i < len(col_izq) else ""
        nom_der = col_der[i] if i < len(col_der) else ""
        n_izq   = i + 1
        n_der   = mitad + i + 1 if i < len(col_der) else ""
        doc_f_data.append([
            P(str(n_izq), size=8, align=TA_CENTER, sb=1,sa=1),
            P(nom_izq, size=8, align=TA_LEFT, sb=1,sa=1),
            "",  # espacio firma
            P(str(n_der) if nom_der else "", size=8, align=TA_CENTER, sb=1,sa=1),
            P(nom_der, size=8, align=TA_LEFT, sb=1,sa=1),
            "",  # espacio firma
        ])

    # col: N°(0.6) | Nombre(5.2) | Firma(2.0) | sep | N°(0.6) | Nombre(5.2) | Firma(1.9)
    t_doc_f = Table(doc_f_data,
                    colWidths=[0.6*cm, 5.2*cm, 2.0*cm, 0.6*cm, 5.2*cm, 1.9*cm],
                    rowHeights=[0.6*cm] + [0.85*cm]*n_filas_doc)
    t_doc_f.setStyle(TableStyle([
        ('GRID',      (0,0),(-1,-1), 0.4, colors.black),
        ('FONTSIZE',  (0,0),(-1,-1), 7.5),
        ('VALIGN',    (0,0),(-1,-1), 'MIDDLE'),
        ('LEFTPADDING',(0,0),(-1,-1), 3),
        ('RIGHTPADDING',(0,0),(-1,-1), 3),
        # Cabecera verde oscura con texto BLANCO legible
        ('BACKGROUND',(0,0),(-1,0), VERDE_OSC),
        ('TEXTCOLOR', (0,0),(-1,0), colors.white),
        ('FONTNAME',  (0,0),(-1,0), 'Helvetica-Bold'),
        ('ALIGN',     (0,0),(-1,0), 'CENTER'),
        # Filas alternas
        ('ROWBACKGROUNDS',(0,1),(-1,-1),
         [colors.white, colors.Color(0.94,1,0.94)]),
        # Línea divisoria entre las dos mitades
        ('LINEAFTER', (2,0),(2,-1), 1.5, VERDE_OSC),
    ]))
    story.append(t_doc_f)
    story.append(Spacer(1, 0.25*cm))
    story.append(P(
        f"Nota: El presente documento tiene valor de declaración jurada. "
        f"Archivar en el file de Trabajo Colegiado {anio} y reportar a la UGEL {ugel} "
        f"al finalizar cada trimestre.",
        italic=True, size=8, align=TA_JUSTIFY, sb=2, sa=0))

    doc.build(story)
    buf.seek(0)
    return buf


def _generar_ficha_monitoreo(config, docente, area, grado, tipo_mon, director, anio):
    """Ficha de monitoreo pedagógico según MINEDU/GEREDU Cusco — MBDD."""
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import (SimpleDocTemplate, Paragraph, Table, TableStyle,
                                     Spacer, KeepTogether)
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_JUSTIFY
    import io as _io
    buf = _io.BytesIO()
    ie = config.get('nombre_ie', 'I.E.P. ALTERNATIVO YACHAY')
    ugel = config.get('ugel', 'Urubamba')
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            topMargin=1.5*cm, bottomMargin=1.5*cm,
                            leftMargin=1.8*cm, rightMargin=1.8*cm)
    styles = getSampleStyleSheet()
    def P(txt, bold=False, size=9, align=TA_LEFT, space=2):
        return Paragraph(txt if not bold else f"<b>{txt}</b>",
                         ParagraphStyle('p', fontSize=size, leading=size+2,
                                        alignment=align, spaceAfter=space,
                                        parent=styles['Normal']))
    def tabla(data, col_ws, row_hs=None):
        if row_hs is None:
            row_hs = [0.7*cm]*len(data)
        t = Table(data, colWidths=col_ws, rowHeights=row_hs)
        t.setStyle(TableStyle([
            ('GRID',(0,0),(-1,-1),0.4,colors.black),
            ('FONTSIZE',(0,0),(-1,-1),7.5),
            ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
            ('LEFTPADDING',(0,0),(-1,-1),4),
        ]))
        return t

    story = []
    # Encabezado
    story += [
        P("FICHA DE MONITOREO Y ACOMPAÑAMIENTO PEDAGÓGICO", bold=True, size=11, align=TA_CENTER, space=4),
        P(f"{ie}  |  UGEL {ugel}  |  Año {anio}", size=8, align=TA_CENTER, space=6),
        tabla([
            ["I. DATOS GENERALES","","",""],
            [f"DOCENTE: {docente or '_'*35}", f"ÁREA: {area or '_'*20}",
             f"GRADO: {grado or '_'*15}", f"FECHA: {' '*20}"],
            [f"DIRECTOR(A): {director or '_'*30}", f"TIPO: {tipo_mon}","N° SESIÓN: ____","HORA: _____"],
        ], [4.5*cm, 3.5*cm, 3*cm, 2.7*cm],
        [0.5*cm, 0.8*cm, 0.8*cm]),
        Spacer(1, 0.3*cm),
    ]

    # Competencias del MBDD
    COMPETENCIAS = [
        ("DOMINIO I: PREPARACIÓN PARA EL APRENDIZAJE", [
            ("Comp. 1", "Conoce y comprende las características de sus estudiantes y sus contextos",
             ["1.1 Demuestra conocimiento de las características individuales y evolutivas de sus estudiantes.",
              "1.2 Demuestra conocimiento de los enfoques y procesos pedagógicos del área.",
              "1.3 Planifica considerando las necesidades e intereses de los estudiantes."]),
            ("Comp. 2", "Planifica la enseñanza de forma colegiada garantizando la coherencia",
             ["2.1 La planificación responde a las características del contexto.",
              "2.2 La unidad didáctica presenta coherencia entre propósitos, actividades y evaluación.",
              "2.3 La sesión de aprendizaje incluye los tres momentos didácticos.",
              "2.4 Los materiales están previstos y son pertinentes."]),
        ]),
        ("DOMINIO II: ENSEÑANZA PARA EL APRENDIZAJE", [
            ("Comp. 3", "Crea un clima propicio para el aprendizaje",
             ["3.1 Promueve relaciones de respeto y colaboración entre estudiantes.",
              "3.2 Genera un ambiente de confianza donde los estudiantes se sienten valorados.",
              "3.3 Maneja el tiempo eficientemente."]),
            ("Comp. 4", "Conduce el proceso de enseñanza con dominio del contenido disciplinar",
             ["4.1 Desarrolla estrategias pedagógicas pertinentes al contenido.",
              "4.2 Utiliza recursos didácticos significativos para el aprendizaje.",
              "4.3 Maneja estrategias de retroalimentación formativa.",
              "4.4 Sistematiza y cierra el aprendizaje de forma clara.",
              "4.5 Usa las TIC como herramienta de aprendizaje cuando corresponde."]),
            ("Comp. 5", "Evalúa permanentemente el aprendizaje",
             ["5.1 Utiliza técnicas e instrumentos de evaluación pertinentes.",
              "5.2 Proporciona retroalimentación oportuna y de calidad.",
              "5.3 Sistematiza los resultados para la toma de decisiones."]),
        ]),
    ]
    escala = ["L = Logrado", "EP = En Proceso", "I = Inicio", "NE = No Evidenciado"]
    story.append(P(f"ESCALA: {'  |  '.join(escala)}", size=7.5, space=4))

    for dominio, comps in COMPETENCIAS:
        story.append(P(dominio, bold=True, size=8.5, space=2))
        for cod, comp_txt, indicadores in comps:
            rows_comp = [[P(f"<b>{cod}</b>", size=7.5), P(comp_txt, size=7.5), "NIVEL", "EVIDENCIAS"]]
            for ind in indicadores:
                rows_comp.append(["", P(f"• {ind}", size=7), "L / EP / I / NE", ""])
            t_comp = Table(rows_comp, colWidths=[1*cm, 8*cm, 2.3*cm, 2.4*cm],
                           rowHeights=[0.6*cm]*(len(rows_comp)))
            t_comp.setStyle(TableStyle([
                ('GRID',(0,0),(-1,-1),0.3,colors.black),
                ('FONTSIZE',(0,0),(-1,-1),7),
                ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
                ('BACKGROUND',(0,0),(-1,0),colors.Color(0.85,0.9,1)),
                ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
                ('SPAN',(0,0),(0,len(rows_comp)-1)),
                ('LEFTPADDING',(0,0),(-1,-1),3),
            ]))
            story += [t_comp, Spacer(1, 0.2*cm)]
        story.append(Spacer(1, 0.2*cm))

    # Fortalezas / Aspectos de mejora / Compromisos
    rows_fm = [
        [P("<b>FORTALEZAS IDENTIFICADAS:</b>", size=8), P("<b>ASPECTOS DE MEJORA:</b>", size=8)],
        [P(" "*50+"\n"*3, size=7), P(" "*50+"\n"*3, size=7)],
        [P("<b>COMPROMISOS DEL DOCENTE:</b>", size=8),
         P("<b>PRÓXIMA VISITA / ACOMPAÑAMIENTO:</b>", size=8)],
        [P("\n\n", size=7), P("Fecha: ________________", size=7)],
    ]
    t_fm = Table(rows_fm, colWidths=[8.6*cm, 5.1*cm],
                 rowHeights=[0.5*cm, 1.8*cm, 0.5*cm, 0.7*cm])
    t_fm.setStyle(TableStyle([
        ('GRID',(0,0),(-1,-1),0.4,colors.black),
        ('VALIGN',(0,0),(-1,-1),'TOP'),
    ]))
    story += [t_fm, Spacer(1, 0.5*cm)]

    # Firmas
    firmas = [["FIRMA DEL DOCENTE", "FIRMA Y SELLO DEL DIRECTOR(A)"],
              [f"\n{docente or ''}\n", f"\n{director or ''}\n"]]
    t_f = Table(firmas, colWidths=[8*cm, 5.7*cm], rowHeights=[0.4*cm, 1.5*cm])
    t_f.setStyle(TableStyle([
        ('GRID',(0,0),(-1,-1),0.4,colors.black),
        ('ALIGN',(0,0),(-1,-1),'CENTER'),
        ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
        ('FONTSIZE',(0,0),(-1,-1),8),
        ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('BACKGROUND',(0,0),(-1,0),colors.Color(0.85,0.85,0.95)),
    ]))
    story.append(t_f)
    doc.build(story)
    buf.seek(0)
    return buf


def _generar_esquema_programacion_word(config, nivel, tipo, docente, area, grado, ciclo, anio):
    """Genera esquema de programación curricular en Word usando python-docx."""
    from docx import Document as _DocxDoc
    from docx.shared import Pt as _Pt, Cm as _Cm, RGBColor as _RGB, Inches as _In
    from docx.enum.text import WD_ALIGN_PARAGRAPH as _WDA
    from docx.enum.table import WD_ALIGN_VERTICAL as _WDAV
    from docx.oxml.ns import qn as _qn
    from docx.oxml import OxmlElement as _OxmlEl
    import io as _io

    ie   = config.get('nombre_ie', 'I.E.P. ALTERNATIVO YACHAY')
    ugel = config.get('ugel', 'Urubamba')
    AZUL_HEX = 'BDD7EE'
    HDR_HEX  = '1F3864'

    def _set_bg(cell, hex_color):
        tc = cell._tc; tcPr = tc.get_or_add_tcPr()
        shd = _OxmlEl('w:shd')
        shd.set(_qn('w:val'),'clear'); shd.set(_qn('w:color'),'auto')
        shd.set(_qn('w:fill'), hex_color); tcPr.append(shd)

    def _set_borders(cell, color='000000'):
        tc = cell._tc; tcPr = tc.get_or_add_tcPr()
        # Remove existing tcBorders first
        for old in tcPr.findall(_qn('w:tcBorders')):
            tcPr.remove(old)
        tcB = _OxmlEl('w:tcBorders')
        for e in ('top','left','bottom','right'):
            el = _OxmlEl(f'w:{e}')
            el.set(_qn('w:val'),'single')
            el.set(_qn('w:sz'),'4')
            el.set(_qn('w:color'), color)
            tcB.append(el)
        tcPr.append(tcB)

    def _cell_write(cell, txt='', bg=None, bold=False, size=9,
                    center=False, italic=False, color_txt=None, wrap=True):
        """Write text into a cell with proper formatting."""
        _set_borders(cell)
        if bg:
            _set_bg(cell, bg)
        cell.vertical_alignment = _WDAV.CENTER
        # Set word wrap
        tc = cell._tc; tcPr = tc.get_or_add_tcPr()
        noWrap = tcPr.find(_qn('w:noWrap'))
        if noWrap is not None and wrap:
            tcPr.remove(noWrap)
        # Clear and write
        for para in cell.paragraphs:
            for run in para.runs:
                run.text = ''
        p = cell.paragraphs[0] if cell.paragraphs else cell.add_paragraph()
        p.clear()
        p.alignment = _WDA.CENTER if center else _WDA.LEFT
        p.paragraph_format.space_before = _Pt(1)
        p.paragraph_format.space_after  = _Pt(1)
        run = p.add_run(str(txt))
        run.bold = bold; run.italic = italic
        run.font.size = _Pt(size)
        run.font.name = 'Arial'
        if color_txt:
            r,g,b = int(color_txt[0:2],16), int(color_txt[2:4],16), int(color_txt[4:6],16)
            run.font.color.rgb = _RGB(r,g,b)
        elif bg == HDR_HEX:
            run.font.color.rgb = _RGB(0xFF,0xFF,0xFF)
        return cell

    def _set_col_widths(table, widths_cm):
        """Set exact column widths."""
        for row in table.rows:
            row.height_rule = None
            for ci, cell in enumerate(row.cells):
                if ci < len(widths_cm):
                    cell.width = _Cm(widths_cm[ci])
        # Also set table layout to fixed
        tbl = table._tbl
        tblPr = tbl.find(_qn('w:tblPr'))
        if tblPr is None:
            tblPr = _OxmlEl('w:tblPr')
            tbl.insert(0, tblPr)
        tblLayout = _OxmlEl('w:tblLayout')
        tblLayout.set(_qn('w:type'), 'fixed')
        # Remove existing layout
        for old in tblPr.findall(_qn('w:tblLayout')):
            tblPr.remove(old)
        tblPr.append(tblLayout)

    def _par(doc, txt, bold=False, size=10, center=False, sb=4, sa=2, color_hex=None):
        p = doc.add_paragraph()
        p.alignment = _WDA.CENTER if center else _WDA.LEFT
        p.paragraph_format.space_before = _Pt(sb)
        p.paragraph_format.space_after  = _Pt(sa)
        run = p.add_run(str(txt))
        run.bold = bold; run.font.size = _Pt(size); run.font.name = 'Arial'
        if color_hex:
            r,g,b = int(color_hex[0:2],16), int(color_hex[2:4],16), int(color_hex[4:6],16)
            run.font.color.rgb = _RGB(r,g,b)
        return p

    doc = _DocxDoc()
    sec = doc.sections[0]
    sec.top_margin = _Cm(1.8); sec.bottom_margin = _Cm(1.8)
    sec.left_margin = _Cm(2);  sec.right_margin  = _Cm(2)
    doc.styles['Normal'].font.name = 'Arial'
    doc.styles['Normal'].font.size = _Pt(10)

    # ── Encabezado ────────────────────────────────────────────────────
    _par(doc, ie.upper(), bold=True, size=13, center=True, sb=0, sa=2)
    _par(doc, f'UGEL {ugel}  |  Año {anio}', size=9, center=True, sb=0, sa=4)
    _par(doc, f'{tipo.upper()} — {nivel.upper()}',
         bold=True, size=12, center=True, sb=0, sa=8, color_hex=HDR_HEX)

    # ── Tabla datos generales ─────────────────────────────────────────
    t0 = doc.add_table(rows=3, cols=4)
    t0.style = 'Table Grid'
    _set_col_widths(t0, [3.8, 5.0, 3.2, 4.0])
    datos = [
        ['INSTITUCIÓN EDUCATIVA', ie,                   'ÁREA CURRICULAR',  area or '___________'],
        ['DOCENTE',               docente or '___________________',
                                                         'GRADO Y SECCIÓN',  grado or '_______'],
        ['CICLO',                 ciclo or '____',       'AÑO',              str(anio)],
    ]
    for ri, row_data in enumerate(datos):
        row = t0.rows[ri]
        for ci, val in enumerate(row_data):
            _cell_write(row.cells[ci], val,
                        bg=AZUL_HEX if ci%2==0 else None,
                        bold=(ci%2==0), size=8.5, center=(ci%2==0))

    doc.add_paragraph().paragraph_format.space_after = _Pt(4)

    # ══════════════════════════════════════════════════════════════════
    if tipo == "Planificación Anual":
        _par(doc, 'I. PROPÓSITOS DE APRENDIZAJE Y ENFOQUES TRANSVERSALES',
             bold=True, size=10.5, color_hex=HDR_HEX)
        t1 = doc.add_table(rows=7, cols=3)
        t1.style = 'Table Grid'
        _set_col_widths(t1, [5.4, 5.4, 5.2])
        for ci, h in enumerate(['COMPETENCIAS / CAPACIDADES',
                                  'ESTÁNDARES DE APRENDIZAJE', 'DESEMPEÑOS PRECISADOS']):
            _cell_write(t1.rows[0].cells[ci], h, bg=AZUL_HEX, bold=True, size=8.5, center=True)
        for ri in range(1,7):
            for ci in range(3):
                _cell_write(t1.rows[ri].cells[ci], '', size=9)

        _par(doc, 'ENFOQUES TRANSVERSALES:', bold=True, size=9.5, sb=8, sa=2)
        t2 = doc.add_table(rows=4, cols=2)
        t2.style = 'Table Grid'
        _set_col_widths(t2, [8.0, 8.0])
        for ci, h in enumerate(['ENFOQUES', 'VALORES Y ACTITUDES']):
            _cell_write(t2.rows[0].cells[ci], h, bg=AZUL_HEX, bold=True, size=8.5, center=True)
        for ri in range(1,4):
            for ci in range(2): _cell_write(t2.rows[ri].cells[ci], '', size=9)

        _par(doc, 'II. ORGANIZACIÓN Y DISTRIBUCIÓN DEL TIEMPO — UNIDADES DIDÁCTICAS',
             bold=True, size=10.5, color_hex=HDR_HEX, sb=10, sa=2)
        t3 = doc.add_table(rows=10, cols=5)
        t3.style = 'Table Grid'
        _set_col_widths(t3, [3.0, 1.5, 4.5, 1.5, 5.5])
        for ci, h in enumerate(['TÍTULO DE LA UNIDAD', 'TIPO',
                                  'SITUACIÓN SIGNIFICATIVA', 'N° SESIONES', 'COMPETENCIAS']):
            _cell_write(t3.rows[0].cells[ci], h, bg=AZUL_HEX, bold=True, size=8, center=True)
        for ri in range(1,10):
            _cell_write(t3.rows[ri].cells[0], f'Unidad {ri}:', size=8.5, bold=True)
            for ci in range(1,5): _cell_write(t3.rows[ri].cells[ci], '', size=9)

    elif tipo == "Unidad Didáctica":
        _par(doc, 'I. PROPÓSITOS DE APRENDIZAJE', bold=True, size=10.5, color_hex=HDR_HEX)
        t1 = doc.add_table(rows=5, cols=4)
        t1.style = 'Table Grid'
        _set_col_widths(t1, [4.0, 4.0, 4.0, 4.0])
        for ci, h in enumerate(['COMPETENCIAS/CAPACIDADES', 'DESEMPEÑOS PRECISADOS',
                                  'PRODUCTO/EVIDENCIA', 'CRITERIOS DE EVALUACIÓN']):
            _cell_write(t1.rows[0].cells[ci], h, bg=AZUL_HEX, bold=True, size=8.5, center=True)
        for ri in range(1,5):
            for ci in range(4): _cell_write(t1.rows[ri].cells[ci], '', size=9)

        _par(doc, 'II. ENFOQUES TRANSVERSALES', bold=True, size=9.5, sb=8, sa=2)
        t2 = doc.add_table(rows=3, cols=3)
        t2.style = 'Table Grid'
        _set_col_widths(t2, [5.3, 5.3, 5.4])
        for ci, h in enumerate(['ENFOQUE', 'VALORES', 'ACTITUDES OBSERVABLES']):
            _cell_write(t2.rows[0].cells[ci], h, bg=AZUL_HEX, bold=True, size=8.5, center=True)
        for ri in range(1,3):
            for ci in range(3): _cell_write(t2.rows[ri].cells[ci], '', size=9)

        _par(doc, 'III. SITUACIÓN SIGNIFICATIVA', bold=True, size=9.5, sb=8, sa=2)
        t3 = doc.add_table(rows=4, cols=1)
        t3.style = 'Table Grid'
        _set_col_widths(t3, [16.0])
        _cell_write(t3.rows[0].cells[0],
                    'Descripción de la situación que genera el reto o problema de aprendizaje:',
                    bg=AZUL_HEX, bold=True, size=8.5)
        for ri in range(1,4): _cell_write(t3.rows[ri].cells[0], '', size=9)

        _par(doc, 'IV. SECUENCIA DE SESIONES DE APRENDIZAJE', bold=True, size=9.5, sb=8, sa=2)
        t4 = doc.add_table(rows=11, cols=4)
        t4.style = 'Table Grid'
        _set_col_widths(t4, [1.8, 7.5, 1.5, 5.2])
        for ci, h in enumerate(['SESIÓN', 'TÍTULO / ACTIVIDAD PRINCIPAL', 'HORAS', 'MATERIALES']):
            _cell_write(t4.rows[0].cells[ci], h, bg=AZUL_HEX, bold=True, size=8.5, center=True)
        for ri in range(1,11):
            _cell_write(t4.rows[ri].cells[0], f'Ses. {ri}', center=True, size=9)
            for ci in range(1,4): _cell_write(t4.rows[ri].cells[ci], '', size=9)

    else:  # Sesión de Aprendizaje
        _par(doc, 'I. DATOS INFORMATIVOS', bold=True, size=10.5, color_hex=HDR_HEX, sb=4, sa=2)
        t_info = doc.add_table(rows=2, cols=6)
        t_info.style = 'Table Grid'
        _set_col_widths(t_info, [2.5, 4.5, 2.0, 2.0, 2.0, 3.0])
        info_rows = [
            ['ÁREA', area or '___', 'GRADO', grado or '___', 'DURACIÓN', '___ min'],
            ['DOCENTE', docente or '___________________', 'CICLO', ciclo or '___', 'FECHA', '___________'],
        ]
        for ri, row_data in enumerate(info_rows):
            for ci, val in enumerate(row_data):
                _cell_write(t_info.rows[ri].cells[ci], val,
                            bg=AZUL_HEX if ci%2==0 else None,
                            bold=(ci%2==0), size=8.5, center=(ci%2==0))
        t_tit = doc.add_table(rows=1, cols=2)
        t_tit.style = 'Table Grid'
        _set_col_widths(t_tit, [4.0, 12.0])
        _cell_write(t_tit.rows[0].cells[0], 'TÍTULO DE LA SESIÓN', bg=AZUL_HEX, bold=True, size=8.5)
        _cell_write(t_tit.rows[0].cells[1], '', size=9)

        _par(doc, 'II. PROPÓSITOS DE APRENDIZAJE Y CRITERIOS DE EVALUACIÓN',
             bold=True, size=10.5, color_hex=HDR_HEX, sb=8, sa=2)
        t1 = doc.add_table(rows=3, cols=4)
        t1.style = 'Table Grid'
        _set_col_widths(t1, [3.5, 4.5, 4.5, 3.5])
        for ci, h in enumerate(['COMPETENCIAS/CAPACIDADES', 'DESEMPEÑOS PRECISADOS',
                                  'EVIDENCIA/PRODUCTO', 'CRITERIOS DE EVALUACIÓN']):
            _cell_write(t1.rows[0].cells[ci], h, bg=AZUL_HEX, bold=True, size=8, center=True)
        for ri in range(1,3):
            for ci in range(4): _cell_write(t1.rows[ri].cells[ci], '', size=9)

        t_et = doc.add_table(rows=2, cols=4)
        t_et.style = 'Table Grid'
        _set_col_widths(t_et, [4.0, 4.0, 4.0, 4.0])
        for ci, h in enumerate(['ENFOQUE TRANSVERSAL', 'VALORES', 'ACTITUDES', 'INSTRUMENTO']):
            _cell_write(t_et.rows[0].cells[ci], h, bg=AZUL_HEX, bold=True, size=8, center=True)
        for ci in range(4): _cell_write(t_et.rows[1].cells[ci], '', size=9)

        _par(doc, 'III. SECUENCIA DIDÁCTICA', bold=True, size=10.5, color_hex=HDR_HEX, sb=8, sa=2)

        # Tabla con subfilas dentro de cada momento
        # MOMENTOS | ACTIVIDADES / ESTRATEGIAS | RECURSOS | TIEMPO
        MOMENTOS = [
            ('INICIO', 'E2EFDA', [
                ('• Saludo y motivación:', ''),
                ('• Saberes previos:', '¿Qué saben sobre...?'),
                ('• Normas de convivencia:', ''),
                ('• Propósito de la sesión:', 'Hoy aprenderemos...'),
                ('• Actividad de enganche:', ''),
            ]),
            ('DESARROLLO', 'DDEBF7', [
                ('• Presentación del reto / situación:', ''),
                ('• Actividad 1:', ''),
                ('• Actividad 2:', ''),
                ('• Actividad 3:', ''),
                ('• Actividad 4:', ''),
                ('• Monitoreo y acompañamiento:', ''),
                ('• Plenaria / socialización:', ''),
            ]),
            ('CIERRE', 'FFF2CC', [
                ('• Metacognición:', '¿Qué aprendiste hoy? ¿Cómo lo aprendiste?'),
                ('• Evaluación formativa:', ''),
                ('• Tarea / extensión:', ''),
            ]),
        ]

        # Encabezado de la tabla secuencia
        t2 = doc.add_table(rows=1, cols=4)
        t2.style = 'Table Grid'
        _set_col_widths(t2, [2.2, 9.8, 2.5, 1.5])
        for ci, h in enumerate(['MOMENTO', 'ACTIVIDADES / ESTRATEGIAS', 'MATERIALES', 'TIEMPO']):
            _cell_write(t2.rows[0].cells[ci], h, bg=AZUL_HEX, bold=True, size=8.5, center=True)

        for momento, bg_hex, subfilas in MOMENTOS:
            # Primera subfila con nombre del momento (rowspan visual)
            first = True
            for sub_label, sub_hint in subfilas:
                row = t2.add_row()
                _set_col_widths(t2, [2.2, 9.8, 2.5, 1.5])
                if first:
                    _cell_write(row.cells[0], momento, bg=bg_hex,
                                bold=True, center=True, size=9,
                                color_txt='1e293b' if bg_hex != HDR_HEX else None)
                    first = False
                else:
                    _cell_write(row.cells[0], '', bg=bg_hex, size=9)
                # Actividad con sugerencia en gris
                _set_borders(row.cells[1])
                p = row.cells[1].paragraphs[0]
                p.paragraph_format.space_before = _Pt(1)
                p.paragraph_format.space_after  = _Pt(1)
                r1 = p.add_run(sub_label)
                r1.bold = True; r1.font.size = _Pt(8.5); r1.font.name = 'Arial'
                if sub_hint:
                    r2 = p.add_run(f'  {sub_hint}')
                    r2.italic = True; r2.font.size = _Pt(8)
                    r2.font.name = 'Arial'
                    r2.font.color.rgb = _RGB(0x64, 0x74, 0x8B)
                _cell_write(row.cells[2], '', size=9)
                _cell_write(row.cells[3], '', center=True, size=9)

        _par(doc, 'IV. REFLEXIONES SOBRE EL APRENDIZAJE', bold=True, size=10.5,
             color_hex=HDR_HEX, sb=8, sa=2)
        t3 = doc.add_table(rows=3, cols=2)
        t3.style = 'Table Grid'
        _set_col_widths(t3, [8.0, 8.0])
        reflex = [
            '¿Qué logros tuvieron los estudiantes?',
            '¿Qué dificultades se identificaron?',
            '¿Qué aprendizajes debo reforzar en la siguiente sesión?',
            '¿Qué actividades y materiales funcionaron mejor?',
        ]
        for ri_r in range(2):
            for ci_r in range(2):
                ri_t = ri_r * 1
                _cell_write(t3.rows[ri_r*2].cells[ci_r] if ri_r == 0 else t3.rows[2].cells[ci_r],
                            reflex[ri_r*2 + ci_r], bg=AZUL_HEX, bold=True, size=8)
        for ci in range(2):
            _cell_write(t3.rows[1].cells[ci], '', size=9)

    # ── Firmas ────────────────────────────────────────────────────────
    doc.add_paragraph().paragraph_format.space_after = _Pt(8)
    _par(doc, f'Cusco, _____ de ___________ de {anio}', size=10, center=True, sb=10, sa=6)
    t_f = doc.add_table(rows=2, cols=2)
    t_f.style = 'Table Grid'
    _set_col_widths(t_f, [8.0, 8.0])
    _cell_write(t_f.rows[0].cells[0], 'FIRMA DEL DOCENTE',
                bg=AZUL_HEX, bold=True, center=True, size=9)
    _cell_write(t_f.rows[0].cells[1], 'FIRMA Y SELLO DEL DIRECTOR(A)',
                bg=AZUL_HEX, bold=True, center=True, size=9)
    _cell_write(t_f.rows[1].cells[0], f'\n\n{docente or ""}\n', center=True, size=9)
    _cell_write(t_f.rows[1].cells[1], '\n\n\n', center=True, size=9)

    buf = _io.BytesIO()
    doc.save(buf)
    buf.seek(0)
    return buf


def _generar_acta_reglamento_alumnos(config, grado, docente, n_filas=30):
    """Acta de conformidad de lectura del Reglamento Interno — Estudiantes."""
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, KeepTogether
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER, TA_JUSTIFY
    import io as _io
    buf = _io.BytesIO()
    anio = config.get('anio', 2026)
    ie = config.get('nombre_ie', 'I.E.P. ALTERNATIVO YACHAY')
    dre = config.get('dre', 'Cusco')
    ugel = config.get('ugel', 'Urubamba')
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            topMargin=1.8*cm, bottomMargin=1.8*cm,
                            leftMargin=2*cm, rightMargin=2*cm)
    styles = getSampleStyleSheet()
    st_t = ParagraphStyle('T', fontSize=11, fontName='Helvetica-Bold',
                           alignment=TA_CENTER, spaceAfter=4, parent=styles['Normal'])
    st_s = ParagraphStyle('S', fontSize=9, alignment=TA_CENTER,
                           spaceAfter=8, parent=styles['Normal'])
    st_b = ParagraphStyle('B', fontSize=9, alignment=TA_JUSTIFY,
                           leading=13, spaceAfter=6, parent=styles['Normal'])
    fecha_hoy = fecha_peru_str()
    story = [
        Paragraph(f"ACTA DE CONFORMIDAD DE LECTURA DEL REGLAMENTO INTERNO {anio}", st_t),
        Paragraph(ie, st_s),
        Spacer(1, 0.3*cm),
        Paragraph("II. DATOS INFORMATIVOS:", ParagraphStyle('h', fontName='Helvetica-Bold',
                   fontSize=9, parent=styles['Normal'], spaceAfter=4)),
    ]
    datos = [
        [f"2.1 DRE     :  {dre}", f"2.3 I.E.             :  {ie}"],
        [f"2.2 UGEL    :  {ugel}", f"2.4 Grado y Sección  :  {grado or '___________________________'}"],
    ]
    t_datos = Table(datos, colWidths=[8*cm, 8*cm])
    t_datos.setStyle(TableStyle([
        ('FONTSIZE',(0,0),(-1,-1), 8.5), ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('TOPPADDING',(0,0),(-1,-1), 3), ('BOTTOMPADDING',(0,0),(-1,-1), 3),
    ]))
    story += [t_datos, Spacer(1, 0.2*cm)]
    story.append(Paragraph(
        f"2.5 Docente / Tutor/a: {docente or '_______________________________________________'}",
        ParagraphStyle('d', fontSize=8.5, parent=styles['Normal'], spaceAfter=8)))
    story.append(Paragraph(
        f"Los estudiantes del {grado or '____________'} de la {ie} declaramos haber recibido, "
        f"leído y comprendido el Reglamento Interno y los Acuerdos de Convivencia "
        f"vigentes para el año lectivo {anio}, comprometiéndonos a su cumplimiento.", st_b))
    story.append(Spacer(1, 0.2*cm))
    story.append(Paragraph("2.5 INTEGRANTES:", ParagraphStyle('h2', fontName='Helvetica-Bold',
                             fontSize=9, parent=styles['Normal'], spaceAfter=4)))
    header = [["N°", "APELLIDOS Y NOMBRES DEL ESTUDIANTE", "FIRMA"]]
    rows = [[str(i), "", ""] for i in range(1, n_filas+1)]
    t = Table(header + rows, colWidths=[1*cm, 12*cm, 3.5*cm])
    t.setStyle(TableStyle([
        ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
        ('FONTSIZE',(0,0),(-1,-1), 8),
        ('GRID',(0,0),(-1,-1), 0.4, colors.black),
        ('BACKGROUND',(0,0),(-1,0), colors.Color(0.1,0.1,0.4)),
        ('TEXTCOLOR',(0,0),(-1,0), colors.white),
        ('ALIGN',(0,0),(-1,-1),'CENTER'),
        ('ALIGN',(1,1),(1,-1),'LEFT'),
        ('ROWBACKGROUNDS',(0,1),(-1,-1),[colors.white, colors.Color(0.97,0.97,1)]),
        ('MINROWHEIGHT',(0,1),(-1,-1), 0.65*cm),
    ]))
    story.append(t)
    story.append(Spacer(1, 0.3*cm))
    story.append(KeepTogether([
        Table([
            ["_______________________________", "  ", "_______________________________"],
            ["Docente / Tutor/a de Aula", "  ", "Vo.Bo. Dirección"],
            [docente or "________________________", "  ", ""],
        ], colWidths=[7*cm, 0.5*cm, 7*cm],
        style=TableStyle([('FONTSIZE',(0,0),(-1,-1),8.5),('ALIGN',(0,0),(-1,-1),'CENTER')])),
        Spacer(1, 0.3*cm),
        Paragraph(f"<i>Chinchero, {fecha_hoy} | YACHAY PRO</i>",
                  ParagraphStyle('fi', fontSize=7, alignment=TA_CENTER,
                                 textColor=colors.grey, parent=styles['Normal'])),
    ]))
    doc.build(story)
    buf.seek(0)
    return buf


def _generar_acta_reglamento_padres(config, grado, docente, n_filas=30):
    """Acta de conformidad de lectura del Reglamento Interno — Padres de Familia."""
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, KeepTogether
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER, TA_JUSTIFY
    import io as _io
    buf = _io.BytesIO()
    anio = config.get('anio', 2026)
    ie = config.get('nombre_ie', 'I.E.P. ALTERNATIVO YACHAY')
    dre = config.get('dre', 'Cusco')
    ugel = config.get('ugel', 'Urubamba')
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            topMargin=1.8*cm, bottomMargin=1.8*cm,
                            leftMargin=2*cm, rightMargin=2*cm)
    styles = getSampleStyleSheet()
    st_t = ParagraphStyle('T', fontSize=11, fontName='Helvetica-Bold',
                           alignment=TA_CENTER, spaceAfter=4, parent=styles['Normal'])
    st_s = ParagraphStyle('S', fontSize=9, alignment=TA_CENTER,
                           spaceAfter=8, parent=styles['Normal'])
    st_b = ParagraphStyle('B', fontSize=9, alignment=TA_JUSTIFY,
                           leading=13, spaceAfter=6, parent=styles['Normal'])
    fecha_hoy = fecha_peru_str()
    story = [
        Paragraph(f"ACTA DE CONFORMIDAD DE LECTURA DEL REGLAMENTO INTERNO {anio}", st_t),
        Paragraph(f"{ie} — PADRES DE FAMILIA", st_s),
        Spacer(1, 0.3*cm),
        Paragraph("II. DATOS INFORMATIVOS:", ParagraphStyle('h', fontName='Helvetica-Bold',
                   fontSize=9, parent=styles['Normal'], spaceAfter=4)),
    ]
    datos = [
        [f"2.1 DRE     :  {dre}", f"2.3 I.E.             :  {ie}"],
        [f"2.2 UGEL    :  {ugel}", f"2.4 Grado y Sección  :  {grado or '___________________________'}"],
    ]
    t_datos = Table(datos, colWidths=[8*cm, 8*cm])
    t_datos.setStyle(TableStyle([
        ('FONTSIZE',(0,0),(-1,-1), 8.5), ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('TOPPADDING',(0,0),(-1,-1), 3), ('BOTTOMPADDING',(0,0),(-1,-1), 3),
    ]))
    story += [t_datos, Spacer(1, 0.2*cm)]
    story.append(Paragraph(
        f"2.5 Docente / Tutor/a: {docente or '_______________________________________________'}",
        ParagraphStyle('d', fontSize=8.5, parent=styles['Normal'], spaceAfter=8)))
    story.append(Paragraph(
        f"Los padres y madres de familia del {grado or '____________'} de la {ie} "
        f"declaramos haber recibido, leído y comprendido el Reglamento Interno "
        f"vigente para el año lectivo {anio}, comprometiéndonos a su cumplimiento "
        f"y difusión en nuestro hogar.", st_b))
    story.append(Spacer(1, 0.2*cm))
    story.append(Paragraph("2.5 INTEGRANTES:", ParagraphStyle('h2', fontName='Helvetica-Bold',
                             fontSize=9, parent=styles['Normal'], spaceAfter=4)))
    header = [["N°", "APELLIDOS Y NOMBRES DEL PADRE/MADRE", "HIJO/A (ALUMNO/A)", "FIRMA"]]
    rows = [[str(i), "", "", ""] for i in range(1, n_filas+1)]
    t = Table(header + rows, colWidths=[0.8*cm, 6.5*cm, 5.5*cm, 3.7*cm])
    t.setStyle(TableStyle([
        ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
        ('FONTSIZE',(0,0),(-1,-1), 8),
        ('GRID',(0,0),(-1,-1), 0.4, colors.black),
        ('BACKGROUND',(0,0),(-1,0), colors.Color(0.1,0.1,0.4)),
        ('TEXTCOLOR',(0,0),(-1,0), colors.white),
        ('ALIGN',(0,0),(-1,-1),'CENTER'),
        ('ALIGN',(1,1),(2,-1),'LEFT'),
        ('ROWBACKGROUNDS',(0,1),(-1,-1),[colors.white, colors.Color(0.97,0.97,1)]),
        ('MINROWHEIGHT',(0,1),(-1,-1), 0.65*cm),
    ]))
    story.append(t)
    story.append(Spacer(1, 0.3*cm))
    story.append(KeepTogether([
        Table([
            ["_______________________________", "  ", "_______________________________"],
            ["Docente / Tutor/a de Aula", "  ", "Vo.Bo. Dirección"],
            [docente or "________________________", "  ", ""],
        ], colWidths=[7*cm, 0.5*cm, 7*cm],
        style=TableStyle([('FONTSIZE',(0,0),(-1,-1),8.5),('ALIGN',(0,0),(-1,-1),'CENTER')])),
        Spacer(1, 0.3*cm),
        Paragraph(f"<i>Chinchero, {fecha_hoy} | YACHAY PRO</i>",
                  ParagraphStyle('fi', fontSize=7, alignment=TA_CENTER,
                                 textColor=colors.grey, parent=styles['Normal'])),
    ]))
    doc.build(story)
    buf.seek(0)
    return buf


def _generar_municipio_escolar(config, grado, docente):
    """Municipio Escolar de Aula — cargos MINEDU."""
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, KeepTogether
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER, TA_JUSTIFY
    import io as _io
    buf = _io.BytesIO()
    anio = config.get('anio', 2026)
    ie = config.get('nombre_ie', 'I.E.P. ALTERNATIVO YACHAY')
    dre = config.get('dre', 'Cusco')
    ugel = config.get('ugel', 'Urubamba')
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            topMargin=1.8*cm, bottomMargin=1.8*cm,
                            leftMargin=2*cm, rightMargin=2*cm)
    styles = getSampleStyleSheet()
    st_t = ParagraphStyle('T', fontSize=12, fontName='Helvetica-Bold',
                           alignment=TA_CENTER, spaceAfter=4, parent=styles['Normal'])
    st_s = ParagraphStyle('S', fontSize=9, alignment=TA_CENTER,
                           spaceAfter=8, parent=styles['Normal'])
    st_b = ParagraphStyle('B', fontSize=9, alignment=TA_JUSTIFY,
                           leading=13, spaceAfter=6, parent=styles['Normal'])
    fecha_hoy = fecha_peru_str()
    story = [
        Paragraph(f"MUNICIPIO ESCOLAR DE AULA {anio}", st_t),
        Paragraph(ie, st_s),
        Spacer(1, 0.3*cm),
        Paragraph("I. DATOS INFORMATIVOS:", ParagraphStyle('h', fontName='Helvetica-Bold',
                   fontSize=9, parent=styles['Normal'], spaceAfter=4)),
    ]
    datos = [
        [f"1.1 DRE     :  {dre}", f"1.3 I.E.             :  {ie}"],
        [f"1.2 UGEL    :  {ugel}", f"1.4 Grado y Sección  :  {grado or '___________________________'}"],
    ]
    t_datos = Table(datos, colWidths=[8*cm, 8*cm])
    t_datos.setStyle(TableStyle([
        ('FONTSIZE',(0,0),(-1,-1), 8.5),('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('TOPPADDING',(0,0),(-1,-1), 3),('BOTTOMPADDING',(0,0),(-1,-1), 3),
    ]))
    story += [t_datos, Spacer(1, 0.3*cm)]
    story.append(Paragraph("1.5 INTEGRANTES DEL MUNICIPIO ESCOLAR:",
                            ParagraphStyle('h2', fontName='Helvetica-Bold', fontSize=9,
                                           parent=styles['Normal'], spaceAfter=4)))
    CARGOS = [
        ("Alcalde", True),
        ("Teniente Alcalde", False),
        ("Regidor/a de Educación, Cultura, Recreación y Deporte", False),
        ("Regiduría de Salud y Ambiente", False),
        ("Regiduría de Emprendimiento y Actividades Productivas", False),
        ("Regiduría de Derechos del Niño, Niña y Adolescente", False),
        ("Regiduría de Comunicación y Tecnologías de la Información", False),
    ]
    header = [["NOMBRES Y APELLIDOS", "CARGO"]]
    rows = [["", c[0]] for c in CARGOS]
    t = Table(header + rows, colWidths=[10*cm, 6.5*cm])
    style_cmds = [
        ('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),
        ('FONTSIZE',(0,0),(-1,-1), 9),
        ('GRID',(0,0),(-1,-1), 0.5, colors.black),
        ('BACKGROUND',(0,0),(-1,0), colors.Color(0.1,0.1,0.4)),
        ('TEXTCOLOR',(0,0),(-1,0), colors.white),
        ('ALIGN',(0,0),(-1,-1),'CENTER'),
        ('ALIGN',(1,1),(1,-1),'CENTER'),
        ('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('ROWBACKGROUNDS',(0,1),(-1,-1),[colors.white, colors.Color(0.96,0.96,1)]),
        ('MINROWHEIGHT',(0,1),(-1,-1), 1.2*cm),
    ]
    # Alcalde con fondo especial
    style_cmds.append(('BACKGROUND',(0,1),(-1,1), colors.Color(0.95,0.95,0.75)))
    t.setStyle(TableStyle(style_cmds))
    story.append(t)
    story.append(Spacer(1, 0.4*cm))
    story.append(KeepTogether([
        Paragraph("FIRMA DEL TUTOR/A:",
                  ParagraphStyle('ft', fontName='Helvetica-Bold', fontSize=9,
                                 parent=styles['Normal'], spaceAfter=12)),
        Table([
            ["_______________________________"],
            ["FIRMA DEL TUTOR/A:"],
            [docente or "Docente / Tutor/a de Aula"],
            [ie],
        ], colWidths=[16.5*cm],
        style=TableStyle([('FONTSIZE',(0,0),(-1,-1),9),('ALIGN',(0,0),(-1,-1),'CENTER')])),
        Spacer(1, 0.3*cm),
        Paragraph(f"<i>Chinchero, {fecha_hoy} | YACHAY PRO</i>",
                  ParagraphStyle('fi', fontSize=7, alignment=TA_CENTER,
                                 textColor=colors.grey, parent=styles['Normal'])),
    ]))
    doc.build(story)
    buf.seek(0)
    return buf


def _generar_acuerdos_convivencia(config, grado, docente):
    """Acta de elaboración de los Acuerdos de Convivencia del Aula."""
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, KeepTogether
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER, TA_JUSTIFY
    import io as _io
    buf = _io.BytesIO()
    anio = config.get('anio', 2026)
    ie = config.get('nombre_ie', 'I.E.P. ALTERNATIVO YACHAY')
    dre = config.get('dre', 'Cusco')
    ugel = config.get('ugel', 'Urubamba')
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            topMargin=1.8*cm, bottomMargin=1.8*cm,
                            leftMargin=2*cm, rightMargin=2*cm)
    styles = getSampleStyleSheet()
    st_t = ParagraphStyle('T', fontSize=11, fontName='Helvetica-Bold',
                           alignment=TA_CENTER, spaceAfter=4, parent=styles['Normal'])
    st_s = ParagraphStyle('S', fontSize=9, alignment=TA_CENTER,
                           spaceAfter=8, parent=styles['Normal'])
    st_b = ParagraphStyle('B', fontSize=9, alignment=TA_JUSTIFY,
                           leading=13, spaceAfter=6, parent=styles['Normal'])
    fecha_hoy = fecha_peru_str()
    story = [
        Paragraph(f"ACTA DE ELABORACIÓN DE LOS ACUERDOS DE CONVIVENCIA DEL AULA {anio}", st_t),
        Paragraph(ie, st_s),
        Spacer(1, 0.3*cm),
        Paragraph("III. DATOS INFORMATIVOS:", ParagraphStyle('h', fontName='Helvetica-Bold',
                   fontSize=9, parent=styles['Normal'], spaceAfter=4)),
    ]
    datos = [
        [f"3.1 DRE     :  {dre}", f"3.3 I.E.             :  {ie}"],
        [f"3.2 UGEL    :  {ugel}", f"3.4 Grado y Sección  :  {grado or '___________________________'}"],
    ]
    t_datos = Table(datos, colWidths=[8*cm, 8*cm])
    t_datos.setStyle(TableStyle([
        ('FONTSIZE',(0,0),(-1,-1), 8.5),('VALIGN',(0,0),(-1,-1),'MIDDLE'),
        ('TOPPADDING',(0,0),(-1,-1), 3),('BOTTOMPADDING',(0,0),(-1,-1), 3),
    ]))
    story += [t_datos, Spacer(1, 0.3*cm)]
    # Tabla de acuerdos — 7 filas vacías para llenar a mano
    story.append(Paragraph("ACUERDOS DE CONVIVENCIA:",
                            ParagraphStyle('h2', fontName='Helvetica-Bold', fontSize=9,
                                           parent=styles['Normal'], spaceAfter=4)))
