def _calcular_afinidad_academica(promedios_area):
    """
    Calcula afinidad a grupos UNSAAC basándose en promedios por área escolar.
    Usa las areas_clave reales de cada grupo UNSAAC (Grupo A/B = Ciencias, C/D = Letras).
    """
    puntajes = {"A": 0, "B": 0, "C": 0, "D": 0, "T": 0}
    conteo_areas = {"A": 0, "B": 0, "C": 0, "D": 0, "T": 0}
    areas_destacadas = []
    areas_debiles = []

    # Construir mapa area → grupo con coincidencia parcial
    area_grupo = {}
    for grupo_id, gdata in UNSAAC_GRUPOS.items():
        for area in gdata["areas_clave"]:
            area_grupo[area.lower().strip()] = grupo_id

    for area, prom in promedios_area.items():
        area_lower = area.lower().strip()
        grupo_id = None
        # Buscar coincidencia exacta primero, luego parcial
        if area_lower in area_grupo:
            grupo_id = area_grupo[area_lower]
        else:
            for ak, gk in area_grupo.items():
                if ak in area_lower or area_lower in ak or any(
                    w in area_lower for w in ak.split() if len(w) > 4):
                    grupo_id = gk
                    break

        if grupo_id:
            peso = (prom / 20) * 10
            puntajes[grupo_id] += peso
            conteo_areas[grupo_id] += 1
            if prom >= 14:
                areas_destacadas.append((area, prom, grupo_id))
            elif prom < 11:
                areas_debiles.append((area, prom))
        else:
            # Área sin grupo asignado: distribuir proporcionalmente
            for gk in ["A","B","C","D"]:
                puntajes[gk] += (prom / 20) * 2.5

    # Si no hubo áreas mapeadas, dar puntaje base igual a todos
    total = sum(puntajes.values()) or 1
    pct = {k: round((v/total)*100, 1) for k, v in puntajes.items()}

    orden = sorted(puntajes, key=lambda k: puntajes[k], reverse=True)
    grupo_principal  = orden[0]
    grupo_secundario = orden[1]

    return {
        "puntajes": puntajes,
        "porcentajes": pct,
        "grupo_principal": grupo_principal,
        "grupo_secundario": grupo_secundario,
        "areas_destacadas": sorted(areas_destacadas, key=lambda x: x[1], reverse=True),
        "areas_debiles": areas_debiles,
        "cepre_recomendado": UNSAAC_GRUPOS.get(grupo_principal,{}).get("cepre_grupo","AB"),
    }

def _calcular_resultado_test(respuestas):
    """Calcula resultado de un test vocacional. respuestas = dict {id: grupo}"""
    conteo = {"A": 0, "B": 0, "C": 0, "D": 0, "T": 0}
    for _, grupo in respuestas.items():
        if grupo in conteo:
            conteo[grupo] += 1
    total = len(respuestas) or 1
    pct = {k: round((v/total)*100, 1) for k, v in conteo.items()}
    principal = max(conteo, key=lambda k: conteo[k])
    return {"conteo": conteo, "porcentajes": pct, "principal": principal}

def _texto_diagnostico_psicopedagogico(nombre, prom_gen, lit_gen, promedios_area, afinidad):
    """Genera texto de diagnóstico psicopedagógico detallado."""
    gp = afinidad["grupo_principal"]
    gs_sec = afinidad["grupo_secundario"]
    gdata = UNSAAC_GRUPOS.get(gp, {})

    lineas = []
    lineas.append(f"DIAGNÓSTICO PSICOPEDAGÓGICO — {nombre.upper()}")
    lineas.append(f"Promedio General: {prom_gen}/20 — Nivel {lit_gen} ({ESCALA_MINEDU.get(lit_gen,{}).get('nombre','')})")
    lineas.append("")
    lineas.append("I. PERFIL ACADÉMICO:")

    if lit_gen == "AD":
        lineas.append("   El/la estudiante evidencia un desempeño académico sobresaliente, superando")
        lineas.append("   consistentemente las expectativas del grado. Demuestra autonomía intelectual,")
        lineas.append("   pensamiento crítico y hábitos de estudio consolidados.")
    elif lit_gen == "A":
        lineas.append("   El/la estudiante alcanza los aprendizajes esperados para su grado con")
        lineas.append("   regularidad. Muestra capacidad de comprensión y aplicación de conceptos.")
        lineas.append("   Con mayor exigencia puede acceder al nivel destacado.")
    elif lit_gen == "B":
        lineas.append("   El/la estudiante se encuentra en proceso de alcanzar los aprendizajes esperados.")
        lineas.append("   Requiere acompañamiento pedagógico continuo y estrategias de refuerzo")
        lineas.append("   diferenciado en las áreas con menor rendimiento.")
    else:
        lineas.append("   El/la estudiante muestra dificultades significativas para alcanzar los")
        lineas.append("   aprendizajes del grado. Se recomienda evaluación psicopedagógica especializada,")
        lineas.append("   plan de intervención individual y coordinación urgente con la familia.")

    lineas.append("")
    lineas.append("II. FORTALEZAS IDENTIFICADAS:")
    for area, prom, grp in afinidad["areas_destacadas"][:4]:
        lineas.append(f"   ✓ {area}: {prom}/20 — {ESCALA_MINEDU.get(nota_a_letra(prom),{}).get('nombre','')}")
    if not afinidad["areas_destacadas"]:
        lineas.append("   No se identifican áreas con logro destacado en el período.")

    lineas.append("")
    lineas.append("III. ÁREAS A REFORZAR:")
    for area, prom in afinidad["areas_debiles"][:4]:
        lineas.append(f"   △ {area}: {prom}/20 — Requiere intervención pedagógica")
    if not afinidad["areas_debiles"]:
        lineas.append("   No se identifican áreas críticas en el período evaluado.")

    lineas.append("")
    lineas.append("IV. AFINIDAD VOCACIONAL — UNSAAC:")
    lineas.append(f"   Grupo principal: {gdata.get('nombre','—')} {gdata.get('icono','')}")
    cepre_grp = gdata.get("cepre_grupo","AB")
    lineas.append(f"   CEPRE-UNSAAC recomendado: Grupo {cepre_grp} ({'Ciencias' if cepre_grp=='AB' else 'Letras/Sociales'})")
    lineas.append(f"   {gdata.get('perfil','')[:120]}")
    lineas.append(f"   Grupo complementario: {UNSAAC_GRUPOS.get(gs_sec,{}).get('nombre','—')}")
    lineas.append("   Áreas del CEPRE que debe reforzar:")
    for area_c in gdata.get("areas_cepre",[])[:5]:
        lineas.append(f"     • {area_c}")

    lineas.append("")
    lineas.append("V. RECOMENDACIONES PSICOPEDAGÓGICAS:")
    if lit_gen in ("AD", "A"):
        lineas.append("   • Participar en el CEPRE-UNSAAC Grupo " + ("AB" if gp in ("A","B") else "CD"))
        lineas.append(f"   • Explorar carreras del {gdata.get('nombre','—')}")
        lineas.append("   • Mantener hábitos de lectura y resolución de problemas")
        lineas.append("   • Participar en olimpiadas académicas según área de fortaleza")
    elif lit_gen == "B":
        lineas.append("   • Refuerzo en áreas identificadas como débiles (2h/semana mínimo)")
        lineas.append("   • Tutoría personalizada docente-estudiante mensual")
        lineas.append("   • Explorar opciones de institutos técnicos afines a sus fortalezas")
        lineas.append("   • Talleres de hábitos de estudio y técnicas de aprendizaje")
    else:
        lineas.append("   • Plan de recuperación pedagógica urgente e individual")
        lineas.append("   • Evaluación de factores externos (familia, salud, socioemocional)")
        lineas.append("   • Sesiones de tutoría semanal con registro de avances")
        lineas.append("   • Coordinación con APAFA para compromisos de apoyo en casa")
        lineas.append("   • Considerar orientación vocacional hacia carreras técnicas")

    return lineas


def generar_pdf_orientacion_vocacional(nombre, dni, grado, prom_gen, lit_gen,
                                        promedios_area, afinidad, config,
                                        resultado_test=None):
    """
    Genera PDF completo de orientación vocacional y diagnóstico psicopedagógico.
    Incluye: análisis académico, afinidad UNSAAC, carreras recomendadas,
    resultado del test vocacional (si existe) y plan de acción.
    """
    from reportlab.platypus import Paragraph, Table, TableStyle, Spacer
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_JUSTIFY
    from reportlab.lib.units import mm

    buf = io.BytesIO()
    c = canvas.Canvas(buf, pagesize=A4)
    w, h = A4

    def _encabezado(pagina=1):
        # Fondo header
        c.setFillColor(colors.HexColor("#0f172a"))
        c.rect(0, h-75, w, 75, fill=True)
        # Franja dorada
        c.setFillColor(colors.HexColor("#f59e0b"))
        c.rect(0, h-78, w, 3, fill=True)
        c.setFillColor(colors.white)
        c.setFont("Helvetica-Bold", 14)
        c.drawCentredString(w/2, h-25, "ORIENTACIÓN VOCACIONAL Y DIAGNÓSTICO PSICOPEDAGÓGICO")
        c.setFont("Helvetica", 9)
        c.drawCentredString(w/2, h-40, f"I.E.P. ALTERNATIVO YACHAY — Chinchero, Cusco — {config.get('anio',2026)}")
        c.setFont("Helvetica-Bold", 9)
        c.drawCentredString(w/2, h-55, f"Estudiante: {nombre}  |  DNI: {dni}  |  Grado: {grado}")
        c.setFont("Helvetica", 7)
        c.drawCentredString(w/2, h-67, f"Generado: {fecha_peru_str()}  |  Pág. {pagina}")

    def _pie():
        c.setFont("Helvetica-Oblique", 6)
        c.setFillColor(colors.HexColor("#64748b"))
        c.drawCentredString(w/2, 18, "YACHAY PRO © — Documento orientativo. No reemplaza evaluación profesional especializada.")
        c.drawCentredString(w/2, 10, "UNSAAC — Universidad Nacional de San Antonio Abad del Cusco | Cusco, Perú")
        c.setFillColor(colors.black)

    pag = 1
    _encabezado(pag)
    _pie()
    y = h - 95

    # ── SECCIÓN 1: Perfil Académico ──────────────────────────────────
    col_h = colors.HexColor("#1e3a8a")
    c.setFillColor(col_h)
    c.rect(40, y-4, w-80, 18, fill=True)
    c.setFillColor(colors.white)
    c.setFont("Helvetica-Bold", 10)
    c.drawString(48, y+1, "I. PERFIL ACADÉMICO")
    y -= 22
    c.setFillColor(colors.black)

    # Promedio general con semáforo
    col_gen = color_semaforo(lit_gen)
    c.setFillColor(colors.HexColor(col_gen))
    c.roundRect(40, y-8, 120, 22, 6, fill=True)
    c.setFillColor(colors.white)
    c.setFont("Helvetica-Bold", 16)
    c.drawCentredString(100, y+1, f"{prom_gen}/20  {lit_gen}")
    c.setFillColor(colors.black)
    c.setFont("Helvetica", 8)
    c.drawString(175, y+6, ESCALA_MINEDU.get(lit_gen,{}).get("nombre",""))
    c.drawString(175, y-4, ESCALA_MINEDU.get(lit_gen,{}).get("desc","")[:70])
    y -= 28

    # Tabla de promedios por área (máx 12 áreas)
    if promedios_area:
        areas_mostrar = sorted(promedios_area.items(), key=lambda x: x[1], reverse=True)[:12]
        c.setFont("Helvetica-Bold", 8)
        # Header
        c.setFillColor(colors.HexColor("#334155"))
        c.rect(40, y-2, w-80, 14, fill=True)
        c.setFillColor(colors.white)
        c.drawString(44, y+1, "Área Curricular")
        c.drawString(300, y+1, "Promedio")
        c.drawString(360, y+1, "Nivel")
        c.drawString(400, y+1, "Barra de Progreso")
        y -= 16
        c.setFont("Helvetica", 7)
        for idx, (area, prom) in enumerate(areas_mostrar):
            lit = nota_a_letra(prom)
            col = color_semaforo(lit)
            bg = "#f8fafc" if idx % 2 == 0 else "#ffffff"
            c.setFillColor(colors.HexColor(bg))
            c.rect(40, y-3, w-80, 13, fill=True)
            c.setFillColor(colors.black)
            c.drawString(44, y+1, area[:40])
            c.drawString(300, y+1, f"{prom:.1f}")
            c.setFillColor(colors.HexColor(col))
            c.circle(358, y+3, 5, fill=True)
            c.setFillColor(colors.white)
            c.setFont("Helvetica-Bold", 6)
            c.drawCentredString(358, y+1, lit)
            # Barra
            c.setFillColor(colors.HexColor("#e2e8f0"))
            c.rect(400, y, 120, 9, fill=True)
            c.setFillColor(colors.HexColor(col))
            c.rect(400, y, max(2, (prom/20)*120), 9, fill=True)
            c.setFillColor(colors.black)
            c.setFont("Helvetica", 7)
            y -= 13
            if y < 120:
                c.showPage()
                pag += 1
                _encabezado(pag)
                _pie()
                y = h - 95

    # ── SECCIÓN 2: Afinidad UNSAAC ───────────────────────────────────
    y -= 8
    if y < 180:
        c.showPage(); pag += 1; _encabezado(pag); _pie(); y = h - 95

    c.setFillColor(col_h)
    c.rect(40, y-4, w-80, 18, fill=True)
    c.setFillColor(colors.white)
    c.setFont("Helvetica-Bold", 10)
    c.drawString(48, y+1, "II. AFINIDAD VOCACIONAL — UNSAAC (Universidad Nacional San Antonio Abad del Cusco)")
    y -= 24
    c.setFillColor(colors.black)

    # Gráfico de barras de afinidad
    c.setFont("Helvetica-Bold", 8)
    c.drawString(44, y, "Afinidad por área de conocimiento:")
    y -= 14
    pcts = afinidad.get("porcentajes", {})
    grupos_order = [("A","⚙️ Ing. y Ciencias"), ("B","🏥 Salud"), ("C","📚 Cs. Sociales"), ("D","🎓 Educación"), ("T","🔧 Técnico")]
    colores_grupos = {"A":"#1e3a8a","B":"#065f46","C":"#7c2d12","D":"#4c1d95","T":"#92400e"}
    for gk, glabel in grupos_order:
        pct_val = pcts.get(gk, 0)
        col_g = colores_grupos.get(gk, "#334155")
        c.setFillColor(colors.HexColor("#e2e8f0"))
        c.rect(44, y, 220, 10, fill=True)
        c.setFillColor(colors.HexColor(col_g))
        c.rect(44, y, max(2, (pct_val/100)*220), 10, fill=True)
        c.setFillColor(colors.black)
        c.setFont("Helvetica", 7)
        c.drawString(270, y+2, f"{glabel}: {pct_val:.0f}%")
        # Estrella si es el principal
        if gk == afinidad.get("grupo_principal"):
            c.setFillColor(colors.HexColor("#f59e0b"))
            c.drawString(44 + max(2, (pct_val/100)*220) + 3, y+2, "◀ PRINCIPAL")
            c.setFillColor(colors.black)
        y -= 13

    y -= 6
    # Detalle del grupo principal
    gp = afinidad.get("grupo_principal", "A")
    gdata_p = UNSAAC_GRUPOS.get(gp, {})
    gs_id = afinidad.get("grupo_secundario", "C")
    gdata_s = UNSAAC_GRUPOS.get(gs_id, {})

    if y < 200:
        c.showPage(); pag += 1; _encabezado(pag); _pie(); y = h - 95

    # ── Caja grupo PRINCIPAL — ancho completo con TODAS las carreras ──
    carreras_p  = gdata_p.get("carreras", [])
    facultades_p = gdata_p.get("facultades", [])
    cepre_p     = gdata_p.get("cepre_grupo", "AB")
    alto_p      = 28 + len(carreras_p) * 9 + len(facultades_p) * 8 + 16
    c.setFillColor(colors.HexColor(gdata_p.get("color_claro","#dbeafe")))
    c.roundRect(40, y - alto_p, w - 80, alto_p + 8, 8, fill=True)
    c.setFillColor(colors.HexColor(gdata_p.get("color","#1e3a8a")))
    c.roundRect(40, y - alto_p, w - 80, alto_p + 8, 8, fill=False)
    c.setFont("Helvetica-Bold", 10)
    c.drawString(50, y - 4, f"★ GRUPO PRINCIPAL — {gdata_p.get('icono','')} {gdata_p.get('nombre','')}")
    c.setFont("Helvetica-Bold", 7)
    c.setFillColor(colors.HexColor(gdata_p.get("color","#1e3a8a")))
    c.drawString(50, y - 15, f"CEPRE-UNSAAC Grupo {cepre_p} | Perfil: {gdata_p.get('perfil','')[:80]}")
    c.setFillColor(colors.black)
    # Facultades
    c.setFont("Helvetica-Bold", 7)
    ty = y - 27
    c.drawString(52, ty, "Facultades UNSAAC:")
    ty -= 9
    c.setFont("Helvetica-Oblique", 6.5)
    for fac in facultades_p:
        c.drawString(58, ty, f"› {fac}")
        ty -= 8
    # Carreras en 2 columnas
    c.setFont("Helvetica-Bold", 7)
    ty -= 4
    c.drawString(52, ty, f"Carreras profesionales ({len(carreras_p)} en total):")
    ty -= 10
    c.setFont("Helvetica", 7)
    mitad = (len(carreras_p) + 1) // 2
    col1_c = carreras_p[:mitad]
    col2_c = carreras_p[mitad:]
    for idx_c in range(max(len(col1_c), len(col2_c))):
        if idx_c < len(col1_c):
            c.drawString(52, ty, f"• {col1_c[idx_c]}")
        if idx_c < len(col2_c):
            c.drawString(310, ty, f"• {col2_c[idx_c]}")
        ty -= 9
    y = ty - 10

    # ── Caja grupo SECUNDARIO ──
    if y < 160:
        c.showPage(); pag += 1; _encabezado(pag); _pie(); y = h - 95
    carreras_s  = gdata_s.get("carreras", [])
    facultades_s = gdata_s.get("facultades", [])
    cepre_s     = gdata_s.get("cepre_grupo", "CD")
    alto_s      = 28 + len(carreras_s) * 9 + len(facultades_s) * 8 + 16
    c.setFillColor(colors.HexColor(gdata_s.get("color_claro","#d1fae5")))
    c.roundRect(40, y - alto_s, w - 80, alto_s + 8, 8, fill=True)
    c.setFillColor(colors.HexColor(gdata_s.get("color","#065f46")))
    c.roundRect(40, y - alto_s, w - 80, alto_s + 8, 8, fill=False)
    c.setFont("Helvetica-Bold", 10)
    c.drawString(50, y - 4, f"◆ GRUPO COMPLEMENTARIO — {gdata_s.get('icono','')} {gdata_s.get('nombre','')}")
    c.setFont("Helvetica-Bold", 7)
    c.setFillColor(colors.HexColor(gdata_s.get("color","#065f46")))
    c.drawString(50, y - 15, f"CEPRE-UNSAAC Grupo {cepre_s}")
    c.setFillColor(colors.black)
    ty2 = y - 27
    c.setFont("Helvetica-Oblique", 6.5)
    for fac in facultades_s[:3]:
        c.drawString(58, ty2, f"› {fac}")
        ty2 -= 8
    c.setFont("Helvetica", 7)
    ty2 -= 2
    mitad2 = (len(carreras_s) + 1) // 2
    col1_s = carreras_s[:mitad2]
    col2_s = carreras_s[mitad2:]
    for idx_s in range(max(len(col1_s), len(col2_s))):
        if idx_s < len(col1_s):
            c.drawString(52, ty2, f"• {col1_s[idx_s]}")
        if idx_s < len(col2_s):
            c.drawString(310, ty2, f"• {col2_s[idx_s]}")
        ty2 -= 9
    y = ty2 - 10

    # ── Otras opciones vocacionales ──
    y -= 8
    c.setFont("Helvetica-Bold", 8)
    c.drawString(44, y, "Otras trayectorias vocacionales:")
    y -= 12
    c.setFont("Helvetica", 7)
    for opc_nombre, odata in OTRAS_OPCIONES_CARRERA.items():
        c.setFillColor(colors.HexColor(odata["color_claro"]))
        c.roundRect(44, y-16, w-88, 22, 4, fill=True)
        c.setFillColor(colors.HexColor(odata["color"]))
        c.setFont("Helvetica-Bold", 7)
        c.drawString(52, y, f"{odata['icono']} {opc_nombre}:")
        c.setFillColor(colors.black)
        c.setFont("Helvetica", 7)
        c.drawString(52, y-10, odata["descripcion"])
        y -= 26
        if y < 100:
            c.showPage(); pag += 1; _encabezado(pag); _pie(); y = h - 95

    # ── SECCIÓN 3: Resultado del test (con explicaciones completas) ──
    if resultado_test:
        y -= 8
        if y < 200:
            c.showPage(); pag += 1; _encabezado(pag); _pie(); y = h - 95

        test_id_r    = resultado_test.get("test_id", "intereses")
        test_nom_r   = resultado_test.get("test_nombre", "Test Vocacional")
        conteo_r     = resultado_test.get("conteo", {})
        grupo_dom    = resultado_test.get("grupo_dominante", "") or (max(conteo_r, key=conteo_r.get) if conteo_r else "A")
        test_data_r  = TESTS_VOCACIONALES.get(test_id_r, {})
        explicaciones_r = test_data_r.get("explicaciones", {})
        grupos_res_r    = test_data_r.get("grupos_resultado", {})
        total_r      = sum(conteo_r.values()) or 1

        # Encabezado sección
        c.setFillColor(col_h)
        c.rect(40, y-4, w-80, 18, fill=True)
        c.setFillColor(colors.white)
        c.setFont("Helvetica-Bold", 10)
        titulo_sec = test_nom_r.encode('ascii','replace').decode()
        c.drawString(48, y+1, f"III. RESULTADO: {titulo_sec[:60]}")
        y -= 26

        # ── Barras de resultado por grupo ──────────────────────────────
        PALETA = ["#2563eb","#16a34a","#7c3aed","#dc2626","#d97706","#0891b2","#059669","#be185d"]
        grupos_ordenados = sorted(conteo_r.items(), key=lambda x: -x[1])
        for gi, (gk, cnt) in enumerate(grupos_ordenados):
            if y < 80: c.showPage(); pag+=1; _encabezado(pag); _pie(); y=h-95
            pct_v = round(cnt/total_r*100)
            bar_w = max(4, int((cnt/total_r)*200))
            gc = PALETA[gi % len(PALETA)]
            expl = explicaciones_r.get(gk, {})
            label = expl.get("titulo", grupos_res_r.get(gk, gk))
            label_clean = label.encode('ascii','replace').decode()
            # Barra
            c.setFillColor(colors.HexColor("#e2e8f0"))
            c.rect(44, y, 200, 10, fill=True, stroke=0)
            c.setFillColor(colors.HexColor(gc))
            c.rect(44, y, bar_w, 10, fill=True, stroke=0)
            c.setFillColor(colors.black)
            c.setFont("Helvetica-Bold" if gk==grupo_dom else "Helvetica", 7.5)
            c.drawString(252, y+2, f"{label_clean[:45]}: {cnt} resp. ({pct_v}%)")
            if gk == grupo_dom:
                c.setFillColor(colors.HexColor(gc))
                c.setFont("Helvetica-Bold", 6)
                c.drawString(44, y+12, "◀ DOMINANTE")
                c.setFillColor(colors.black)
            y -= 14

        # ── Explicación detallada del resultado dominante ──────────────
        y -= 6
        if y < 180: c.showPage(); pag+=1; _encabezado(pag); _pie(); y=h-95

        expl_dom = explicaciones_r.get(grupo_dom, {})
        if expl_dom:
            col_dom = expl_dom.get("color","#2563eb")
            titulo_dom = expl_dom.get("titulo","Resultado")
            desc_dom   = expl_dom.get("desc","")
            fortalezas = expl_dom.get("fortalezas",[])
            carreras   = expl_dom.get("carreras",[])
            consejo    = expl_dom.get("consejo","")

            # Caja de resultado principal
            c.setFillColor(colors.HexColor(col_dom))
            c.roundRect(40, y-38, w-80, 42, 6, fill=True, stroke=0)
            c.setFillColor(colors.white)
            c.setFont("Helvetica-Bold", 11)
            titulo_clean = titulo_dom.encode('ascii','replace').decode()
            c.drawCentredString(w/2, y-10, titulo_clean)
            c.setFont("Helvetica", 7.5)
            # Descripción en 2 líneas
            desc_clean = desc_dom.encode('ascii','replace').decode()
            words = desc_clean.split()
            lines_desc = []
            line = ""
            for wd in words:
                if len(line)+len(wd)+1 <= 100:
                    line = (line+" "+wd).strip()
                else:
                    lines_desc.append(line); line=wd
            if line: lines_desc.append(line)
            for li, ld in enumerate(lines_desc[:2]):
                c.drawCentredString(w/2, y-22-(li*10), ld)
            y -= 50

            # Fortalezas y Carreras lado a lado
            if y < 120: c.showPage(); pag+=1; _encabezado(pag); _pie(); y=h-95
            mid = w/2
            c.setFillColor(colors.HexColor("#f0f9ff"))
            c.roundRect(40, y-14-len(fortalezas)*11, (mid-50), 18+len(fortalezas)*11, 4, fill=True, stroke=0)
            c.setFillColor(colors.HexColor("#fff7ed"))
            c.roundRect(mid+10, y-14-len(carreras)*11, (mid-50), 18+len(carreras)*11, 4, fill=True, stroke=0)

            c.setFillColor(colors.HexColor(col_dom))
            c.setFont("Helvetica-Bold", 8)
            c.drawString(46, y-4, "FORTALEZAS:")
            c.drawString(mid+16, y-4, "CARRERAS SUGERIDAS:")
            c.setFillColor(colors.black)
            c.setFont("Helvetica", 7.5)
            for fi, ft in enumerate(fortalezas[:5]):
                ft_c = ft.encode('ascii','replace').decode()
                c.drawString(48, y-16-(fi*11), f"• {ft_c[:45]}")
            for ci2, ca in enumerate(carreras[:5]):
                ca_c = ca.encode('ascii','replace').decode()
                c.drawString(mid+18, y-16-(ci2*11), f"• {ca_c[:38]}")
            y -= 20 + max(len(fortalezas),len(carreras))*11

            # Consejo
            if consejo and y > 80:
                if y < 100: c.showPage(); pag+=1; _encabezado(pag); _pie(); y=h-95
                c.setFillColor(colors.HexColor("#fefce8"))
                cons_clean = consejo.encode('ascii','replace').decode()
                # wrap consejo
                cwords = cons_clean.split()
                clines = []
                cl = ""
                for cw in cwords:
                    if len(cl)+len(cw)+1 <= 95: cl=(cl+" "+cw).strip()
                    else: clines.append(cl); cl=cw
                if cl: clines.append(cl)
                box_h = 18 + len(clines)*11
                c.roundRect(40, y-box_h, w-80, box_h, 4, fill=True, stroke=0)
                c.setFillColor(colors.HexColor("#92400e"))
                c.setFont("Helvetica-Bold", 8)
                c.drawString(46, y-12, "CONSEJO PERSONALIZADO:")
                c.setFillColor(colors.black)
                c.setFont("Helvetica", 7.5)
                for cli, cl2 in enumerate(clines):
                    c.drawString(48, y-24-(cli*11), cl2)
                y -= box_h + 8
        y -= 6

    # ── SECCIÓN 4: Diagnóstico psicopedagógico ───────────────────────
    if y < 200:
        c.showPage(); pag += 1; _encabezado(pag); _pie(); y = h - 95

    seccion_num = "IV" if resultado_test else "III"
    c.setFillColor(col_h)
    c.rect(40, y-4, w-80, 18, fill=True)
    c.setFillColor(colors.white)
    c.setFont("Helvetica-Bold", 10)
    c.drawString(48, y+1, f"{seccion_num}. DIAGNÓSTICO PSICOPEDAGÓGICO Y PLAN DE ACCIÓN")
    y -= 22
    c.setFillColor(colors.black)

    lineas_diag = _texto_diagnostico_psicopedagogico(nombre, prom_gen, lit_gen, promedios_area, afinidad)
    c.setFont("Helvetica", 7)
    for linea in lineas_diag:
        if linea.startswith("I.") or linea.startswith("II.") or linea.startswith("III.") or linea.startswith("IV.") or linea.startswith("V."):
            c.setFont("Helvetica-Bold", 8)
        else:
            c.setFont("Helvetica", 7)
        c.drawString(44, y, linea[:105])
        y -= 10
        if y < 80:
            c.showPage(); pag += 1; _encabezado(pag); _pie(); y = h - 95

    # ── Firma / sello ────────────────────────────────────────────────
    y -= 20
    if y < 120:
        c.showPage(); pag += 1; _encabezado(pag); _pie(); y = h - 95
    c.setStrokeColor(colors.HexColor("#94a3b8"))
    c.setLineWidth(0.5)
    c.line(44, y, 250, y)
    c.line(310, y, 520, y)
    c.setFont("Helvetica", 7)
    c.drawCentredString(147, y-10, "Firma del Tutor/a")
    c.drawCentredString(415, y-10, "V°B° Dirección")
    c.setFont("Helvetica-Oblique", 6)
    c.setFillColor(colors.HexColor("#64748b"))
    c.drawCentredString(w/2, y-24, "Este informe es de carácter orientativo y complementa el proceso de tutoría escolar.")

    c.save()
    buf.seek(0)
    return buf



def generar_pdf_test_imprimible(test_id, config):
    """
    Genera un PDF listo para imprimir del cuestionario vocacional.
    Incluye: encabezado, instrucciones, preguntas con opciones A-E,
    hoja de respuestas (burbuja) y espacio para datos del alumno.
    """
    test_data = TESTS_VOCACIONALES.get(test_id, {})
    if not test_data:
        return None
    preguntas = test_data.get("preguntas", [])
    n_pregs   = len(preguntas)

    buf = io.BytesIO()
    c = canvas.Canvas(buf, pagesize=A4)
    w, h = A4

    # Paleta de colores por pregunta (cíclica)
    PALETA_PREGS = [
        ("#eff6ff","#2563eb"),  # azul suave
        ("#f0fdf4","#16a34a"),  # verde suave
        ("#fef3c7","#d97706"),  # amarillo suave
        ("#fdf4ff","#9333ea"),  # morado suave
        ("#fff1f2","#e11d48"),  # rosa suave
        ("#ecfdf5","#059669"),  # esmeralda
    ]
    COLORES_OPCION = {
        "A": ("#dcfce7","#16a34a"),  # verde
        "B": ("#dbeafe","#2563eb"),  # azul
        "C": ("#fef9c3","#ca8a04"),  # amarillo
        "D": ("#fce7f3","#db2777"),  # rosa
        "E": ("#f3e8ff","#9333ea"),  # morado
    }

    def _header_test(pag=1):
        # Degradado de fondo
        c.setFillColor(colors.HexColor("#0f172a"))
        c.rect(0, h-72, w, 72, fill=True)
        # Barra arcoiris decorativa
        barra_cols = ["#ef4444","#f59e0b","#22c55e","#3b82f6","#8b5cf6","#ec4899"]
        seg_w = w / len(barra_cols)
        for bi, bc in enumerate(barra_cols):
            c.setFillColor(colors.HexColor(bc))
            c.rect(bi*seg_w, h-75, seg_w+1, 3, fill=True, stroke=False)
        c.setFillColor(colors.white)
        c.setFont("Helvetica-Bold", 14)
        nombre_test = test_data.get("nombre","TEST VOCACIONAL")
        c.drawCentredString(w/2, h-22, nombre_test.upper())
        c.setFont("Helvetica", 8.5)
        c.drawCentredString(w/2, h-38, f"I.E.P. ALTERNATIVO YACHAY — Chinchero, Cusco — {config.get('anio',2026)}")
        desc = test_data.get("descripcion","")
        c.setFont("Helvetica-Oblique", 7.5)
        c.setFillColor(colors.HexColor("#a5b4fc"))
        c.drawCentredString(w/2, h-52, desc[:90])
        c.setFillColor(colors.HexColor("#94a3b8"))
        c.setFont("Helvetica", 7)
        c.drawCentredString(w/2, h-64, f"Pág. {pag}")

    def _footer_test():
        c.setFont("Helvetica-Oblique", 6)
        c.setFillColor(colors.HexColor("#94a3b8"))
        c.drawCentredString(w/2, 15, "YACHAY PRO © — Orientación Vocacional UNSAAC — Uso exclusivo institucional")
        c.setFillColor(colors.black)

    pag = 1
    _header_test(pag)
    _footer_test()
    y = h - 82

    # ── DATOS DEL ESTUDIANTE ──────────────────────────────────────────
    c.setFillColor(colors.HexColor("#f1f5f9"))
    c.roundRect(30, y-48, w-60, 52, 6, fill=True)
    c.setFillColor(colors.HexColor("#1e3a8a"))
    c.roundRect(30, y-48, w-60, 52, 6, fill=False)
    c.setFont("Helvetica-Bold", 8)
    c.setFillColor(colors.black)
    c.drawString(40, y-6,  "Apellidos y Nombres: _____________________________________________")
    c.drawString(40, y-18, "DNI: __________________    Grado: ________________    Sección: ________")
    c.drawString(40, y-30, "Fecha de aplicación: ___________________    Tutor/a: _______________________")
    c.drawString(40, y-42, "Institución: I.E.P. ALTERNATIVO YACHAY — Chinchero, Cusco")
    y -= 58

    # ── INSTRUCCIONES ─────────────────────────────────────────────────
    c.setFillColor(colors.HexColor("#fef3c7"))
    c.roundRect(30, y-32, w-60, 36, 4, fill=True)
    c.setFillColor(colors.HexColor("#d97706"))
    c.setFont("Helvetica-Bold", 8)
    c.drawString(38, y-8, "📌 INSTRUCCIONES:")
    c.setFillColor(colors.black)
    c.setFont("Helvetica", 7.5)
    instruccion = test_data.get("instruccion","Elige la alternativa que más te identifica en cada pregunta.")
    c.drawString(38, y-19, instruccion)
    c.drawString(38, y-29, f"Total de preguntas: {n_pregs}  |  Marca solo UNA alternativa por pregunta  |  No borrones")
    y -= 42

    # ── PREGUNTAS ─────────────────────────────────────────────────────
    c.setFont("Helvetica-Bold", 8)
    c.setFillColor(colors.HexColor("#1e3a8a"))
    c.drawString(30, y, "CUESTIONARIO:")
    c.setFillColor(colors.black)
    y -= 12

    def _wrap_text(txt, max_c=88):
        words = txt.split(); lines = []; line = ""
        for w2 in words:
            if len(line)+len(w2)+1 <= max_c: line = (line+" "+w2).strip()
            else: lines.append(line); line=w2
        if line: lines.append(line)
        return lines

    for preg in preguntas:
        pid      = preg["id"]
        texto_p  = preg["pregunta"]
        opciones = preg["opciones"]
        pal_idx  = (pid - 1) % len(PALETA_PREGS)
        bg_preg, col_preg = PALETA_PREGS[pal_idx]

        lineas_p   = _wrap_text(texto_p)
        n_opciones = len(opciones)
        alto_bloque = len(lineas_p)*9 + n_opciones*11 + 18

        if y - alto_bloque < 80:
            c.showPage(); pag += 1; _header_test(pag); _footer_test()
            y = h - 80

        # Caja de pregunta con color de fondo
        c.setFillColor(colors.HexColor(bg_preg))
        c.roundRect(28, y - alto_bloque + 6, w-56, alto_bloque, 8, fill=True, stroke=False)
        # Barra lateral de color
        c.setFillColor(colors.HexColor(col_preg))
        c.roundRect(28, y - alto_bloque + 6, 6, alto_bloque, 3, fill=True, stroke=False)

        # Círculo numerado
        c.setFillColor(colors.HexColor(col_preg))
        c.circle(48, y - 4, 8, fill=True, stroke=False)
        c.setFillColor(colors.white)
        c.setFont("Helvetica-Bold", 8)
        c.drawCentredString(48, y - 7, str(pid))

        # Texto pregunta
        c.setFillColor(colors.HexColor("#0f172a"))
        c.setFont("Helvetica-Bold", 8.5)
        ty = y - 1
        for lp in lineas_p:
            c.drawString(62, ty, lp)
            ty -= 9
        ty -= 2

        # Opciones con chip de color
        for letra, (texto_op, _grupo) in opciones.items():
            bg_op, col_op = COLORES_OPCION.get(letra, ("#f1f5f9","#475569"))
            # Chip colored background
            c.setFillColor(colors.HexColor(bg_op))
            c.roundRect(40, ty - 1, w - 76, 10, 3, fill=True, stroke=False)
            # Letra badge
            c.setFillColor(colors.HexColor(col_op))
            c.roundRect(42, ty, 12, 9, 2, fill=True, stroke=False)
            c.setFillColor(colors.white)
            c.setFont("Helvetica-Bold", 7)
            c.drawCentredString(48, ty + 2, letra)
            # Texto opción
            c.setFillColor(colors.HexColor("#1e293b"))
            c.setFont("Helvetica", 7.5)
            txt_op = texto_op[:95] if len(texto_op) > 95 else texto_op
            c.drawString(58, ty + 2, txt_op)
            ty -= 11

        y = ty - 6

    # ══════════════════════════════════════════════════════════════════
    # PÁGINA FINAL: 4 HOJAS DE RESPUESTAS RECORTABLES POR PÁGINA
    # Layout: 2 columnas × 2 filas  (como en la imagen de referencia)
    # ══════════════════════════════════════════════════════════════════
    c.showPage()
    pag += 1
    _header_test(pag)
    _footer_test()

    letras_resp = ["A", "B", "C", "D", "E"]

    def _dibujar_mini_hoja(ox, oy, ancho, alto, test_nombre_corto):
        """
        Dibuja una mini hoja de respuestas recortable.
        ox, oy = esquina inferior izquierda del recuadro.
        ancho, alto = tamaño del recuadro.
        """
        AZUL  = colors.HexColor("#1e3a8a")
        ROJO  = colors.HexColor("#dc2626")
        GRIS  = colors.HexColor("#475569")
        GRIS_L= colors.HexColor("#e2e8f0")
        BLANC = colors.white

        # Borde exterior recortable (línea punteada)
        c.setStrokeColor(colors.HexColor("#94a3b8"))
        c.setLineWidth(0.5)
        c.setDash(3, 3)
        c.rect(ox, oy, ancho, alto, fill=False)
        c.setDash()   # reset
        c.setLineWidth(1)

        # ── Encabezado de la mini hoja ──────────────────────────────
        c.setFillColor(AZUL)
        c.rect(ox, oy + alto - 18, ancho, 18, fill=True)
        c.setFillColor(colors.HexColor("#f59e0b"))
        c.rect(ox, oy + alto - 20, ancho, 2, fill=True)
        c.setFillColor(BLANC)
        c.setFont("Helvetica-Bold", 6.5)
        c.drawCentredString(ox + ancho/2, oy + alto - 12,
                            f"✏  HOJA DE RESPUESTAS — {test_nombre_corto[:35].upper()}")

        # ── Datos alumno ────────────────────────────────────────────
        dy = oy + alto - 24
        c.setFillColor(colors.HexColor("#f8fafc"))
        c.rect(ox + 4, dy - 20, ancho - 8, 20, fill=True)
        c.setFillColor(colors.black)
        c.setFont("Helvetica-Bold", 5.5)
        c.drawString(ox + 7, dy - 8,
                     "Apellidos y Nombres: ________________________________")
        c.drawString(ox + 7, dy - 17,
                     "DNI: _______________   Grado: ____________   Fecha: __________")
        dy -= 24

        # ── Encabezado columnas (N° A B C D E) ──────────────────────
        c.setFillColor(AZUL)
        c.setFont("Helvetica-Bold", 5.5)
        # Calcular posiciones
        COL_GAP   = ancho / 2 - 4       # ancho de cada media hoja
        BUB_R     = 4                    # radio burbuja
        BUB_STEP  = 13                   # separación entre letras
        N_X_OFF   = 8                    # offset del número desde ox
        LETRAS_X0 = N_X_OFF + 16        # donde empieza la primera burbuja

        for col_lado in range(2):       # 0=izq, 1=der
            base_x = ox + col_lado * COL_GAP + 4
            # encabezado N°
            c.drawString(base_x + N_X_OFF - 2, dy, "N°")
            for li, letra in enumerate(letras_resp):
                cx_h = base_x + LETRAS_X0 + li * BUB_STEP
                c.drawCentredString(cx_h, dy, letra)

        dy -= 2
        c.setStrokeColor(GRIS_L)
        c.setLineWidth(0.4)
        c.line(ox + 4, dy, ox + ancho - 4, dy)
        c.setLineWidth(1)
        dy -= 1

        # ── Burbujas por pregunta ─────────────────────────────────────
        mitad = (n_pregs + 1) // 2
        col1 = list(range(1, mitad + 1))
        col2 = list(range(mitad + 1, n_pregs + 1))
        fila_h = 11   # altura por fila

        for idx_f in range(len(col1)):
            dy -= fila_h
            if dy < oy + 18:
                break   # no cabe más en este recuadro

            for col_lado in range(2):
                num_p = col1[idx_f] if col_lado == 0 else (col2[idx_f] if idx_f < len(col2) else None)
                if num_p is None:
                    continue
                base_x = ox + col_lado * COL_GAP + 4

                # Fondo alterno
                if num_p % 2 == 0:
                    c.setFillColor(colors.HexColor("#f1f5f9"))
                    c.rect(base_x + 4, dy - 2, COL_GAP - 8, fila_h - 1, fill=True)

                # Número pregunta
                c.setFillColor(AZUL)
                c.setFont("Helvetica-Bold", 5.5)
                c.drawRightString(base_x + N_X_OFF + 12, dy + 3, f"{num_p}.")

                # 5 burbujas
                for li in range(5):
                    cx_b = base_x + LETRAS_X0 + li * BUB_STEP
                    c.setFillColor(BLANC)
                    c.setStrokeColor(GRIS)
                    c.setLineWidth(0.6)
                    c.circle(cx_b, dy + 3, BUB_R, fill=True, stroke=True)
                    c.setFillColor(GRIS)
                    c.setFont("Helvetica", 4.5)
                    c.drawCentredString(cx_b, dy + 1, letras_resp[li])

            # Línea separadora entre filas
            c.setStrokeColor(GRIS_L)
            c.setLineWidth(0.2)
            c.line(ox + 6, dy - 2, ox + ancho - 6, dy - 2)

        # ── Pie: advertencia ────────────────────────────────────────
        c.setFillColor(ROJO)
        c.setFont("Helvetica-Bold", 5)
        c.drawCentredString(ox + ancho/2, oy + 5,
                            "⚠ NO DOBLE NI MALTRATE ESTA HOJA — ENTREGUE AL TUTOR AL TERMINAR")
        c.setFillColor(colors.black)
        c.setStrokeColor(colors.black)

    # ── Layout: 4 hojas por página (2 cols × 2 filas) bien distribuidas ─
    HDR_H     = 72    # altura del encabezado ya dibujado
    PIE_H     = 22    # espacio pie de página
    MARGEN_L  = 16    # márgenes laterales
    MARGEN_V  = 8     # márgenes verticales entre hojas y borde
    ESPACIO_H = 10    # separación horizontal entre hojas
    ESPACIO_V = 10    # separación vertical entre hojas

    area_x = MARGEN_L
    area_y = PIE_H + MARGEN_V
    area_w = w  - 2 * MARGEN_L
    area_h = h  - HDR_H - PIE_H - 2 * MARGEN_V

    HOJA_W = (area_w - ESPACIO_H) / 2
    HOJA_H = (area_h - ESPACIO_V) / 2

    nombre_corto_test = test_data.get("nombre","TEST VOCACIONAL")

    # 4 posiciones: fila superior (oy más alto) e inferior
    posiciones = [
        (area_x,              area_y + HOJA_H + ESPACIO_V),   # sup izq
        (area_x + HOJA_W + ESPACIO_H, area_y + HOJA_H + ESPACIO_V),  # sup der
        (area_x,              area_y),                          # inf izq
        (area_x + HOJA_W + ESPACIO_H, area_y),                 # inf der
    ]

    for (ox_h, oy_h) in posiciones:
        _dibujar_mini_hoja(ox_h, oy_h, HOJA_W, HOJA_H, nombre_corto_test)

    # ── Líneas de corte punteadas ─────────────────────────────────────
    c.setStrokeColor(colors.HexColor("#7c3aed"))
    c.setLineWidth(0.7)
    c.setDash(5, 4)
    cx_c = area_x + HOJA_W + ESPACIO_H / 2
    cy_c = area_y + HOJA_H + ESPACIO_V / 2
    c.line(cx_c, area_y, cx_c, area_y + area_h)           # vertical
    c.line(area_x, cy_c, area_x + area_w, cy_c)            # horizontal
    c.setDash()
    c.setLineWidth(1)

    # Instrucción de corte
    c.setFillColor(colors.HexColor("#7c3aed"))
    c.setFont("Helvetica-Bold", 7)
    c.drawCentredString(w/2, PIE_H - 4,
                        "✂  Recortar por las líneas punteadas — 4 hojas por página  ✂")

    c.save()
    buf.seek(0)
    return buf


def _tab_test_vocacional_ui(config):
    """
    Pestaña: Orientación Vocacional UNSAAC
    3 subtabs:
      1. Descargar Tests en PDF (para imprimir y aplicar)
      2. Ingresar Claves y generar Diagnóstico individual
      3. Diagnósticos en Lote (ZIP por grado)
    """
    st.markdown("### 🎓 Orientación Vocacional — UNSAAC")
    st.caption("Centro de Estudios Preuniversitarios — Universidad Nacional de San Antonio Abad del Cusco")

    subtab_tv = st.radio("", [
        "📄 Descargar Tests para imprimir",
        "💻 Modo Digital — Alumno responde en pantalla",
        "✏️ Ingresar Claves → Diagnóstico individual",
        "📦 Diagnósticos en Lote (ZIP por grado)",
    ], horizontal=True, key="tv_subtab")

    test_ids     = list(TESTS_VOCACIONALES.keys())
    test_nombres = [TESTS_VOCACIONALES[t]["nombre"] for t in test_ids]

    # ═══════════════════════════════════════════════════════════════
    # SUBTAB 1: Descargar tests para imprimir
    # ═══════════════════════════════════════════════════════════════
    if subtab_tv == "📄 Descargar Tests para imprimir":
        st.markdown("#### 📄 Tests listos para imprimir y aplicar")
        st.info("Imprime el test, aplícalo a los alumnos, recoge las hojas y luego ingresa las claves en la siguiente pestaña.")

        col_t1, col_t2 = st.columns([2,1])
        with col_t1:
            test_sel_imp = st.selectbox("Seleccionar test:", test_nombres, key="tv_imp_test")
            test_id_imp  = test_ids[test_nombres.index(test_sel_imp)]
            td           = TESTS_VOCACIONALES[test_id_imp]
            st.markdown(f"**{td['nombre']}**")
            st.caption(f"📌 {td['descripcion']}")
            st.caption(f"📝 {len(td['preguntas'])} preguntas  |  Instrucción: {td['instruccion']}")
        with col_t2:
            st.markdown("<br>", unsafe_allow_html=True)
            if st.button("🖨️ Generar PDF del test", type="primary", key="tv_imp_btn"):
                pdf_imp = generar_pdf_test_imprimible(test_id_imp, config)
                if pdf_imp:
                    nombre_archivo = f"TEST_{test_id_imp.upper()}_{config.get('anio',2026)}.pdf"
                    st.download_button(
                        "⬇️ Descargar PDF para imprimir",
                        pdf_imp,
                        nombre_archivo,
                        "application/pdf",
                        key="dl_tv_imp"
                    )
                    st.success("✅ PDF generado — incluye cuestionario + hoja de respuestas con burbujas")

        # Vista previa de las preguntas
        st.markdown("---")
        st.markdown("##### 👁️ Vista previa del cuestionario:")
        td2 = TESTS_VOCACIONALES[test_id_imp]
        for preg in td2["preguntas"]:
            with st.expander(f"**{preg['id']}.** {preg['pregunta']}"):
                for letra, (texto_op, grupo) in preg["opciones"].items():
                    etiq_grupo = UNSAAC_GRUPOS.get(grupo, {}).get("nombre", "Técnico/Otros") if grupo != "T" else "Técnico / PNP / Institutos"
                    st.write(f"**{letra})** {texto_op}")

    # ═══════════════════════════════════════════════════════════════
    # SUBTAB 2: Ingresar Claves → Diagnóstico individual
    # ═══════════════════════════════════════════════════════════════
    elif subtab_tv == "💻 Modo Digital — Alumno responde en pantalla":
        st.markdown("#### 💻 Modo Digital — El alumno responde el test en pantalla")

        # ── MODO DE ACCESO ────────────────────────────────────────────────────
        modo_acceso = st.radio("¿Quién ingresa?", [
            "DOCENTE Docente selecciona al alumno",
            "🎓 Alumno ingresa su DNI",
        ], horizontal=True, key="dig_acceso_modo")

        df_alum_dig = BaseDatos.cargar_matricula()

        if modo_acceso == "🎓 Alumno ingresa su DNI":
            st.markdown("---")
            st.markdown("##### 🎓 Ingreso del Estudiante")
            st.info("El alumno escribe su DNI — el sistema lo identifica automáticamente. No necesita contraseña.")
            col_dni1, col_dni2 = st.columns([2, 3])
            with col_dni1:
                dni_ingresado = st.text_input("📋 Escribe tu DNI:", max_chars=8,
                                              placeholder="Ej: 76543210", key="dig_dni_input")
            alumno_encontrado = None
            grado_dig = ""
            nombre_dig = ""
            if dni_ingresado and len(dni_ingresado.strip()) >= 7:
                _fila_dni = df_alum_dig[df_alum_dig["DNI"].astype(str).str.strip() == dni_ingresado.strip()] if not df_alum_dig.empty and "DNI" in df_alum_dig.columns else pd.DataFrame()
                if not _fila_dni.empty:
                    alumno_encontrado = _fila_dni.iloc[0]
                    nombre_dig = str(alumno_encontrado.get("Nombre", ""))
                    grado_dig  = str(alumno_encontrado.get("Grado", ""))
                    st.success(f"✅ Bienvenido/a **{nombre_dig}** — {grado_dig}")
                else:
                    st.error("❌ DNI no encontrado. Verifica el número o pide ayuda al docente.")
            if not alumno_encontrado:
                st.stop()
            df_g_dig = _fila_dni
        else:
            # Docente selecciona
            col_dig1, col_dig2 = st.columns(2)
            with col_dig1:
                grados_dig = sorted(df_alum_dig["Grado"].dropna().unique().tolist()) if not df_alum_dig.empty else []
                grado_dig = st.selectbox("Grado:", grados_dig, key="dig_grado")
            with col_dig2:
                df_g_dig = df_alum_dig[df_alum_dig["Grado"] == grado_dig] if not df_alum_dig.empty else pd.DataFrame()
                nombres_dig = df_g_dig["Nombre"].dropna().tolist() if not df_g_dig.empty else []
                nombre_dig = st.selectbox("Estudiante:", nombres_dig, key="dig_nombre")
            df_g_dig = df_alum_dig[df_alum_dig["Nombre"] == nombre_dig] if not df_alum_dig.empty else pd.DataFrame()

        # ── Filtrar tests por nivel del grado ────────────────────────────────
        def _nivel_grado(grado_str):
            g = str(grado_str).lower()
            if any(x in g for x in ['inicial','jardin','kinder']): return 'inicial'
            if any(x in g for x in ['primaria','1° p','2° p','3° p','4° p','5° p','6° p']): return 'primaria'
            if any(x in g for x in ['sec','secundaria','1° s','2° s','3° s','4° s','5° s']): return 'secundaria'
            if any(x in g for x in ['grupo','preu','ciclo','cepre']): return 'preuniversitario'
            return 'secundaria'

        _nivel_actual = _nivel_grado(grado_dig)
        _nivel_badge = {"inicial":"🌱 Inicial","primaria":"📚 Primaria","secundaria":"🎓 Secundaria","preuniversitario":"🏫 Preuniversitario"}.get(_nivel_actual, _nivel_actual)

        # Filtrar tests apropiados para el nivel
        _test_ids_filtrados   = [t for t in test_ids if _nivel_actual in TESTS_VOCACIONALES[t].get("nivel", ["secundaria","preuniversitario"])]
        _test_nombres_filtrados = [TESTS_VOCACIONALES[t]["nombre"] for t in _test_ids_filtrados]

        if not _test_ids_filtrados:
            st.warning(f"⚠️ No hay tests disponibles para el nivel {_nivel_badge} aún.")
            st.stop()

        st.caption(f"Nivel detectado: **{_nivel_badge}** — mostrando {len(_test_ids_filtrados)} test(s) apropiado(s)")
        test_sel_dig = st.selectbox("🧪 Seleccionar Test:", _test_nombres_filtrados, key="dig_test")
        test_id_dig  = _test_ids_filtrados[_test_nombres_filtrados.index(test_sel_dig)]

        td_dig = TESTS_VOCACIONALES[test_id_dig]
        preguntas_dig = td_dig["preguntas"]
        total_preg_dig = len(preguntas_dig)

        # Inicializar respuestas digitales en session_state
        key_resp = f"dig_resp_{test_id_dig}"
        if key_resp not in st.session_state:
            st.session_state[key_resp] = {}

        st.markdown("---")
        st.markdown(f"### 📝 {td_dig['nombre']}")
        st.caption(f"*{td_dig['instruccion']}*")
        st.markdown("<div style='height:8px'></div>", unsafe_allow_html=True)

        # Mostrar preguntas con botones de opción estilo tarjeta
        respuestas_dig = st.session_state[key_resp].copy()
        todas_resp = True

        for preg in preguntas_dig:
            pid = preg["id"]
            opciones = preg["opciones"]
            resp_actual = respuestas_dig.get(str(pid), "")

            # Card de pregunta
            st.markdown(
                f'<div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:10px;'
                f'padding:14px 16px;margin-bottom:8px;">'
                f'<div style="font-weight:700;color:#1e293b;margin-bottom:8px;">'
                f'{pid}. {preg["pregunta"]}</div></div>',
                unsafe_allow_html=True)

            # Opciones como botones radio con color
            letras = list(opciones.keys())
            _cols = st.columns(len(letras))
            for ci, letra in enumerate(letras):
                texto_op, _ = opciones[letra]
                is_sel = (resp_actual == letra)
                bg = "#2563eb" if is_sel else "#f1f5f9"
                fg = "white" if is_sel else "#334155"
                brd = "#2563eb" if is_sel else "#e2e8f0"
                with _cols[ci]:
                    # Mostrar como texto clicable (Streamlit no soporta botones con estado visual nativo en columnas)
                    st.markdown(
                        f'<div style="background:{bg};color:{fg};border:2px solid {brd};'
                        f'border-radius:8px;padding:8px 6px;text-align:center;font-size:0.8rem;'
                        f'cursor:pointer;min-height:60px;display:flex;align-items:center;justify-content:center;">'
                        f'<strong>{letra}</strong><br><span style="font-size:0.72rem;">{texto_op[:40]}</span>'
                        f'</div>', unsafe_allow_html=True)
                    if st.button(f"{letra}", key=f"dig_{test_id_dig}_{pid}_{letra}",
                                 use_container_width=True,
                                 type="primary" if is_sel else "secondary"):
                        st.session_state[key_resp][str(pid)] = letra
                        st.rerun()

            if not resp_actual:
                todas_resp = False

        # Progreso
        respondidas = sum(1 for p in preguntas_dig if str(p["id"]) in respuestas_dig)
        pct_prog = int(respondidas / total_preg_dig * 100)
        color_prog = "#16a34a" if pct_prog == 100 else "#3b82f6"
        st.markdown(
            f'<div style="margin:16px 0 8px 0;">'
            f'<div style="display:flex;justify-content:space-between;font-size:0.85rem;color:#64748b;margin-bottom:4px;">'
            f'<span>Progreso</span><span>{respondidas}/{total_preg_dig} respondidas</span></div>'
            f'<div style="background:#e2e8f0;border-radius:8px;height:8px;">'
            f'<div style="background:{color_prog};border-radius:8px;height:8px;width:{pct_prog}%;transition:width 0.4s;"></div>'
            f'</div></div>', unsafe_allow_html=True)

        st.markdown("---")
        if todas_resp:
            st.success("✅ ¡Test completado! Genera tu diagnóstico PDF.")
            _gen_pdf = st.button("🎯 GENERAR DIAGNÓSTICO PDF", type="primary",
                         use_container_width=True, key="dig_gen_pdf")
            # Si ya se generó antes en esta sesión, mostrar de nuevo automáticamente
            if _gen_pdf or st.session_state.get(f"dig_pdf_listo_{test_id_dig}_{nombre_dig}"):
                _gen_pdf = True
            if _gen_pdf:
                # Calcular resultado del test
                conteo = {}
                for preg in preguntas_dig:
                    letra_r = respuestas_dig.get(str(preg["id"]), "")
                    if letra_r and letra_r in preg["opciones"]:
                        grupo = preg["opciones"][letra_r][1]
                        conteo[grupo] = conteo.get(grupo, 0) + 1

                resultado_test_dig = {
                    "test_id": test_id_dig,
                    "test_nombre": td_dig["nombre"],
                    "respuestas": respuestas_dig,
                    "conteo": conteo,
                    "grupo_dominante": max(conteo, key=conteo.get) if conteo else "A",
                    "descripcion_grupo": td_dig.get("grupos_resultado", UNSAAC_GRUPOS).get(
                        max(conteo, key=conteo.get) if conteo else "A", {}
                    ) if isinstance(list(td_dig.get("grupos_resultado",{}).values() or [""])[0], str)
                      else UNSAAC_GRUPOS.get(max(conteo, key=conteo.get) if conteo else "A", {}),
                }

                # Buscar datos del alumno
                fila_dig = df_g_dig[df_g_dig["Nombre"] == nombre_dig] if not df_g_dig.empty else pd.DataFrame()
                dni_dig  = str(fila_dig.iloc[0].get("DNI","")) if not fila_dig.empty else ""
                prom_areas_dig = {}
                hist_dig = _cargar_historial_evaluaciones()
                for _, ev_d in hist_dig.items():
                    if ev_d.get("grado","") == grado_dig:
                        for frd in ev_d.get("ranking",[]):
                            if str(frd.get("DNI","")) == dni_dig or frd.get("Nombre","") == nombre_dig:
                                for an in [a["nombre"] for a in ev_d.get("areas",[]) if isinstance(a, dict)]:
                                    nv = frd.get(an, 0)
                                    if nv and float(nv) > 0:
                                        prom_areas_dig.setdefault(an, []).append(float(nv))
                prom_areas_dig = {k: round(sum(v)/len(v),1) for k,v in prom_areas_dig.items()}
                prom_dig = round(sum(prom_areas_dig.values())/len(prom_areas_dig),1) if prom_areas_dig else 0
                lit_dig  = nota_a_letra(prom_dig) if prom_dig > 0 else "C"
                afin_dig = _calcular_afinidad_academica(prom_areas_dig)

                _pdf_key       = f"dig_pdf_listo_{test_id_dig}_{nombre_dig}"
                _pdf_bytes_key = f"dig_pdf_bytes_{test_id_dig}_{nombre_dig}"
                # Usar PDF cacheado si ya fue generado antes
                if st.session_state.get(_pdf_bytes_key):
                    pdf_dig = st.session_state[_pdf_bytes_key]
                else:
                    with st.spinner("Generando diagnóstico..."):
                        pdf_dig = generar_pdf_orientacion_vocacional(
                            nombre_dig, dni_dig, grado_dig,
                            prom_dig, lit_dig, prom_areas_dig, afin_dig, config,
                            resultado_test=resultado_test_dig)
                    st.session_state[_pdf_key]       = True
                    st.session_state[_pdf_bytes_key] = pdf_dig
                st.success("✅ Diagnóstico listo — descárgalo ahora")
                # Botón de descarga SIEMPRE visible al completar
                st.download_button(
                    "⬇️ 📄 Descargar PDF Diagnóstico",
                    pdf_dig, f"Diagnostico_{nombre_dig.replace(' ','_')}_{test_id_dig}.pdf",
                    "application/pdf", key="dl_dig_pdf",
                    use_container_width=True, type="primary")

                # Mostrar resumen visual del resultado
                st.markdown("---")
                st.markdown("### 📊 Resultado del test")
                if conteo:
                    grupos_res = td_dig.get("grupos_resultado", {})
                    _sorted_c = sorted(conteo.items(), key=lambda x: -x[1])
                    cols_res = st.columns(min(len(_sorted_c), 4))
                    for ci, (gr, cnt) in enumerate(_sorted_c[:4]):
                        with cols_res[ci]:
                            gr_nombre = grupos_res.get(gr, gr) if grupos_res else UNSAAC_GRUPOS.get(gr, {}).get("nombre", gr)
                            _pct_r = round(cnt / total_preg_dig * 100)
                            _cc_r = ["#2563eb","#16a34a","#f59e0b","#dc2626"][ci]
                            st.markdown(
                                f'<div style="background:white;border:2px solid {_cc_r};border-radius:10px;'
                                f'padding:12px;text-align:center;">'
                                f'<div style="font-size:1.6rem;font-weight:900;color:{_cc_r};">{_pct_r}%</div>'
                                f'<div style="font-size:0.8rem;font-weight:700;color:#334155;">{gr_nombre}</div>'
                                f'<div style="font-size:0.72rem;color:#94a3b8;">{cnt} respuestas</div>'
                                f'</div>', unsafe_allow_html=True)
        else:
            st.warning(f"⚠️ Faltan {total_preg_dig - respondidas} preguntas por responder.")
            if st.button("🔄 Reiniciar test", key="dig_reset", type="secondary"):
                st.session_state[key_resp] = {}
                st.rerun()

    elif subtab_tv == "✏️ Ingresar Claves → Diagnóstico individual":
        st.markdown("#### ✏️ Ingreso de claves del test aplicado")
        st.info("Selecciona el estudiante, el test aplicado, e ingresa la alternativa que marcó en cada pregunta (A, B, C, D o E). Luego genera el diagnóstico PDF.")

        df_alum = BaseDatos.cargar_matricula()
        if df_alum is None or df_alum.empty:
            st.warning("No hay alumnos cargados en la base de datos.")
            return

        grados_disp = sorted(df_alum["Grado"].dropna().unique().tolist())

        col_e1, col_e2, col_e3 = st.columns(3)
        with col_e1:
            grado_tv = st.selectbox("Grado:", grados_disp, key="tv_grado_cl")
        with col_e2:
            df_g     = df_alum[df_alum["Grado"] == grado_tv]
            nombres_tv = df_g["Nombre"].dropna().tolist()
            nombre_tv  = st.selectbox("Estudiante:", nombres_tv, key="tv_nombre_cl")
        with col_e3:
            test_sel_nombre = st.selectbox("Test aplicado:", test_nombres, key="tv_tipo_cl")
            test_sel_id     = test_ids[test_nombres.index(test_sel_nombre)]
            test_data       = TESTS_VOCACIONALES[test_sel_id]

        if nombre_tv:
            fila_tv = df_g[df_g["Nombre"] == nombre_tv].iloc[0]
            dni_tv  = str(fila_tv.get("DNI",""))

            st.markdown("---")
            st.markdown(f"**Test:** {test_data['nombre']}  |  **Estudiante:** {nombre_tv}  |  **Grado:** {grado_tv}")
            st.caption(f"Instrucción dada al estudiante: *{test_data['instruccion']}*")

            # ── Tabla de ingreso de claves ────────────────────────────
            st.markdown("##### 📋 Ingresa la alternativa marcada por el estudiante:")
            st.caption("Selecciona A / B / C / D / E según lo que marcó el alumno en la hoja de respuestas.")

            preguntas_test = test_data["preguntas"]
            n_cols = 5  # preguntas por fila
            respuestas = {}

            for fila_idx in range(0, len(preguntas_test), n_cols):
                chunk = preguntas_test[fila_idx : fila_idx + n_cols]
                cols  = st.columns(len(chunk))
                for ci, preg in enumerate(chunk):
                    with cols[ci]:
                        texto_corto = preg["pregunta"][:45] + "…" if len(preg["pregunta"]) > 45 else preg["pregunta"]
                        st.caption(f"**{preg['id']}.** {texto_corto}")
                        letra_marcada = st.selectbox(
                            f"Resp. {preg['id']}",
                            list(preg["opciones"].keys()),
                            key=f"tv_clave_{test_sel_id}_{preg['id']}",
                            label_visibility="collapsed"
                        )
                        grupo_mapeado = preg["opciones"].get(letra_marcada, ("","A"))[1]
                        respuestas[preg["id"]] = grupo_mapeado

                        # Mostrar a qué grupo va esta respuesta
                        nombre_grp = UNSAAC_GRUPOS.get(grupo_mapeado,{}).get("icono","🔧") if grupo_mapeado != "T" else "🔧"
                        st.caption(f"→ {nombre_grp} {letra_marcada}")

            st.markdown("---")

            # ── Resumen visual antes de generar ──────────────────────
            conteo_prev = {"A":0,"B":0,"C":0,"D":0,"T":0}
            for _, grp in respuestas.items():
                conteo_prev[grp] = conteo_prev.get(grp,0) + 1
            labels_prev = {"A":"⚙️ Ing/Ciencias","B":"🏥 Salud","C":"⚖️ Sociales","D":"🎓 Educación","T":"🔧 Técnico"}
            st.markdown("**Distribución de respuestas:**")
            cols_prev = st.columns(5)
            for gi, (gk, glabel) in enumerate(labels_prev.items()):
                with cols_prev[gi]:
                    cnt = conteo_prev.get(gk,0)
                    color_card = {"A":"#dbeafe","B":"#d1fae5","C":"#fee2e2","D":"#ede9fe","T":"#fef3c7"}[gk]
                    st.markdown(
                        f"<div style='background:{color_card};padding:8px;border-radius:8px;text-align:center'>"
                        f"<b style='font-size:1.4em'>{cnt}</b><br><small>{glabel}</small></div>",
                        unsafe_allow_html=True
                    )

            st.markdown("<br>", unsafe_allow_html=True)
            if st.button("🎯 Generar Diagnóstico y Descargar PDF", type="primary", key="tv_generar_cl"):
                # Cargar notas del estudiante
                hist_eval = _cargar_historial_evaluaciones()
                notas_est = []
                for _, ev in hist_eval.items():
                    for fila_h in ev.get("ranking",[]):
                        if str(fila_h.get("DNI","")) == dni_tv:
                            areas_h = ev.get("areas",[])
                            names_h = [a["nombre"] for a in areas_h] if areas_h and isinstance(areas_h[0],dict) else list(areas_h)
                            for an in names_h:
                                nv = fila_h.get(an,0)
                                if nv and float(nv)>0:
                                    notas_est.append({"area":an,"nota":float(nv)})

                promedios_area = {}
                for n in notas_est:
                    promedios_area.setdefault(n["area"],[]).append(n["nota"])
                promedios_area = {k: round(sum(v)/len(v),1) for k,v in promedios_area.items()}
                prom_gen  = round(sum(promedios_area.values())/len(promedios_area),1) if promedios_area else 0
                lit_gen   = nota_a_letra(prom_gen) if prom_gen>0 else "C"
                afinidad  = _calcular_afinidad_academica(promedios_area)
                resultado_test = _calcular_resultado_test(respuestas)

                gp    = afinidad["grupo_principal"]
                gdata = UNSAAC_GRUPOS.get(gp,{})
                gp_t  = resultado_test["principal"]
                gdata_t = UNSAAC_GRUPOS.get(gp_t,{})

                col_r1, col_r2 = st.columns(2)
                with col_r1:
                    st.success(f"✅ Por notas académicas → **{gdata.get('nombre','—')}** {gdata.get('icono','')}")
                with col_r2:
                    nombre_t = gdata_t.get("nombre","—") if gp_t!="T" else "Técnico / PNP / Institutos"
                    st.info(f"🧠 Por test vocacional → **{nombre_t}**")

                pdf_diag = generar_pdf_orientacion_vocacional(
                    nombre_tv, dni_tv, grado_tv,
                    prom_gen, lit_gen, promedios_area, afinidad, config,
                    resultado_test=resultado_test)
                st.download_button(
                    f"⬇️ Diagnóstico Vocacional PDF — {nombre_tv}",
                    pdf_diag,
                    f"Diagnostico_Vocacional_{nombre_tv.replace(' ','_')}.pdf",
                    "application/pdf",
                    key="dl_tv_diag"
                )

    # ═══════════════════════════════════════════════════════════════
    # SUBTAB 3: Diagnósticos en lote
    # ═══════════════════════════════════════════════════════════════
    else:
        st.markdown("#### 📦 Diagnósticos en lote — Por grado")
        st.info("Genera el PDF de diagnóstico vocacional para todos los estudiantes del grado (basado en notas académicas sin test individual).")

        df_alum = BaseDatos.cargar_matricula()
        if df_alum is None or df_alum.empty:
            st.warning("No hay alumnos cargados en la base de datos.")
            return
        grados_disp = sorted(df_alum["Grado"].dropna().unique().tolist())

        col_l1, col_l2 = st.columns(2)
        with col_l1:
            grado_lote = st.selectbox("Grado:", grados_disp, key="tv_lote_grado")
        with col_l2:
            st.markdown("<br>", unsafe_allow_html=True)
            incluir_tabla = st.checkbox("Incluir tabla de carreras UNSAAC completa", value=True, key="tv_lote_tabla")

        df_lote = df_alum[df_alum["Grado"] == grado_lote]
        st.info(f"📋 {len(df_lote)} estudiantes en **{grado_lote}** — Cada uno recibirá su PDF de diagnóstico vocacional UNSAAC.")

        if st.button("📦 Generar ZIP — Diagnósticos del grado completo", type="primary", key="tv_lote_btn"):
            hist_eval = _cargar_historial_evaluaciones()
            zip_buf   = io.BytesIO()
            generados = 0
            barra     = st.progress(0)
            total_est = len(df_lote)

            with zipfile.ZipFile(zip_buf, "w", zipfile.ZIP_DEFLATED) as zf:
                for idx_est, (_, row_l) in enumerate(df_lote.iterrows()):
                    nombre_l = str(row_l.get("Nombre",""))
                    dni_l    = str(row_l.get("DNI",""))
                    if not nombre_l or not dni_l:
                        continue
                    notas_l = []
                    for _, ev in hist_eval.items():
                        for fila_l in ev.get("ranking",[]):
                            if str(fila_l.get("DNI","")) == dni_l:
                                areas_l  = ev.get("areas",[])
                                names_l  = [a["nombre"] for a in areas_l] if areas_l and isinstance(areas_l[0],dict) else list(areas_l)
                                for an in names_l:
                                    nv = fila_l.get(an,0)
                                    if nv and float(nv)>0:
                                        notas_l.append({"area":an,"nota":float(nv)})
                    prom_area_l = {}
                    for n in notas_l:
                        prom_area_l.setdefault(n["area"],[]).append(n["nota"])
                    prom_area_l = {k: round(sum(v)/len(v),1) for k,v in prom_area_l.items()}
                    prom_l      = round(sum(prom_area_l.values())/len(prom_area_l),1) if prom_area_l else 0
                    lit_l       = nota_a_letra(prom_l) if prom_l>0 else "C"
                    afinidad_l  = _calcular_afinidad_academica(prom_area_l)

                    pdf_l = generar_pdf_orientacion_vocacional(
                        nombre_l, dni_l, grado_lote,
                        prom_l, lit_l, prom_area_l, afinidad_l, config,
                        resultado_test=None)
                    zf.writestr(f"Diagnostico_{nombre_l.replace(' ','_')}.pdf", pdf_l.read())
                    generados += 1
                    barra.progress(int((idx_est+1)/total_est*100))

            zip_buf.seek(0)
            barra.empty()
            st.success(f"✅ {generados} diagnósticos generados")
            st.download_button(
                f"⬇️ Descargar ZIP — {grado_lote} ({generados} diagnósticos)",
                zip_buf,
                f"Diagnosticos_Vocacionales_{grado_lote.replace(' ','_')}.zip",
                "application/zip",
                key="dl_tv_lote"
            )


def tab_reportes(config):
    """Tab de reportes y historial — COMPLETO"""
    st.subheader("📊 Reportes e Historial")

    subtab = st.radio("Seleccionar:", [
        "📋 Asistencia Mensual", "DOCENTE Asistencia Docentes",
        "📊 Reporte Integral",
        "📄 Reporte ZipGrade", "🏆 Historial de Evaluaciones",
        "📁 Fichas Docentes",
        "🎓 Orientación Vocacional UNSAAC",
    ], horizontal=True, key="rep_tipo")

    gs = _gs()

    if subtab == "🏆 Historial de Evaluaciones":
        st.markdown("### 🏆 Historial de Evaluaciones — Vista Director")
        hist = _cargar_historial_evaluaciones()
        if not hist:
            st.info("📭 No hay evaluaciones guardadas en el historial.")
            return

        # Filtros
        fc1, fc2 = st.columns(2)
        with fc1:
            grados_hist = sorted(set(v.get('grado','') for v in hist.values()))
            filtro_grado = st.selectbox("Filtrar por grado:", ["Todos"] + grados_hist, key="rep_hist_grado")
        with fc2:
            docentes_hist = sorted(set(v.get('docente','') for v in hist.values()))
            filtro_doc = st.selectbox("Filtrar por docente:", ["Todos"] + docentes_hist, key="rep_hist_doc")

        total_mostradas = 0
        for clave, ev in sorted(hist.items(), reverse=True):
            if filtro_grado != "Todos" and ev.get('grado') != filtro_grado:
                continue
            if filtro_doc != "Todos" and ev.get('docente') != filtro_doc:
                continue
            total_mostradas += 1
            areas_ev = ev.get('areas', [])
            if areas_ev and isinstance(areas_ev[0], dict):
                areas_nombres_ev = [a['nombre'] for a in areas_ev]
            else:
                areas_nombres_ev = list(areas_ev)
            titulo_ev = ev.get('titulo', '') or ''
            label_ev = f"📝 {ev.get('grado','')} | {ev.get('periodo','')} | {ev.get('fecha','')}"
            if titulo_ev:
                label_ev += f" — {titulo_ev}"
            with st.expander(label_ev):
                st.caption(f"👤 Docente: {ev.get('docente_nombre', ev.get('docente','—'))} | 📚 Áreas: {', '.join(areas_nombres_ev)} | 👥 Estudiantes: {len(ev.get('ranking',[]))}")
                ranking_ev = ev.get('ranking', [])
                if ranking_ev:
                    df_ev = pd.DataFrame(ranking_ev)
                    cols_ev = ['Puesto','Medalla','Nombre'] + areas_nombres_ev + ['Promedio']
                    cols_ev = [c for c in cols_ev if c in df_ev.columns]
                    st.dataframe(df_ev[cols_ev], use_container_width=True, hide_index=True)
                    if st.button("📥 PDF Ranking", key=f"rep_pdf_{clave}", type="primary"):
                        pdf_ev = _generar_ranking_pdf(ranking_ev, areas_nombres_ev,
                                                      ev.get('grado',''), ev.get('periodo',''), config)
                        st.download_button("⬇️ Descargar PDF", pdf_ev,
                                           f"Ranking_{ev.get('grado','')}_{ev.get('periodo','')}_{ev.get('fecha','')}.pdf",
                                           "application/pdf", key=f"dl_rep_{clave}")
        if total_mostradas == 0:
            st.info("No hay evaluaciones para los filtros seleccionados.")
        return

    if subtab == "DOCENTE Asistencia Docentes":
        st.markdown("""<div style='background:linear-gradient(135deg,#001e7c,#0044cc);color:white;
            padding:15px 20px;border-radius:12px;margin-bottom:15px;text-align:center;'>
            <h3 style='margin:0;color:white;'>DOCENTE I.E.P. ALTERNATIVO YACHAY</h3>
            <p style='margin:4px 0 0;color:#b8d4ff;'>Reporte de Asistencia y Puntualidad — Docentes</p>
            <p style='margin:2px 0 0;color:#FFD700;font-size:0.85rem;'>📍 Chinchero, Cusco — {hora_peru().year}</p>
        </div>""", unsafe_allow_html=True)

        # ── Cargar datos de asistencia ──────────────────────────────────
        asistencias = {}
        if Path(ARCHIVO_ASISTENCIAS).exists():
            try:
                with open(ARCHIVO_ASISTENCIAS, 'r', encoding='utf-8') as f:
                    asistencias = json.load(f)
            except Exception:
                pass

        # GS
        datos_gs_doc = {}
        if gs:
            try:
                ws = gs.sh.worksheet('asistencias')
                registros = ws.get_all_records()
                for r in registros:
                    if str(r.get('tipo_persona', '')).lower() == 'docente':
                        fecha = str(r.get('fecha', ''))
                        dni = str(r.get('dni', ''))
                        if fecha and dni:
                            if fecha not in datos_gs_doc:
                                datos_gs_doc[fecha] = {}
                            datos_gs_doc[fecha][dni] = {
                                'nombre': r.get('nombre', ''),
                                'entrada': r.get('hora_entrada', ''),
                                'salida': r.get('hora_salida', ''),
                                'es_docente': True
                            }
            except Exception:
                pass

        todas_fechas = set(asistencias.keys()) | set(datos_gs_doc.keys())

        # Extraer solo docentes
        docentes_asist = {}
        for fecha in sorted(todas_fechas):
            regs = {**datos_gs_doc.get(fecha, {}), **asistencias.get(fecha, {})}
            for dni, dat in regs.items():
                if dat.get('es_docente', False):
                    nm = dat.get('nombre', dni)
                    if nm not in docentes_asist:
                        docentes_asist[nm] = {}
                    entrada = dat.get('entrada', '') or dat.get('tardanza', '')
                    tardanza_auto = _es_tardanza_docente(entrada) if entrada else False
                    docentes_asist[nm][fecha] = {
                        'entrada': entrada,
                        'salida': dat.get('salida', ''),
                        'tardanza': tardanza_auto,
                        'entrada_tarde': dat.get('entrada_tarde', ''),
                        'salida_tarde': dat.get('salida_tarde', ''),
                        'dni': dni,
                    }

        if not docentes_asist:
            st.info("📭 No hay registros de asistencia de docentes aún.")
        else:
            df_doc_list = BaseDatos.cargar_docentes()

            modo = st.radio("Vista:", [
                "📅 Semanal por Mes", "📆 Resumen Mensual",
                "✏️ Editar Registros", "⏱️ Horas Sec/PreU",
                "📱 WhatsApp Docentes"
            ], horizontal=True, key="rep_doc_modo")

            # ── Meses escolares (marzo a diciembre) ──────────────────────
            meses_esc = [(m, n) for m, n in MESES_ESCOLARES.items() if m >= 3]

            if modo == "📅 Semanal por Mes":
                mes_sel = st.selectbox("📆 Mes:", meses_esc,
                                        format_func=lambda x: x[1],
                                        key="rep_doc_mes_sem")
                mes_num = mes_sel[0]
                mes_nombre = mes_sel[1]
                anio_sel = hora_peru().year

                semanas = _semanas_del_mes(mes_num, anio_sel)
                if not semanas:
                    st.info("Sin semanas para este mes.")
                else:
                    st.markdown(f"### 📅 {mes_nombre} {anio_sel} — Semanas {semanas[0][0]} a {semanas[-1][0]}")

                    for sem_num, lun, vie in semanas:
                        with st.expander(
                            f"📌 Semana {sem_num}: {lun.strftime('%d/%m')} – {vie.strftime('%d/%m')}",
                            expanded=(sem_num == _semana_escolar_actual())
                        ):
                            data_sem = []
                            for nm in sorted(docentes_asist.keys()):
                                dias_ok = 0
                                tardanzas = 0
                                faltas = 0
                                detalle = []
                                for d in range(5):
                                    dia = lun + timedelta(days=d)
                                    fecha_str = dia.strftime('%Y-%m-%d')
                                    reg = docentes_asist[nm].get(fecha_str, {})
                                    dia_nombre = ['Lun','Mar','Mié','Jue','Vie'][d]
                                    if reg.get('entrada'):
                                        dias_ok += 1
                                        if reg.get('tardanza'):
                                            tardanzas += 1
                                            detalle.append(f"{dia_nombre}:⏰{reg['entrada']}")
                                        else:
                                            detalle.append(f"{dia_nombre}:✅{reg['entrada']}")
                                    elif dia <= hora_peru().date():
                                        faltas += 1
                                        detalle.append(f"{dia_nombre}:❌")
                                    else:
                                        detalle.append(f"{dia_nombre}:—")
                                puntualidad = round((dias_ok - tardanzas) / max(dias_ok, 1) * 100)
                                data_sem.append({
                                    'Docente': nm, 'Asist.': dias_ok,
                                    'Tard.': tardanzas, 'Faltas': faltas,
                                    'Puntualidad': f"{puntualidad}%",
                                    'Detalle': ' | '.join(detalle)
                                })

                            if data_sem:
                                df_s = pd.DataFrame(data_sem)
                                st.dataframe(df_s, use_container_width=True, hide_index=True)

                    # ── Gráfico de barras del mes ──────────────────────────
                    st.markdown("---")
                    st.markdown(f"### 📊 Resumen Gráfico — {mes_nombre}")
                    chart_data = []
                    for nm in sorted(docentes_asist.keys()):
                        dias_total = 0
                        puntuales = 0
                        tardes = 0
                        for fecha_str, reg in docentes_asist[nm].items():
                            try:
                                fd = datetime.strptime(fecha_str, '%Y-%m-%d').date()
                                if fd.month == mes_num and fd.year == anio_sel:
                                    if reg.get('entrada'):
                                        dias_total += 1
                                        if reg.get('tardanza'):
                                            tardes += 1
                                        else:
                                            puntuales += 1
                            except Exception:
                                pass
                        # Nombre corto
                        nm_corto = nm.split()[-1] if ' ' in nm else nm
                        if len(nm_corto) > 12:
                            nm_corto = nm_corto[:10] + ".."
                        chart_data.append({'Docente': nm_corto, 'Puntuales': puntuales, 'Tardanzas': tardes})

                    if chart_data:
                        df_chart = pd.DataFrame(chart_data)
                        import altair as alt
                        df_melt = df_chart.melt(id_vars='Docente', value_vars=['Puntuales', 'Tardanzas'],
                                                 var_name='Tipo', value_name='Días')
                        chart = alt.Chart(df_melt).mark_bar().encode(
                            x=alt.X('Docente:N', sort='-y', title=''),
                            y=alt.Y('Días:Q', title='Días'),
                            color=alt.Color('Tipo:N', scale=alt.Scale(
                                domain=['Puntuales', 'Tardanzas'],
                                range=['#22c55e', '#f59e0b']
                            )),
                            xOffset='Tipo:N'
                        ).properties(height=300, title=f'Asistencia y Puntualidad — {mes_nombre} {anio_sel}')
                        st.altair_chart(chart, use_container_width=True)

            elif modo == "📆 Resumen Mensual":
                mes_sel2 = st.selectbox("📆 Mes:", meses_esc,
                                         format_func=lambda x: x[1],
                                         key="rep_doc_mes2")
                mes_num = mes_sel2[0]
                mes_nombre = mes_sel2[1]
                anio_sel = hora_peru().year

                st.markdown(f"### 📆 Resumen Mensual — {mes_nombre} {anio_sel}")

                data_tabla = []
                for nm in sorted(docentes_asist.keys()):
                    dias_mes = 0
                    puntuales = 0
                    tardanzas = 0
                    entradas = []
                    for fecha_str, reg in docentes_asist[nm].items():
                        try:
                            fd = datetime.strptime(fecha_str, '%Y-%m-%d').date()
                            if fd.month == mes_num and fd.year == anio_sel:
                                if reg.get('entrada'):
                                    dias_mes += 1
                                    entradas.append(reg['entrada'])
                                    if reg.get('tardanza'):
                                        tardanzas += 1
                                    else:
                                        puntuales += 1
                        except Exception:
                            pass
                    puntualidad = round(puntuales / max(dias_mes, 1) * 100)
                    data_tabla.append({
                        'Docente': nm, 'Días': dias_mes,
                        'Puntuales': puntuales, 'Tardanzas': tardanzas,
                        'Puntualidad': f"{puntualidad}%",
                        'Hora Prom.': sorted(entradas)[len(entradas)//2] if entradas else '—',
                    })

                if data_tabla:
                    df_mes = pd.DataFrame(data_tabla).sort_values('Días', ascending=False)
                    st.dataframe(df_mes, use_container_width=True, hide_index=True)

                    # Métricas
                    col_m1, col_m2, col_m3, col_m4 = st.columns(4)
                    col_m1.metric("DOCENTE Docentes", len(data_tabla))
                    col_m2.metric("📅 Prom. días", f"{sum(r['Días'] for r in data_tabla)/max(len(data_tabla),1):.1f}")
                    total_punt = sum(r['Puntuales'] for r in data_tabla)
                    total_tard = sum(r['Tardanzas'] for r in data_tabla)
                    col_m3.metric("✅ Puntuales", total_punt)
                    col_m4.metric("⏰ Tardanzas", total_tard)

                    # Gráfico
                    st.markdown("---")
                    chart_data = []
                    for r in data_tabla:
                        nm_c = r['Docente'].split()[-1] if ' ' in r['Docente'] else r['Docente']
                        if len(nm_c) > 12:
                            nm_c = nm_c[:10] + ".."
                        chart_data.append({'Docente': nm_c, 'Puntuales': r['Puntuales'], 'Tardanzas': r['Tardanzas']})

                    df_chart = pd.DataFrame(chart_data)
                    import altair as alt
                    df_melt = df_chart.melt(id_vars='Docente', value_vars=['Puntuales', 'Tardanzas'],
                                             var_name='Tipo', value_name='Días')
                    chart = alt.Chart(df_melt).mark_bar().encode(
                        x=alt.X('Docente:N', sort='-y', title=''),
                        y=alt.Y('Días:Q', title='Días'),
                        color=alt.Color('Tipo:N', scale=alt.Scale(
                            domain=['Puntuales', 'Tardanzas'],
                            range=['#22c55e', '#f59e0b']
                        )),
                        xOffset='Tipo:N'
                    ).properties(height=300, title=f'Asistencia y Puntualidad — {mes_nombre} {anio_sel}')
                    st.altair_chart(chart, use_container_width=True)

                    # PDF
                    if st.button("📥 Descargar PDF", type="primary", key="dl_asist_doc_pdf"):
                        buf = io.BytesIO()
                        c_p = canvas.Canvas(buf, pagesize=landscape(A4))
                        wp, hp = landscape(A4)
                        # Encabezado oficial
                        c_p.setFillColor(colors.HexColor("#001e7c"))
                        c_p.rect(0, hp - 55, wp, 55, fill=1, stroke=0)
                        c_p.setFillColor(colors.white)
                        c_p.setFont("Helvetica-Bold", 16)
                        c_p.drawCentredString(wp/2, hp-22, "I.E.P. ALTERNATIVO YACHAY")
                        c_p.setFont("Helvetica", 10)
                        c_p.drawCentredString(wp/2, hp-38,
                                              f"REPORTE DE ASISTENCIA DOCENTES — {mes_nombre.upper()} {anio_sel}")
                        c_p.setFillColor(colors.HexColor("#FFD700"))
                        c_p.setFont("Helvetica", 8)
                        c_p.drawCentredString(wp/2, hp-50, "Chinchero, Cusco — Perú")
                        c_p.setFillColor(colors.black)
                        # Tabla
                        headers = ["N°", "DOCENTE", "DÍAS", "PUNTUALES", "TARDANZAS", "PUNTUALIDAD", "HORA PROM."]
                        rows = [headers]
                        for i, r in enumerate(data_tabla):
                            rows.append([str(i+1), r['Docente'], str(r['Días']),
                                        str(r['Puntuales']), str(r['Tardanzas']),
                                        r['Puntualidad'], r['Hora Prom.']])
                        t_doc = Table(rows, colWidths=[25, 200, 50, 65, 65, 70, 65])
                        t_doc.setStyle(TableStyle([
                            ('FONTNAME', (0,0), (-1,0), 'Helvetica-Bold'),
                            ('FONTSIZE', (0,0), (-1,-1), 7),
                            ('GRID', (0,0), (-1,-1), 0.5, colors.black),
                            ('BACKGROUND', (0,0), (-1,0), colors.HexColor("#001e7c")),
                            ('TEXTCOLOR', (0,0), (-1,0), colors.white),
                            ('ALIGN', (0,0), (-1,-1), 'CENTER'),
                            ('ALIGN', (1,1), (1,-1), 'LEFT'),
                            ('VALIGN', (0,0), (-1,-1), 'MIDDLE'),
                            ('ROWBACKGROUNDS', (0,1), (-1,-1), [colors.white, colors.Color(0.95,0.95,1.0)]),
                        ]))
                        tw2, th2 = t_doc.wrap(wp-40, hp-80)
                        t_doc.drawOn(c_p, 20, hp-70-th2)
                        # Pie
                        c_p.setFont("Helvetica", 6)
                        c_p.drawString(20, 12, f"Generado: {fecha_peru_str()} | Puntualidad: entrada antes de 8:05am")
                        c_p.drawRightString(wp-20, 12, "Sistema YACHAY PRO")
                        c_p.save()
                        buf.seek(0)
                        st.download_button("⬇️ PDF", buf, f"Asistencia_Docentes_{mes_nombre}.pdf",
                                           "application/pdf", key="dl_doc_pdf2")
                else:
                    st.info("Sin datos para este mes.")

            elif modo == "✏️ Editar Registros":
                # ── Editar registros de docentes ─────────────────────────
                st.markdown("### ✏️ Editar Registro de Asistencia — Docente")
                st.caption("Para docentes con actividades especiales que justifican la hora de llegada")

                docente_edit = st.selectbox("DOCENTE Docente:",
                                            sorted(docentes_asist.keys()),
                                            key="edit_doc_sel")
                fecha_edit = st.date_input("📅 Fecha:", value=hora_peru().date(),
                                            key="edit_fecha")
                fecha_str_e = fecha_edit.strftime('%Y-%m-%d')

                reg_actual = docentes_asist.get(docente_edit, {}).get(fecha_str_e, {})
                st.info(f"Registro actual: Entrada: **{reg_actual.get('entrada', '—')}** | "
                        f"Salida: **{reg_actual.get('salida', '—')}** | "
                        f"Tardanza: **{'Sí' if reg_actual.get('tardanza') else 'No'}**")

                col_e1, col_e2, col_e3 = st.columns(3)
                with col_e1:
                    nueva_entrada = st.text_input("🕒 Entrada:", value=reg_actual.get('entrada', ''),
                                                   placeholder="07:45", key="edit_ent")
                with col_e2:
                    nueva_salida = st.text_input("🕒 Salida:", value=reg_actual.get('salida', ''),
                                                  placeholder="13:30", key="edit_sal")
                with col_e3:
                    quitar_tard = st.checkbox("✅ Marcar como PUNTUAL (quitar tardanza)",
                                              key="edit_puntual")

                motivo = st.text_input("📝 Motivo de la modificación:",
                                        placeholder="Ej: Actividad extracurricular autorizada",
                                        key="edit_motivo")

                if st.button("💾 GUARDAR CAMBIOS", type="primary", key="btn_edit_doc"):
                    if motivo:
                        try:
                            asist_data = {}
                            if Path(ARCHIVO_ASISTENCIAS).exists():
                                with open(ARCHIVO_ASISTENCIAS, 'r', encoding='utf-8') as f:
                                    asist_data = json.load(f)
                            # Buscar DNI del docente
                            dni_edit = None
                            if fecha_str_e in asist_data:
                                for dk, dv in asist_data[fecha_str_e].items():
                                    if dv.get('nombre', '').strip().upper() == docente_edit.strip().upper():
                                        dni_edit = dk
                                        break
                            if dni_edit and fecha_str_e in asist_data and dni_edit in asist_data[fecha_str_e]:
                                if nueva_entrada:
                                    asist_data[fecha_str_e][dni_edit]['entrada'] = nueva_entrada
                                if nueva_salida:
                                    asist_data[fecha_str_e][dni_edit]['salida'] = nueva_salida
                                if quitar_tard:
                                    asist_data[fecha_str_e][dni_edit]['tardanza'] = ''
                                    if not asist_data[fecha_str_e][dni_edit].get('entrada'):
                                        asist_data[fecha_str_e][dni_edit]['entrada'] = nueva_entrada or '07:30'
                                asist_data[fecha_str_e][dni_edit]['modificado'] = motivo
                                asist_data[fecha_str_e][dni_edit]['modificado_por'] = st.session_state.get('usuario_actual', '')
                                with open(ARCHIVO_ASISTENCIAS, 'w', encoding='utf-8') as f:
                                    json.dump(asist_data, f, indent=2, ensure_ascii=False)
                                st.success(f"✅ Registro de {docente_edit} modificado — {fecha_str_e}")
                                st.rerun()
                            else:
                                st.warning("No se encontró registro para esa fecha. Puede crear uno nuevo.")
                                # Crear registro
                                if fecha_str_e not in asist_data:
                                    asist_data[fecha_str_e] = {}
                                # Buscar DNI en docentes
                                df_doc_e = BaseDatos.cargar_docentes()
                                if not df_doc_e.empty:
                                    fd = df_doc_e[df_doc_e['Nombre'].astype(str).str.upper() == docente_edit.upper()]
                                    if not fd.empty:
                                        dn = str(fd.iloc[0].get('DNI', f'edit_{docente_edit[:10]}'))
                                        asist_data[fecha_str_e][dn] = {
                                            'nombre': docente_edit, 'entrada': nueva_entrada or '07:30',
                                            'salida': nueva_salida, 'tardanza': '' if quitar_tard else '',
                                            'es_docente': True, 'modificado': motivo,
                                            'entrada_tarde': '', 'salida_tarde': '',
                                        }
                                        with open(ARCHIVO_ASISTENCIAS, 'w', encoding='utf-8') as f:
                                            json.dump(asist_data, f, indent=2, ensure_ascii=False)
                                        st.success(f"✅ Registro creado para {docente_edit} — {fecha_str_e}")
                                        st.rerun()
                        except Exception as e:
                            st.error(f"❌ Error: {e}")
                    else:
                        st.warning("⚠️ Debe ingresar el motivo de la modificación.")

            elif modo == "⏱️ Horas Sec/PreU":
                # ── Horas de trabajo Sec/PreU ────────────────────────────
                st.markdown("### ⏱️ Control de Horas — Docentes Secundaria / PreUniversitario")
                st.caption("Docentes que trabajan por horas: registro de horas por día, semana y mes")

                mes_h = st.selectbox("📆 Mes:", meses_esc,
                                      format_func=lambda x: x[1],
                                      key="horas_mes")
                mes_num_h = mes_h[0]
                mes_nombre_h = mes_h[1]
                anio_h = hora_peru().year

                # Calcular horas por docente
                horas_data = []
                for nm in sorted(docentes_asist.keys()):
                    horas_dia = {}
                    total_horas_mes = 0.0
                    for fecha_str, reg in docentes_asist[nm].items():
                        try:
                            fd = datetime.strptime(fecha_str, '%Y-%m-%d').date()
                            if fd.month == mes_num_h and fd.year == anio_h:
                                ent = reg.get('entrada', '')
                                sal = reg.get('salida', '')
                                horas_d = 0.0
                                if ent and sal:
                                    try:
                                        h1, m1 = ent.split(':')[:2]
                                        h2, m2 = sal.split(':')[:2]
                                        min1 = int(h1) * 60 + int(m1)
                                        min2 = int(h2) * 60 + int(m2)
                                        horas_d = max(0, (min2 - min1) / 60)
                                    except Exception:
                                        pass
                                # Sumar turno tarde si existe
                                ent_t = reg.get('entrada_tarde', '')
                                sal_t = reg.get('salida_tarde', '')
                                if ent_t and sal_t:
                                    try:
                                        h1t, m1t = ent_t.split(':')[:2]
                                        h2t, m2t = sal_t.split(':')[:2]
                                        min1t = int(h1t) * 60 + int(m1t)
                                        min2t = int(h2t) * 60 + int(m2t)
                                        horas_d += max(0, (min2t - min1t) / 60)
                                    except Exception:
                                        pass
                                horas_dia[fecha_str] = round(horas_d, 1)
                                total_horas_mes += horas_d
                        except Exception:
                            pass

                    if horas_dia:
                        # Calcular por semana
                        semanas_h = _semanas_del_mes(mes_num_h, anio_h)
                        horas_por_sem = []
                        for sem_n, lun_s, vie_s in semanas_h:
                            h_sem = 0.0
                            for d in range(5):
                                dia_s = lun_s + timedelta(days=d)
                                h_sem += horas_dia.get(dia_s.strftime('%Y-%m-%d'), 0.0)
                            horas_por_sem.append(round(h_sem, 1))

                        horas_data.append({
                            'Docente': nm,
                            'Días': len(horas_dia),
                            'Horas Total': round(total_horas_mes, 1),
                            'Prom/Día': round(total_horas_mes / max(len(horas_dia), 1), 1),
                            **{f'Sem {s[0]}': h for s, h in zip(semanas_h, horas_por_sem)},
                        })

                if horas_data:
                    st.markdown(f"### {mes_nombre_h} {anio_h}")
                    df_h = pd.DataFrame(horas_data).sort_values('Horas Total', ascending=False)
                    st.dataframe(df_h, use_container_width=True, hide_index=True)

                    # Métricas
                    ch1, ch2, ch3 = st.columns(3)
                    ch1.metric("DOCENTE Docentes", len(horas_data))
                    ch2.metric("⏱️ Prom. horas/mes", f"{sum(r['Horas Total'] for r in horas_data)/max(len(horas_data),1):.1f}h")
                    ch3.metric("⏱️ Total horas", f"{sum(r['Horas Total'] for r in horas_data):.0f}h")

                    # Gráfico
                    import altair as alt
                    chart_h = []
                    for r in horas_data:
                        nm_c = r['Docente'].split()[-1] if ' ' in r['Docente'] else r['Docente']
                        if len(nm_c) > 12:
                            nm_c = nm_c[:10] + ".."
                        chart_h.append({'Docente': nm_c, 'Horas': r['Horas Total']})
                    df_ch = pd.DataFrame(chart_h)
                    bar = alt.Chart(df_ch).mark_bar(color='#3b82f6').encode(
                        x=alt.X('Docente:N', sort='-y', title=''),
                        y=alt.Y('Horas:Q', title='Horas trabajadas'),
                    ).properties(height=280, title=f'Horas Trabajadas — {mes_nombre_h} {anio_h}')
                    st.altair_chart(bar, use_container_width=True)
                else:
                    st.info("Sin datos de horas para este mes. Se necesita entrada Y salida registradas.")

            elif modo == "📱 WhatsApp Docentes":
                # ── WhatsApp Docentes ──────────────────────────────────────
                st.markdown("### 📱 Enviar WhatsApp a Docentes")
                st.caption("Enviar mensajes de asistencia o comunicados a docentes")

                if not df_doc_list.empty and 'Celular' in df_doc_list.columns:
                    msg_tipo = st.selectbox("Tipo de mensaje:", [
                        "Recordatorio de asistencia",
                        "Felicitación por puntualidad",
                        "Comunicado general",
                        "Mensaje personalizado"
                    ], key="wa_doc_tipo")

                    msg_custom = ""
                    if msg_tipo == "Mensaje personalizado":
                        msg_custom = st.text_area("Mensaje:", placeholder="Escriba su mensaje...",
                                                   key="wa_doc_msg")

                    st.markdown("---")
                    enviados_count = 0
                    for _, row in df_doc_list.iterrows():
                        nm = str(row.get('Nombre', '')).strip()
                        cel = str(row.get('Celular', '')).strip()
                        if cel and cel not in ('nan', 'None', ''):
                            if '.' in cel:
                                cel = cel.split('.')[0]
                            cel = ''.join(c for c in cel if c.isdigit())
                            if len(cel) >= 7:
                                if msg_tipo == "Recordatorio de asistencia":
                                    msg = (f"Buenos días Prof. {nm}. Le recordamos registrar "
                                           f"su asistencia en el sistema YACHAY. Gracias.")
                                elif msg_tipo == "Felicitación por puntualidad":
                                    msg = (f"Estimado(a) Prof. {nm}, felicitamos su puntualidad "
                                           f"y compromiso con la I.E.P. YACHAY. ¡Siga así!")
                                elif msg_tipo == "Comunicado general":
                                    msg = (f"Estimado(a) Prof. {nm}, se le comunica que "
                                           f"hay una reunión de coordinación. "
                                           f"Por favor revise el sistema YACHAY. Gracias.")
                                else:
                                    msg = f"Prof. {nm}: {msg_custom}" if msg_custom else f"Mensaje para {nm}"

                                link = generar_link_whatsapp(cel, msg)
                                st.markdown(
                                    f'<a href="{link}" target="_blank" class="wa-btn">'
                                    f'📱 DOCENTE {nm} → {cel}</a>',
                                    unsafe_allow_html=True)
                                enviados_count += 1
                    if enviados_count == 0:
                        st.warning("No hay docentes con celular registrado.")
                    else:
                        st.success(f"📱 {enviados_count} docentes con WhatsApp disponible")
                else:
                    st.warning("No hay docentes registrados o sin campo Celular.")

    if subtab == "📋 Asistencia Mensual":
        st.markdown("### 📋 Reporte Mensual de Asistencia por Grado")
        if gs:
            c1, c2, c3 = st.columns(3)
            with c1:
                grado_rep = st.selectbox("Grado:", GRADOS_OPCIONES, key="rep_gr")
            with c2:
                mes_rep = st.selectbox("Mes:", list(range(1, 13)),
                                        format_func=lambda x: ['', 'Enero', 'Febrero',
                                        'Marzo', 'Abril', 'Mayo', 'Junio', 'Julio',
                                        'Agosto', 'Septiembre', 'Octubre', 'Noviembre',
                                        'Diciembre'][x], key="rep_mes")
            with c3:
                anio_rep = st.number_input("Año:", value=hora_peru().year,
                                            key="rep_anio")

            if st.button("📊 Generar Reporte", type="primary", key="btn_rep_asist"):
                datos = gs.reporte_asistencia_mensual(grado_rep, mes_rep, int(anio_rep))
                if datos:
                    st.success(f"✅ {len(datos)} estudiantes encontrados")
                    for nombre, info_a in sorted(datos.items()):
                        total = len(info_a.get('fechas', {}))
                        st.write(f"**{nombre}** — {total} días asistidos")
                    pdf = generar_reporte_asistencia_mensual_pdf(
                        datos, grado_rep, mes_rep, int(anio_rep), config)
                    st.download_button("📥 PDF Asistencia Mensual", pdf,
                                       f"Asistencia_{grado_rep}_{mes_rep}.pdf",
                                       "application/pdf", key="dl_rep_asist")
                else:
                    st.warning("No hay datos para este período")
        else:
            st.warning("⚠️ Conecta Google Sheets")

    elif subtab == "📊 Reporte Integral":
        st.markdown("### 📊 Reporte Integral del Estudiante")
        st.markdown("*Incluye: Notas + Asistencia + Semáforo + Recomendaciones*")

        rc1, rc2 = st.columns(2)
        with rc1:
            grado_ri = st.selectbox("Grado:", GRADOS_OPCIONES, key="ri_grado")
        with rc2:
            modo_ri = st.radio("Generar:", ["Un estudiante", "Todo el grado"],
                               horizontal=True, key="ri_modo")

        dg = BaseDatos.obtener_estudiantes_grado(grado_ri)
        if dg.empty:
            st.warning("Sin estudiantes en este grado")
            return

        if modo_ri == "Un estudiante":
            opciones = [f"{r['Nombre']} — {r['DNI']}" for _, r in dg.iterrows()]
            sel = st.selectbox("Estudiante:", opciones, key="ri_est")
            if sel:
                dni_ri = sel.split(" — ")[-1].strip()
                nombre_ri = sel.split(" — ")[0].strip()
                
                # EDITAR NOTAS (Solo Director/Admin/Promotor)
                if st.session_state.rol in ['admin', 'directivo']:
                    st.markdown("---")
                    with st.expander("✏️ Editar Notas del Estudiante", expanded=False):
                        st.caption("🔐 Solo Director, Administrador y Promotor")
                        
                        notas_edit = []
                        if gs:
                            try:
                                ws = gs._get_hoja('config')
                                if ws:
                                    data = ws.get_all_records()
                                    for d in data:
                                        clave = str(d.get('clave', ''))
                                        if clave.startswith(f'nota_{dni_ri}'):
                                            try:
                                                nota_data = json.loads(d.get('valor', '{}'))
                                                nota_data['_clave'] = clave
                                                notas_edit.append(nota_data)
                                            except Exception:
                                                pass
                            except Exception:
                                pass
                        
                        if notas_edit:
                            for idx, nota in enumerate(notas_edit):
                                col1, col2, col3 = st.columns([3, 1, 1])
                                with col1:
                                    st.text(f"{nota.get('area', 'N/A')} - {nota.get('bimestre', 'N/A')}")
                                with col2:
                                    nueva = st.number_input("Nota:", 0.0, 20.0, 
                                                          float(nota.get('nota', 0)), 0.5,
                                                          key=f"ne_{idx}_{dni_ri}")
                                with col3:
                                    if st.button("💾", key=f"sv_{idx}_{dni_ri}", type="primary"):
                                        if gs and '_clave' in nota:
                                            try:
                                                nota['nota'] = nueva
                                                nota['literal'] = nota_a_letra(nueva)
                                                ws = gs._get_hoja('config')
                                                if ws:
                                                    all_data = ws.get_all_records()
                                                    for row_idx, row in enumerate(all_data, start=2):
                                                        if str(row.get('clave', '')) == nota['_clave']:
                                                            nota_copy = nota.copy()
                                                            nota_copy.pop('_clave', None)
                                                            ws.update_cell(row_idx, 2, 
                                                                         json.dumps(nota_copy, ensure_ascii=False))
                                                            break
                                                st.success(f"✅ Actualizado: {nueva}/20")
                                                time.sleep(1)
                                                st.rerun()
                                            except Exception as e:
                                                st.error(f"Error: {str(e)[:50]}")
                        else:
                            st.info("Sin notas para editar")
                    st.markdown("---")
        else:
            dni_ri = None
            nombre_ri = None

        if st.button("📥 GENERAR REPORTE INTEGRAL", type="primary",
                     use_container_width=True, key="btn_ri"):
            with st.spinner("Generando reporte..."):
                if modo_ri == "Un estudiante" and dni_ri:
                    # Cargar notas del estudiante
                    notas_est = []
                    asist_est = {}

                    # Cargar asistencia LOCAL primero (fuente principal)
                    try:
                        if Path(ARCHIVO_ASISTENCIAS).exists():
                            with open(ARCHIVO_ASISTENCIAS, 'r', encoding='utf-8') as f:
                                todas_asis = json.load(f)
                            for fecha_a, registros in todas_asis.items():
                                if str(dni_ri) in registros:
                                    asist_est[fecha_a] = registros[str(dni_ri)]
                    except Exception:
                        pass

                    # SIEMPRE complementar con GS (puede tener datos que local perdió)
                    if gs:
                        try:
                            asist_gs = gs.historial_asistencia_estudiante(dni_ri)
                            if asist_gs:
                                for fecha_g, datos_g in asist_gs.items():
                                    if fecha_g not in asist_est:
                                        asist_est[fecha_g] = datos_g
                                    else:
                                        # Completar campos vacíos
                                        if not asist_est[fecha_g].get('entrada') and datos_g.get('entrada'):
                                            asist_est[fecha_g]['entrada'] = datos_g['entrada']
                                        if not asist_est[fecha_g].get('salida') and datos_g.get('salida'):
                                            asist_est[fecha_g]['salida'] = datos_g['salida']
                        except Exception:
                            pass

                    if gs:
                        try:
                            ws = gs._get_hoja('config')
                            if ws:
                                data = ws.get_all_records()
                                for d in data:
                                    clave = str(d.get('clave', ''))
                                    if clave.startswith(f'nota_{dni_ri}'):
                                        try:
                                            notas_est.append(json.loads(d.get('valor', '{}')))
                                        except Exception:
                                            pass
                        except Exception:
                            pass

                    # También cargar de resultados de examen
                    _anio_rep = str(config.get('anio', 2026))
                    all_res = BaseDatos.cargar_todos_resultados()
                    for r in all_res:
                        if str(r.get('dni', '')) == str(dni_ri):
                            _fecha_r = str(r.get('fecha', ''))
                            if not _fecha_r.startswith(_anio_rep):
                                continue
                            for area in r.get('areas', []):
                                notas_est.append({
                                    'area': area['nombre'],
                                    'nota': area['nota'],
                                    'literal': nota_a_letra(area['nota']),
                                    'bimestre': r.get('titulo', 'Evaluación'),
                                    'fecha': r.get('fecha', ''),
                                    'tipo': 'examen'
                                })

                    # Cargar notas del historial de evaluaciones (Registrar Notas)
                    hist_eval = _cargar_historial_evaluaciones()
                    for clave_h, ev_h in hist_eval.items():
                        _fecha_h = str(ev_h.get('fecha', ''))
                        if not _fecha_h.startswith(_anio_rep):
                            continue
                        for fila_h in ev_h.get('ranking', []):
                            if str(fila_h.get('DNI', '')) == str(dni_ri):
                                areas_h = ev_h.get('areas', [])
                                areas_nombres_h = [a['nombre'] for a in areas_h] if areas_h and isinstance(areas_h[0], dict) else list(areas_h)
                                for a_n in areas_nombres_h:
                                    nota_v = fila_h.get(a_n, 0)
                                    if nota_v and float(nota_v) > 0:
                                        notas_est.append({
                                            'area': a_n,
                                            'nota': float(nota_v),
                                            'literal': nota_a_letra(float(nota_v)),
                                            'bimestre': ev_h.get('periodo', ''),
                                            'fecha': ev_h.get('fecha', ''),
                                            'titulo': ev_h.get('titulo', ''),
                                            'tipo': 'registro_notas'
                                        })

                    al = BaseDatos.buscar_por_dni(dni_ri)
                    grado_est = str(al.get('Grado', grado_ri)) if al else grado_ri

                    pdf = generar_reporte_integral_pdf(
                        nombre_ri, dni_ri, grado_est, notas_est, asist_est, config)

                    # ── Calcular afinidad para PDF vocacional ──
                    prom_area_ri = {}
                    for n_ri_v in notas_est:
                        a_ri_v = str(n_ri_v.get("area",""))
                        v_ri_v = float(n_ri_v.get("nota",0))
                        if a_ri_v:
                            prom_area_ri.setdefault(a_ri_v,[]).append(v_ri_v)
                    prom_area_ri = {k: round(sum(v)/len(v),1) for k,v in prom_area_ri.items()}
                    prom_gen_ri = round(sum(prom_area_ri.values())/len(prom_area_ri),1) if prom_area_ri else 0
                    lit_gen_ri = nota_a_letra(prom_gen_ri) if prom_gen_ri>0 else "C"
                    afinidad_ri_ind = _calcular_afinidad_academica(prom_area_ri)

                    pdf_voc = generar_pdf_orientacion_vocacional(
                        nombre_ri, dni_ri, grado_est,
                        prom_gen_ri, lit_gen_ri, prom_area_ri, afinidad_ri_ind, config)

                    col_dl1, col_dl2 = st.columns(2)
                    with col_dl1:
                        st.download_button("⬇️ Reporte Integral PDF", pdf,
                                           f"Reporte_{nombre_ri.replace(' ','_')}.pdf",
                                           "application/pdf", key="dl_ri")
                    with col_dl2:
                        st.download_button("🎓 Orientación Vocacional PDF", pdf_voc,
                                           f"Vocacional_{nombre_ri.replace(' ','_')}.pdf",
                                           "application/pdf", key="dl_ri_voc")
                    st.success(f"✅ Reporte de {nombre_ri} generado — Grupo UNSAAC: {UNSAAC_GRUPOS.get(afinidad_ri_ind.get('grupo_principal','A'),{}).get('nombre','—')}")

                else:
                    # Todo el grado - un PDF multi-página
                    buf_all = io.BytesIO()
                    c_pdf = canvas.Canvas(buf_all, pagesize=A4)
                    w_page, h_page = A4

                    for _, row in dg.iterrows():
                        n_est = str(row.get('Nombre', ''))
                        d_est = str(row.get('DNI', ''))

                        # Cargar notas
                        notas_est = []
                        if gs:
                            try:
                                ws = gs._get_hoja('config')
                                if ws:
                                    data = ws.get_all_records()
                                    for d in data:
                                        clave = str(d.get('clave', ''))
                                        if clave.startswith(f'nota_{d_est}'):
                                            try:
                                                notas_est.append(json.loads(d.get('valor', '{}')))
                                            except Exception:
                                                pass
                            except Exception:
                                pass

                        # De exámenes también
                        _anio_rep_g = str(config.get('anio', 2026))
                        all_res = BaseDatos.cargar_todos_resultados()
                        for r in all_res:
                            if str(r.get('dni', '')) == d_est:
                                if not str(r.get('fecha', '')).startswith(_anio_rep_g):
                                    continue
                                for area in r.get('areas', []):
                                    notas_est.append({
                                        'area': area['nombre'],
                                        'nota': area['nota'],
                                        'fecha': r.get('fecha', ''),
                                    })

                        # De historial de evaluaciones (Registrar Notas)
                        hist_eval_g = _cargar_historial_evaluaciones()
                        for clave_hg, ev_hg in hist_eval_g.items():
                            if not str(ev_hg.get('fecha', '')).startswith(_anio_rep_g):
                                continue
                            for fila_hg in ev_hg.get('ranking', []):
                                if str(fila_hg.get('DNI', '')) == str(d_est):
                                    areas_hg = ev_hg.get('areas', [])
                                    areas_noms_hg = [a['nombre'] for a in areas_hg] if areas_hg and isinstance(areas_hg[0], dict) else list(areas_hg)
                                    for a_ng in areas_noms_hg:
                                        nota_vg = fila_hg.get(a_ng, 0)
                                        if nota_vg and float(nota_vg) > 0:
                                            notas_est.append({
                                                'area': a_ng,
                                                'nota': float(nota_vg),
                                                'fecha': ev_hg.get('fecha', ''),
                                            })

                        # Página del estudiante
                        c_pdf.setFont("Helvetica-Bold", 14)
                        c_pdf.drawCentredString(w_page/2, h_page-40, f"REPORTE: {n_est}")
                        c_pdf.setFont("Helvetica", 10)
                        y = h_page-65
                        c_pdf.drawString(50, y, f"DNI: {d_est} | Grado: {grado_ri}")
                        y -= 25

                        if notas_est:
                            for n in notas_est:
                                nota_v = float(n.get('nota', 0))
                                lit = nota_a_letra(nota_v)
                                c_pdf.drawString(60, y,
                                    f"• {n.get('area', '')}: {nota_v}/20 ({lit}) — {n.get('fecha', '')}")
                                y -= 14
                                if y < 80:
                                    break

                            # Promedio
                            promedios = [float(n.get('nota', 0)) for n in notas_est if float(n.get('nota', 0)) > 0]
                            if promedios:
                                prom = round(sum(promedios)/len(promedios), 1)
                                lit_p = nota_a_letra(prom)
                                y -= 10
                                c_pdf.setFont("Helvetica-Bold", 12)
                                c_pdf.drawString(60, y, f"PROMEDIO: {prom}/20 ({lit_p})")
                        else:
                            c_pdf.drawString(60, y, "Sin calificaciones registradas.")

                        c_pdf.showPage()

                    c_pdf.save()
                    buf_all.seek(0)
                    st.download_button("⬇️ Reportes Todo el Grado", buf_all,
                                       f"Reportes_{grado_ri}.pdf",
                                       "application/pdf", key="dl_ri_all")
                    st.success(f"✅ Reportes de {len(dg)} estudiantes generados")

    elif subtab == "📄 Reporte ZipGrade":
        st.markdown("### 📄 Reporte estilo ZipGrade")
        usuario = st.session_state.get('usuario_actual', '')
        resultados = BaseDatos.cargar_resultados_examen(usuario)
        if st.session_state.rol in ['admin', 'directivo']:
            resultados = BaseDatos.cargar_todos_resultados()

        if resultados:
            opciones_eval = [
                f"{r.get('nombre', '?')} — {r.get('fecha', '')}"
                for r in resultados
            ]
            sel_eval = st.selectbox("Evaluación:", opciones_eval, key="zg_eval")
            idx_eval = opciones_eval.index(sel_eval)
            eval_sel = resultados[idx_eval]

            # Mostrar detalles
            for area in eval_sel.get('areas', []):
                nota = area.get('nota', 0)
                lit = nota_a_letra(nota)
                col = color_semaforo(lit)
                st.markdown(f"**{area['nombre']}:** <span style='color:{col};'>{nota}/20 ({lit})</span>",
                           unsafe_allow_html=True)

            if st.button("📥 PDF ZipGrade", type="primary", key="btn_zg"):
                pdf = generar_reporte_examen_zipgrade(eval_sel, config)
                st.download_button("⬇️ PDF", pdf,
                                   f"ZipGrade_{sel_eval[:20]}.pdf",
                                   "application/pdf", key="dl_zg")
        else:
            st.info("Sin evaluaciones. Califica exámenes primero.")

    elif subtab == "📁 Fichas Docentes":
        st.markdown("### 📁 Fichas de Trabajo — Registro por Docente")
        st.caption("Vista consolidada de todas las fichas subidas por los docentes")

        fichas = _cargar_fichas_registro()
        if not fichas:
            st.info("📭 No hay fichas registradas aún. Los docentes pueden subirlas desde 'Registrar Ficha'.")
            return

        # ── Filtros ──
        fc1, fc2, fc3, fc4 = st.columns(4)
        with fc1:
            grados_f = sorted(set(f.get('grado', '') for f in fichas if f.get('grado')))
            filtro_grado = st.selectbox("🎓 Grado:", ["Todos"] + grados_f, key="fichas_f_grado")
        with fc2:
            meses_f = sorted(set(f.get('mes', '') for f in fichas if f.get('mes')))
            filtro_mes = st.selectbox("📅 Mes:", ["Todos"] + meses_f, key="fichas_f_mes")
        with fc3:
            semanas_f = sorted(set(str(f.get('semana', '')) for f in fichas if f.get('semana')))
            filtro_semana = st.selectbox("📆 Semana:", ["Todas"] + semanas_f, key="fichas_f_sem")
        with fc4:
            docentes_f = sorted(set(f.get('docente_nombre', f.get('docente', ''))
                                    for f in fichas if f.get('docente')))
            filtro_doc = st.selectbox("DOCENTE Docente:", ["Todos"] + docentes_f, key="fichas_f_doc")

        # ── Aplicar filtros ──
        fichas_filtradas = fichas.copy()
        if filtro_grado != "Todos":
            fichas_filtradas = [f for f in fichas_filtradas if f.get('grado') == filtro_grado]
        if filtro_mes != "Todos":
            fichas_filtradas = [f for f in fichas_filtradas if f.get('mes') == filtro_mes]
        if filtro_semana != "Todas":
            fichas_filtradas = [f for f in fichas_filtradas if str(f.get('semana')) == filtro_semana]
        if filtro_doc != "Todos":
            fichas_filtradas = [f for f in fichas_filtradas
                                if f.get('docente_nombre') == filtro_doc or f.get('docente') == filtro_doc]

        # ── Métricas ──
        mc1, mc2, mc3, mc4 = st.columns(4)
        with mc1:
            st.metric("📄 Total fichas", len(fichas_filtradas))
        with mc2:
            docs_unicos = len(set(f.get('docente', '') for f in fichas_filtradas))
            st.metric("DOCENTE Docentes", docs_unicos)
        with mc3:
            grados_unicos = len(set(f.get('grado', '') for f in fichas_filtradas))
            st.metric("🎓 Grados", grados_unicos)
        with mc4:
            areas_unicas = len(set(f.get('area', '') for f in fichas_filtradas))
            st.metric("📚 Áreas", areas_unicas)

        st.markdown("---")

        # ── Tabla de fichas ──
        if fichas_filtradas:
            for ficha in sorted(fichas_filtradas,
                                key=lambda x: x.get('fecha_subida', ''), reverse=True):
                doc_nombre = ficha.get('docente_nombre', ficha.get('docente', ''))
                titulo_f = ficha.get('titulo', 'Sin título')
                area_f = ficha.get('area', '')
                grado_f = ficha.get('grado', '')
                sem_f = ficha.get('semana', '')
                mes_f = ficha.get('mes', '')
                fecha_f = ficha.get('fecha_subida', '')
                tipo_f = ficha.get('tipo', '')
                archivo_f = ficha.get('archivo', '')

                with st.expander(f"📄 **{titulo_f}** — {area_f} | {grado_f} | Sem {sem_f} | {mes_f}"):
                    ec1, ec2 = st.columns([3, 1])
                    with ec1:
                        st.markdown(f"**Docente:** {doc_nombre}")
                        st.markdown(f"**Área:** {area_f} | **Grado:** {grado_f} | "
                                    f"**Semana:** {sem_f} | **Mes:** {mes_f}")
                        st.caption(f"📅 Subido: {fecha_f} | Tipo: {tipo_f} | Archivo: {archivo_f}")
                    with ec2:
                        # Intentar ofrecer descarga si el archivo existe localmente
                        ruta_ficha = Path("fichas") / archivo_f if archivo_f else None
                        if ruta_ficha and ruta_ficha.exists():
                            with open(ruta_ficha, 'rb') as ff:
                                st.download_button("⬇️ Descargar", ff.read(),
                                                   archivo_f, "application/pdf",
                                                   key=f"dl_rep_{ficha.get('id', '')}")
                        else:
                            st.caption("📁 Solo en servidor")
        else:
            st.info("No hay fichas que coincidan con los filtros seleccionados.")

    elif subtab == "🎓 Orientación Vocacional UNSAAC":
        _tab_test_vocacional_ui(config)


