def _guardar_archivo_binario_gs(nombre_clave, filepath):
    """Guarda un archivo binario (imagen, mp3) como base64 en Google Sheets hoja config"""
    try:
        if not Path(filepath).exists():
            return False
        import base64 as b64mod
        with open(filepath, "rb") as fbin:
            data_b64 = b64mod.b64encode(fbin.read()).decode('utf-8')
        gs = _gs()
        if not gs:
            return False
        ws = gs._get_hoja('config')
        if not ws:
            return False
        all_vals = ws.get_all_values()
        found = False
        for idx, row in enumerate(all_vals):
            if row and row[0] == nombre_clave:
                ws.update_cell(idx + 1, 2, data_b64)
                found = True
                break
        if not found:
            ws.append_row([nombre_clave, data_b64])
        return True
    except Exception:
        return False

def _restaurar_archivo_binario_gs(nombre_clave, filepath):
    """Restaura un archivo binario desde base64 en Google Sheets si no existe localmente"""
    try:
        if Path(filepath).exists():
            return True  # ya existe, no sobreescribir
        import base64 as b64mod
        gs = _gs()
        if not gs:
            return False
        ws = gs._get_hoja('config')
        if not ws:
            return False
        all_vals = ws.get_all_values()
        for row in all_vals:
            if row and row[0] == nombre_clave and len(row) > 1 and row[1]:
                data = b64mod.b64decode(row[1])
                with open(filepath, "wb") as fbin:
                    fbin.write(data)
                return True
        return False
    except Exception:
        return False

# ================================================================
# GOOGLE DRIVE — helpers para MP3 de Pausa Activa
# Guarda los archivos directamente en Drive (no como base64 en Sheets)
# Evita el lag y el límite de 50k chars por celda de GSheets
# ================================================================

# ================================================================
# GOOGLE DRIVE — token OAuth2 via requests (sin google-api-python-client)
# Usa directamente st.secrets["gcp_service_account"] que ya está configurado
# ================================================================

def _drive_get_token():
    """Obtiene un access token de Drive usando JWT firmado con la llave privada del service account."""
    try:
        import time, json as _j, base64 as _b64, hashlib, hmac
        from urllib import request as _urllib_req, parse as _urllib_parse

        creds = dict(st.secrets["gcp_service_account"])
        private_key_pem = creds["private_key"]
        client_email    = creds["client_email"]
        token_uri       = creds.get("token_uri", "https://oauth2.googleapis.com/token")

        # Construir JWT
        now = int(time.time())
        header  = _b64.urlsafe_b64encode(_j.dumps({"alg":"RS256","typ":"JWT"}).encode()).rstrip(b"=")
        payload = _b64.urlsafe_b64encode(_j.dumps({
            "iss": client_email,
            "scope": "https://www.googleapis.com/auth/drive",
            "aud": token_uri,
            "iat": now,
            "exp": now + 3600
        }).encode()).rstrip(b"=")
        signing_input = header + b"." + payload

        # Firmar con RSA usando cryptography (disponible en streamlit cloud)
        try:
            from cryptography.hazmat.primitives import hashes, serialization
            from cryptography.hazmat.primitives.asymmetric import padding
            private_key_obj = serialization.load_pem_private_key(private_key_pem.encode(), password=None)
            signature = private_key_obj.sign(signing_input, padding.PKCS1v15(), hashes.SHA256())
            sig_b64 = _b64.urlsafe_b64encode(signature).rstrip(b"=")
        except Exception as _e_cry:
            st.session_state["_drive_error"] = f"Error firmando JWT: {_e_cry}"
            return None

        jwt_token = (signing_input + b"." + sig_b64).decode()

        # Intercambiar JWT por access token
        data = _urllib_parse.urlencode({
            "grant_type": "urn:ietf:params:oauth:grant-type:jwt-bearer",
            "assertion": jwt_token
        }).encode()
        req = _urllib_req.Request(token_uri, data=data,
                                   headers={"Content-Type": "application/x-www-form-urlencoded"})
        with _urllib_req.urlopen(req, timeout=15) as resp:
            resp_data = _j.loads(resp.read())
        token = resp_data.get("access_token")
        if not token:
            st.session_state["_drive_error"] = f"Sin access_token: {resp_data}"
        return token
    except Exception as _e:
        st.session_state["_drive_error"] = f"_drive_get_token: {_e}"
        return None


def _drive_service():
    """Retorna un objeto liviano para llamadas a Drive API via requests."""
    token = _drive_get_token()
    if not token:
        return None

    class _DriveLite:
        def __init__(self, tok):
            self._tok = tok
            self._headers = {"Authorization": f"Bearer {tok}"}

        def list_files(self, q, fields="files(id,name)", page_size=5):
            import urllib.request as _r, urllib.parse as _p, json as _j
            params = _p.urlencode({"q": q, "fields": fields, "pageSize": page_size,
                                   "supportsAllDrives": "true",
                                   "includeItemsFromAllDrives": "true"})
            req = _r.Request(f"https://www.googleapis.com/drive/v3/files?{params}",
                             headers=self._headers)
            with _r.urlopen(req, timeout=15) as resp:
                return _j.loads(resp.read()).get("files", [])

        def create_folder(self, name, parent_id=None):
            import urllib.request as _r, json as _j
            meta = {"name": name, "mimeType": "application/vnd.google-apps.folder"}
            if parent_id:
                meta["parents"] = [parent_id]
            body = _j.dumps(meta).encode()
            req = _r.Request(
                "https://www.googleapis.com/drive/v3/files"
                "?fields=id&supportsAllDrives=true",
                data=body,
                headers={**self._headers, "Content-Type": "application/json"})
            with _r.urlopen(req, timeout=15) as resp:
                return _j.loads(resp.read()).get("id")

        def upload(self, fname, data_bytes, mime, parent_id=None):
            """Sube archivo usando multipart upload con supportsAllDrives."""
            import urllib.request as _r, json as _j
            meta = {"name": fname}
            if parent_id:
                meta["parents"] = [parent_id]
            meta_bytes = _j.dumps(meta).encode()
            boundary = b"yachay_boundary_1234"
            body = (b"--" + boundary + b"\r\nContent-Type: application/json; charset=UTF-8\r\n\r\n" +
                    meta_bytes + b"\r\n--" + boundary + b"\r\nContent-Type: " + mime.encode() +
                    b"\r\n\r\n" + data_bytes + b"\r\n--" + boundary + b"--")
            req = _r.Request(
                "https://www.googleapis.com/upload/drive/v3/files"
                "?uploadType=multipart&fields=id&supportsAllDrives=true",
                data=body,
                headers={**self._headers,
                         "Content-Type": f"multipart/related; boundary={boundary.decode()}"})
            with _r.urlopen(req, timeout=60) as resp:
                return _j.loads(resp.read()).get("id")

        def update(self, file_id, data_bytes, mime):
            import urllib.request as _r, json as _j
            req = _r.Request(
                f"https://www.googleapis.com/upload/drive/v3/files/{file_id}"
                f"?uploadType=media&supportsAllDrives=true",
                data=data_bytes,
                headers={**self._headers, "Content-Type": mime})
            req.get_method = lambda: "PATCH"
            with _r.urlopen(req, timeout=60) as resp:
                return _j.loads(resp.read()).get("id", file_id)

        def set_public(self, file_id):
            import urllib.request as _r, json as _j
            body = _j.dumps({"role": "reader", "type": "anyone"}).encode()
            req = _r.Request(
                f"https://www.googleapis.com/drive/v3/files/{file_id}/permissions",
                data=body,
                headers={**self._headers, "Content-Type": "application/json"})
            with _r.urlopen(req, timeout=15) as resp:
                return resp.read()

        def delete(self, file_id):
            import urllib.request as _r
            req = _r.Request(
                f"https://www.googleapis.com/drive/v3/files/{file_id}",
                headers=self._headers)
            req.get_method = lambda: "DELETE"
            try:
                with _r.urlopen(req, timeout=15):
                    pass
            except Exception:
                pass

    return _DriveLite(token)

def _drive_get_carpeta_raiz():
    """Retorna el folder_id configurado manualmente (carpeta compartida con el service account)."""
    try:
        gs = _gs()
        if gs:
            ws = gs._get_hoja("config")
            if ws:
                for row in ws.get_all_values():
                    if row and row[0] == "drive_folder_raiz" and len(row) > 1 and row[1]:
                        return row[1].strip()
    except Exception:
        pass
    return None

def _drive_guardar_carpeta_raiz(folder_id):
    """Guarda el folder_id configurado en GSheets."""
    try:
        gs = _gs()
        if gs:
            ws = gs._get_hoja("config")
            if ws:
                all_v = ws.get_all_values()
                for idx, row in enumerate(all_v):
                    if row and row[0] == "drive_folder_raiz":
                        ws.update_cell(idx + 1, 2, folder_id)
                        return True
                ws.append_row(["drive_folder_raiz", folder_id])
                return True
    except Exception:
        pass
    return False

def _drive_get_folder(folder_name):
    """Retorna la carpeta raiz configurada — no crea subcarpetas para evitar 403."""
    return _drive_get_carpeta_raiz()

def _drive_folder_pausa():
    """Usa la subcarpeta YACHAY_PAUSA_MP3 si existe, si no usa la raíz directamente."""
    raiz = _drive_get_carpeta_raiz()
    if not raiz:
        return None
    # Buscar si ya existe la subcarpeta (puede haberla creado antes)
    try:
        svc = _drive_service()
        if svc:
            q = (f"name='YACHAY_PAUSA_MP3' and "
                 f"mimeType='application/vnd.google-apps.folder' and "
                 f"trashed=false and '{raiz}' in parents")
            files = svc.list_files(q=q)
            if files:
                return files[0]["id"]
    except Exception:
        pass
    return raiz  # Usar carpeta raíz si no hay subcarpeta

def _drive_backup_json(nombre_archivo, datos_dict):
    """Sube un archivo JSON como backup a la carpeta YACHAY_BACKUP en Drive."""
    try:
        import json as _jb
        svc = _drive_service()
        if not svc:
            return None
        folder_id = _drive_get_folder("YACHAY_BACKUP")
        fname = nombre_archivo
        data_bytes = _jb.dumps(datos_dict, ensure_ascii=False, indent=2, default=str).encode('utf-8')
        existing = svc.list_files(
            q=f"name='{fname}' and trashed=false" + (f" and '{folder_id}' in parents" if folder_id else ""))
        if existing:
            file_id = existing[0]["id"]
            svc.update(file_id, data_bytes, "application/json")
        else:
            file_id = svc.upload(fname, data_bytes, "application/json", parent_id=folder_id)
        return file_id
    except Exception as _e:
        return None

def _drive_restaurar_json(nombre_archivo):
    """Descarga y retorna dict desde backup en Drive. None si no existe."""
    try:
        import json as _jb
        import urllib.request as _ur
        svc = _drive_service()
        if not svc:
            return None
        folder_id = _drive_get_folder("YACHAY_BACKUP")
        q = f"name='{nombre_archivo}' and trashed=false"
        if folder_id:
            q += f" and '{folder_id}' in parents"
        files = svc.list_files(q=q, fields="files(id,name,modifiedTime)")
        if not files:
            return None
        file_id = files[0]["id"]
        req = _ur.Request(
            f"https://www.googleapis.com/drive/v3/files/{file_id}?alt=media",
            headers={"Authorization": f"Bearer {_drive_get_token()}"})
        with _ur.urlopen(req, timeout=30) as resp:
            return _jb.loads(resp.read())
    except Exception:
        return None

def _drive_subir_mp3(modelo_id, audio_bytes, extension="mp3"):
    """Sube MP3 a Google Drive y retorna el file_id."""
    try:
        svc = _drive_service()
        if not svc:
            return None
        folder_id = _drive_folder_pausa()
        fname = f"pausa_mp3_{modelo_id}.{extension}"
        mime  = "audio/mpeg" if extension == "mp3" else f"audio/{extension}"
        # Buscar si ya existe
        q = f"name='{fname}' and trashed=false"
        if folder_id:
            q += f" and '{folder_id}' in parents"
        existing = svc.list_files(q=q)
        if existing:
            file_id = existing[0]["id"]
            try:
                svc.update(file_id, audio_bytes, mime)
            except Exception as _eu:
                st.session_state["_drive_error"] = f"update falló: {_eu}"
                return None
        else:
            try:
                file_id = svc.upload(fname, audio_bytes, mime, parent_id=folder_id)
            except Exception as _eup:
                st.session_state["_drive_error"] = f"upload falló: {_eup}"
                return None
        if file_id:
            # set_public es opcional — si falla no bloquea el guardado
            try:
                svc.set_public(file_id)
            except Exception:
                pass  # El archivo se guardó igual, solo no será público
        return file_id
    except Exception as _e:
        st.session_state["_drive_error"] = f"_drive_subir_mp3: {_e}"
        return None

def _drive_borrar_mp3(file_id):
    """Elimina MP3 de Google Drive por file_id."""
    try:
        svc = _drive_service()
        if svc and file_id:
            svc.delete(file_id)
        return True
    except Exception:
        return False

def _pausa_guardar_mp3(modelo_id, audio_bytes, extension="mp3"):
    """
    Guarda MP3 de pausa activa:
    1. Guarda local (sesión actual)
    2. Sube a Google Drive y guarda el file_id en GSheets
    NOTA: base64 en GSheets NO funciona para MP3 (límite 50k chars por celda)
    """
    # 1. Guardar local
    path = f"pausa_mp3_{modelo_id}.{extension}"
    try:
        with open(path, "wb") as f:
            f.write(audio_bytes)
    except Exception:
        pass

    # 2. Subir a Drive y guardar file_id en GSheets
    drive_file_id = None
    try:
        drive_file_id = _drive_subir_mp3(modelo_id, audio_bytes, extension)
        if drive_file_id:
            gs = _gs()
            if gs:
                ws = gs._get_hoja('config')
                if ws:
                    clave = f"drive_pausa_mp3_{modelo_id}"
                    all_vals = ws.get_all_values()
                    found = False
                    for idx, row in enumerate(all_vals):
                        if row and row[0] == clave:
                            ws.update_cell(idx + 1, 2, drive_file_id)
                            found = True; break
                    if not found:
                        ws.append_row([clave, drive_file_id])
    except Exception as _e:
        st.session_state["_drive_error"] = str(_e)

    return path, drive_file_id

def _pausa_drive_url(file_id):
    """Retorna URL de streaming directo desde Google Drive."""
    if not file_id:
        return None
    return f"https://drive.google.com/uc?export=download&id={file_id}"

def _pausa_cargar_drive_file_id(modelo_id):
    """Obtiene el Drive file_id guardado en GSheets para un modelo."""
    try:
        gs = _gs()
        if not gs:
            return None
        ws = gs._get_hoja('config')
        if not ws:
            return None
        all_vals = ws.get_all_values()
        clave = f"drive_pausa_mp3_{modelo_id}"
        for row in all_vals:
            if row and row[0] == clave and len(row) > 1 and row[1]:
                return row[1]
    except Exception:
        pass
    return None

def _pausa_cargar_mp3_b64(modelo_id):
    """
    Carga audio para reproducción HTML:
    - Si existe local: usa base64 directo (más rápido)
    - Si no: retorna None,None y el llamador usará la URL de Drive
    """
    import base64 as b64mod
    for ext in ["mp3", "ogg", "wav"]:
        path = f"pausa_mp3_{modelo_id}.{ext}"
        if Path(path).exists():
            with open(path, "rb") as f:
                return b64mod.b64encode(f.read()).decode("utf-8"), ext
    return None, None

