                    f'animation-delay:.3s;">2°</div></div>'
                    # 1er lugar
                    f'<div class="bloque">'
                    f'<div class="medalla" style="animation-delay:0s;font-size:2.8rem;">🥇</div>'
                    f'<div class="nombre" style="font-size:1rem;">{_sn(p1)}</div>'
