                        cp_r.setFont("Helvetica", 8)
                        cp_r.drawCentredString(wp_r/2, hp_r-50, f"Promedio: {pm_r:.1f}/20 | Aprobados: {ap_r}/{len(res)} | {fecha_peru_str()}")
